-- Poems batch 86
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('83b77bf2-c343-4c71-bb4c-48a654b2b312','秋懷十首  其六','朱松','宋','宋诗','song-poetry','','[]','林臯一葉脫，靜士最先知。',72,'全唐诗/poet.song.107000.json','["林臯一葉脫，靜士最先知。", "自我抱茲獨，悠然星氣馳。", "乾坤一逆旅，鼎鼎竟何爲。", "枯榮俯仰中，兒輩浪自悲。", "青雲渺難必，白髮不可辭。", "得飽良已泰，雨畦瓜芋肥。"]'),
('d44576be-9e6b-4fb0-9efb-ef9440eb9201','秋懷十首  其七','朱松','宋','宋诗','song-poetry','','[]','了翁卧淮楚，德望臨一世。',48,'全唐诗/poet.song.107000.json','["了翁卧淮楚，德望臨一世。", "憂時九迴腸，醫國三折臂。", "四海一滔滔，揚湯不止沸。", "斯人倘可起，姚宋何足繼。"]'),
('e0534bc3-8869-4444-a1ef-65ea3c60b498','秋懷十首  其八','朱松','宋','宋诗','song-poetry','','[]','反身聖可作，自恕惡易盈。',48,'全唐诗/poet.song.107000.json','["反身聖可作，自恕惡易盈。", "昨非往莫諫，今是來足程。", "幽人歲晚粟，樹者夷跖并。", "慨然釋七歎，諒知負平生。"]'),
('fd832f27-a82c-4989-9127-12013f88e3f6','秋懷十首  其九','朱松','宋','宋诗','song-poetry','','[]','甘菊卧風雨，枯荷暗池塘。',48,'全唐诗/poet.song.107000.json','["甘菊卧風雨，枯荷暗池塘。", "達人聽榮悴，志士費感傷。", "亭亭岩桂花，已作宮槐黄。", "諒無青霞客，誰與媚孤芳。"]'),
('c531bd69-e89e-4f8d-8b3a-edac41695f54','秋懷十首  其一○','朱松','宋','宋诗','song-poetry','','[]','江海有一士，補衮抱經緯。',48,'全唐诗/poet.song.107000.json','["江海有一士，補衮抱經緯。", "帝衣日月明，袖手久不試。", "九關隔雲雨，誰肯借一臂。", "絃急而調卑，此歎同萬世。"]'),
('b1ca832f-b391-4382-a393-d778e11ee2c3','和謝綽中觀瀾亭','朱松','宋','宋诗','song-poetry','','[]','方塘灧宿漲，曲澗來飛湍。',144,'全唐诗/poet.song.107000.json','["方塘灧宿漲，曲澗來飛湍。", "光涵鬰藍天，澒洞碧玉寬。", "小亭塵土外，瓦影浮朱欄。", "霜渚寫秋色，烟林養漁竿。", "佳人秋霞衣，皎皎明月冠。", "欲濯且無塵，隠几得妙觀。", "海若眩河伯，等在蝸角端。", "那知坳堂上，盃水生濤瀾。", "雲間謝公子，五字冰雪寒。", "展讀勝圖畫，經行記林巒。", "九垓未暇遊，據殻諒匪安。", "一到定何日，眷焉抱長歎。"]'),
('ab2b55b8-5bcd-4423-894e-74af3c659ea9','寄題陳國器容膝齋','朱松','宋','宋诗','song-poetry','','[]','淵明乃畸人，遊戲於塵寰。',144,'全唐诗/poet.song.107000.json','["淵明乃畸人，遊戲於塵寰。", "南窗歸徙倚，宇宙容膝間。", "豈不念斗米，折腰諒匪安。", "是非無今昨，飛倦會須還。", "國器青雲姿，逸志追孔鸞。", "曲肱數椽底，尚友千載前。", "規模琴書室，料理松菊緣。", "心遊萬物表，了覺函丈寬。", "念君方適越，昔至誰云然。", "要知丘壑志，本出軒裳先。", "瑣闥麗宸居，追飛不云艱。", "回車莫待遠，泉石聞此言。"]'),
('c0099ebc-d293-4399-b8ae-a9983d281e94','約金確然不至','朱松','宋','宋诗','song-poetry','','[]','門前北風裂我襦，知君未能出僧廬。',64,'全唐诗/poet.song.107000.json','["門前北風裂我襦，知君未能出僧廬。", "忍看烟雨凍梅膚，南枝北枝香欲無。", "可無一杯相煖熱，道人酒熟不用沽。", "區區濡沫浪辛苦，安得共似江湖魚。"]'),
('14354c49-2eaa-4464-aeb7-43ca3d5b24ca','確然雪中見過','朱松','宋','宋诗','song-poetry','','[]','雨斷雪將墮，天低雲可攀。',180,'全唐诗/poet.song.107000.json','["雨斷雪將墮，天低雲可攀。", "誰穿東郭履，來款山陰關。", "故人金公子，身窶心甚閑。", "道機久純熟，世味飽險艱。", "一杯不可緩，軟此雙脚頑。", "未忘膜外境，忽湧胸中山。", "白眼槩六合，誰云書生孱。", "萬類宅天壤，細觀真市闤。", "攫金掩醉眼，倚門眩朱顔。", "哀哉兒女態，今古可笑訕。", "坐令一世豪，偃蹇棲茅菅。", "先生談天舌，久挂屋壁間。", "置之且默坐，觀我無所還。", "紛紛造物機，顛倒轉愚姦。", "於我何所歉，莫歎簞瓢慳。"]'),
('42115954-b267-4ad6-a0f3-1a71be3b364a','書僧房','朱松','宋','宋诗','song-poetry','','[]','陸續流泉自成句，來擁紅爐聽山雨。',64,'全唐诗/poet.song.107000.json','["陸續流泉自成句，來擁紅爐聽山雨。", "道人更有深深處，詰曲如珠蟻絲度。", "几研無塵寒欲霧，雕盤篆破孤螢吐。", "味如嚼蠟那禁咀，茶甘未回君莫去。"]'),
('f7665ba0-e2a3-4743-9ed4-f77811917dc6','題蘆鴈屏','朱松','宋','宋诗','song-poetry','','[]','征鴻坐何事，天遣南北飛。',108,'全唐诗/poet.song.107000.json','["征鴻坐何事，天遣南北飛。", "蕭然如旅人，無情自相依。", "孤葦吹欲折，秋風不勝威。", "冥冥一孤鶱，空費弋者機。", "寒聲落烟渚，相應不我違。", "嗟我識此情，手納空歎欷。", "安知丹青師，落筆廼庶幾。", "畫形孰不工，畫意識者稀。", "他時因吾句，購此千金揮。"]'),
('6976bc31-0db5-4c01-8d0d-49a35b806296','題臨賦軒','朱松','宋','宋诗','song-poetry','','[]','蒼山圍岑寂，下有一水奔。',132,'全唐诗/poet.song.107000.json','["蒼山圍岑寂，下有一水奔。", "閉戶卧風雨，束蒿翳籬藩。", "寥哉祇樹人，心遠忘世喧。", "此身自蘧廬，長物餘此軒。", "鳥語幽夢斷，香橫經帙翻。", "未成借路行，自要窺潺湲。", "遠師淵明意，不愧靈徹魂。", "月度了無迹，風行偶成痕。", "心境兩清妙，尺喙何由吞。", "賦詩安所取，碧雲未足論。", "何當拂朱絲，窈眇絃吾言。"]'),
('a6286d30-7f59-4119-b645-4eeb5ef4d53d','答保安江師送米','朱松','宋','宋诗','song-poetry','','[]','不見道人久，天涯歲云除。',144,'全唐诗/poet.song.107000.json','["不見道人久，天涯歲云除。", "朝來食指動，忽接送米書。", "念師折脚鐺，五合未省餘。", "雖無覆餗禍，尚有乞食逋。", "云何憐孤客，日受饑火驅。", "未曾貸監河，矧肯索胡奴。", "誰言斗升意，矯矯超萬夫。", "嗟予事筆耕，輕棄南畝鋤。", "慁煩方外客，此計良已疏。", "何時事粗了，歸葺五畝居。", "生涯寄緯竹，豈即非良圖。", "不爲泉壤蚓，願學江湖魚。"]'),
('c222ce49-e826-419a-b902-8652e1bc83d0','陳德瑞饋新茶','朱松','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','空山冥冥雲霧窗，春風好夢欹殘缸。',96,'全唐诗/poet.song.107000.json','["空山冥冥雲霧窗，春風好夢欹殘缸。", "朝來果得故人信，微凸而么犀銙雙。", "貴人爭買百瓔珞，此心兒女久已降。", "坐觀市井起攘袂，念之使我心紛龐。", "領君此意九鼎重，雖有筆力安能扛。", "何時來施三昧手，慰我渴夢思長江。"]'),
('64d0c67e-ce64-4f73-bf8e-53339468f299','次韻希旦喜雨','朱松','宋','宋诗','song-poetry','','[]','驕陽挾酷暑，何啻虎而翼。',180,'全唐诗/poet.song.107000.json','["驕陽挾酷暑，何啻虎而翼。", "高田土可篩，况廼耕與殖。", "風伯真可訟，雲合吹復拆。", "那知下土民，糟粕配橡實。", "古佛棲巖隈，旱沴豈吾責。", "應緣賢令尹，閔雨丐法力。", "積陰暝山谷，流潤凄几格。", "朝來賀客散，置酒浣愁疾。", "古詩成雲外，險句動潜蟄。", "旋看蓑笠出，競喜溝澮溢。", "讙言令與佛，念我一何悉。", "嗟我困蒿藜，最覺民可恤。", "何當問牛喘，免使訴魚失。", "九關虎豹守，懷此欲安適。", "誰哉此心同，吾飽將何日。"]'),
('0e23213c-0e0d-4f0a-a74f-5564a3b0e02d','古風二首寄汪明道  其一','朱松','宋','宋诗','song-poetry','','[]','紫蘭初茁芽，深壑終自秀。',48,'全唐诗/poet.song.107000.json','["紫蘭初茁芽，深壑終自秀。", "骯髒蕭艾中，不采則誰咎。", "兒曹逐紛華，壯士保窮陋。", "應知此調同，萬世無先後。"]'),
('7bd84239-8b89-49c2-a6ef-9161dc55ddd7','古風二首寄汪明道  其二','朱松','宋','宋诗','song-poetry','','[]','俗士白人眼，從誰明此心。',48,'全唐诗/poet.song.107000.json','["俗士白人眼，從誰明此心。", "不欲故人見，訶我車轍深。", "蕭然江上廬，客卧詩書林。", "得句不相寄，誰賞氣駸駸。"]'),
('4b91a8a9-1202-442b-810f-63eec590f3a7','建安道中','朱松','宋','宋诗','song-poetry','','[]','吾生意行初不謀，泛泛何啻波中鷗。',128,'全唐诗/poet.song.107000.json','["吾生意行初不謀，泛泛何啻波中鷗。", "携家來作閩海夢，三年客食天南陬。", "我先人廬在何許，大江之左道阻脩。", "奉新家有手足愛，隻身歸掃先梧楸。", "旋當來此營斗粟，南北顛倒無時休。", "此心轉與世事左，自作磨螘將誰尤。", "安知不滿達者笑，窮達一戲如觀優。", "咄哉吾語亦已墮，且與造物同浮遊。"]'),
('d6ef2856-5ac3-47ef-af5f-a635b211a150','書事呈元聲如愚起華三兄','朱松','宋','宋诗','song-poetry','','[]','隠吏朱墨暇，飽眠北窗風。',144,'全唐诗/poet.song.107000.json','["隠吏朱墨暇，飽眠北窗風。", "時呼方外客，逃暑尊酒中。", "寂寞杜拾遺，四壁口不供。", "坐取盤飧疑，哀哉豈天窮。", "何如平生友，磁鐵間不容。", "每懷千里駕，今作五斗逢。", "吏行散鳬鶩，楸局收鸞龍。", "共話十年舊，事往如飛蓬。", "浮榮真一戲，何者爲窮通。", "應須河漢語，凈洗芥蔕胸。", "僕夫適在門，客醉尊亦空。", "更爲後日約，及此芙蕖紅。"]'),
('c019082e-c787-470b-81ba-9317670b39f9','寄題起莘家義軒','朱松','宋','宋诗','song-poetry','','[]','貞觀盛德後，餘慶未渠央。',120,'全唐诗/poet.song.107000.json','["貞觀盛德後，餘慶未渠央。", "舊聞閩海家，欲縱燕山芳。", "教子嗣先訓，開軒翼中堂。", "地偏市朝遠，几浄書簡香。", "先生陳太丘，飯糜百憂忘。", "弟子真羯胡，不聞觸屏僵。", "一變豪俠窟，遂成鄒魯鄉。", "下車里門外，他年看諸郎。", "坐上紆素髮，詵詵立冠裳。", "我詩自可絃，請以侑壺觴。"]'),
('9493415b-61a3-4b04-9eb4-5188cd1ad88d','梅花','朱松','宋','宋诗','song-poetry','','[]','山深春未動，沙淺水欲冰。',144,'全唐诗/poet.song.107000.json','["山深春未動，沙淺水欲冰。", "玉梅於此時，靚粧畧無朋。", "露蘂欲的皪，月枝挂鬅鬙。", "儼如江漢女，可愛不可陵。", "他年江南路，曉粧犯嚴凝。", "尋香烟雨中，橫斜插茆簦。", "却數今幾日，癡如秋後蠅。", "北嶺枝欲空，誰與扶一登。", "聊分窺水影，依我照字燈。", "坐使惜花夢，臨風脚騰騰。", "昔如夢中蝶，今學桑下僧。", "了知菩提長，念起吾何曾。"]'),
('dee51e5b-012f-453b-8b7a-625a6a9764dc','十一月十九日與仲猷大年綽中美中飲於南臺','朱松','宋','宋诗','song-poetry','','[]','空山欲雪雲冥冥，玉梅半開吾眼青。',96,'全唐诗/poet.song.107000.json','["空山欲雪雲冥冥，玉梅半開吾眼青。", "此身垂欲走塵土，聊復舉酒看崢嶸。", "折腰向人不知耻，故園可鋤在千里。", "金昆石友一開眉，珍重道人相料理。", "楚江東岸先人廬，竹君安否久無書。", "歸歟何時應白首，我食吾言如此酒。"]'),
('7f1251f2-69c3-41a6-99ab-198d36f32059','春社齋禁連雨不止賦呈夢得','朱松','宋','宋诗','song-poetry','','[]','歲豐農猶饑，歲惡何可說。',144,'全唐诗/poet.song.107000.json','["歲豐農猶饑，歲惡何可說。", "哀哉半菽氓，罪歲同一舌。", "年時旱塵漲，臘盡不見雪。", "青皇忽雨我，萬頃麥苗活。", "令尹民父母，溝壑思手挈。", "祈年祓齋居，有酒不忍設。", "那知桃李徑，狼籍香泥滑。", "芳意一如此，坐恐及鶗鴂。", "郊原佇開晴，出勞南畝饁。", "秋成已在眼，一醉宇宙豁。", "更呼湔裙人，勸此側帽客。", "和公斜川詩，磨石鑱歲月。"]'),
('4ca8f52c-ddff-49ae-ab0f-c30579d5c2b9','次韻夢得見示長篇','朱松','宋','宋诗','song-poetry','','[]','雉馴不因媒，鳩暖自呼婦。',216,'全唐诗/poet.song.107000.json','["雉馴不因媒，鳩暖自呼婦。", "詩成桃李陰，知是霹靂手。", "簿書我亦厭，丘壑渠自有。", "却憐支離疏，飽食得薪槱。", "俗夫嘗世味，甘苦半噦嘔。", "知公超然處，心跡兩無垢。", "愁陰老芳物，蟲鳥故相誘。", "浪蕊費收拾，柔條可結揉。", "豈無我輩人，一醉開笑口。", "那知市門底，客倦枕兩肘。", "眼高可人稀，命蹇亨運偶。", "平生願執鞭，見謂予小友。", "細觀愷悌心，宜在帝左右。", "却來塵埃中，寂寞對五柳。", "鷇音藏鵠羽，正待荆雞剖。", "學政容窺譜，問字當載酒。", "虛名翻誤夢，恐坐箕與斗。", "言詩終不稱，永愧賦瓊玖。"]'),
('6c044931-7d6e-4887-9692-cabca88ddbba','久雨短句呈夢得','朱松','宋','宋诗','song-poetry','','[]','身閑書有味，吏傲俗不親。',192,'全唐诗/poet.song.107000.json','["身閑書有味，吏傲俗不親。", "小窗據物表，掃盡心眼塵。", "令尹垂珠玉，敲門喚行春。", "作意向芳物，吾車曾未巾。", "愁陰入病骨，鳩婦聲亦嗔。", "冥冥三日雨，桃李迹已陳。", "空餘深枝間，一一青子新。", "穠芳殿春晚，猶堪慰佳辰。", "酴醿曉妝靚，芍樂醉臉勻。", "日萼簪嫋嫋，風巵倒粼粼。", "言當呼短舞，抵掌回雙顰。", "年來得相從，稍覺安沈淪。", "豈不掛俗事，察公極清真。", "眼中醉鄉路，風味良獨醇。", "流光不容玩，尺璧何足珍。", "漓俗益可厭，願言勤問津。"]'),
('06f5f29f-93c1-4a3d-b771-e6795cbe011f','牡丹酴醿各一首呈周宰  其一','朱松','宋','宋诗','song-poetry','','[]','珍藂壓朝露，無人羞欲欹。',48,'全唐诗/poet.song.107000.json','["珍藂壓朝露，無人羞欲欹。", "春風醉香骨，綽約不自持。", "誰憐曲肱人，一笑遣穠姿。", "不言意可了，君醉當勿疑。"]'),
('8b5c495e-f82e-4f09-afc0-5a99c2954e16','牡丹酴醿各一首呈周宰  其二','朱松','宋','宋诗','song-poetry','','[]','妝淡洗逾靚，肌香薰不成。',48,'全唐诗/poet.song.107000.json','["妝淡洗逾靚，肌香薰不成。", "皎然月露姿，一笑午景晴。", "聊移夢蝶牀，相對戶不扃。", "誰令風雨暴，睡起春縱橫。"]'),
('d87e8932-c4c2-4b70-b749-c2956f83136b','次韻夢得淺紅芍藥長句','朱松','宋','宋诗','song-poetry','','[]','十日愁陰病不出，卧看春歸無計惜。',128,'全唐诗/poet.song.107000.json','["十日愁陰病不出，卧看春歸無計惜。", "詩翁遣送淮海春，衰眼熨開雲霧拆。", "胭脂注臉勻未遍，肉紅借酒生真色。", "了知造物著意深，傾倒春工不餘力。", "年來不顧溱洧女，載酒非公復安適。", "且將妙句寫餘妍，欲立佳名付精識。", "一春頗困歌酒汙，回首紛華三太息。", "願言乞與洗心方，歸對爐香誦周易。"]'),
('0cf09269-43ec-4ba0-9381-a6cda9641e0e','宿禪寂院','朱松','宋','宋诗','song-poetry','','[]','夢中一葉摇江湖，困睡不覺身藍輿。',192,'全唐诗/poet.song.107000.json','["夢中一葉摇江湖，困睡不覺身藍輿。", "眼明佛屋麗丹碧，瓦鴟鴺鳳凌空虛。", "疲民日者困苛索，半作赬尾相濡魚。", "鵜鶘數罟兩不置，肯念竭澤明年無。", "道人誰與辦此事，斤琢千指開渠渠。", "頗疑如幻三昧力，上方手攬歸吾廬。", "了知舌本法輪轉，咄嗟檀施爭奔輸。", "不辭割愛一念善，誰謂歲惡窮民愚。", "書生袖手對溝壑，力不能援心煩紆。", "事無大小成者少，談說治亂何區區。", "調卑絃急誠齟齬，鑿圓枘方尤闊疏。", "古今罪歲同一口，撫掌一笑皆愚儒。"]'),
('629e1503-cefb-4307-ba34-fee46d2e3813','詩約范直夫遊萬葉寺觀瀑泉','朱松','宋','宋诗','song-poetry','','[]','萬侯隠下吏，夙尚本丘園。',120,'全唐诗/poet.song.107000.json','["萬侯隠下吏，夙尚本丘園。", "身投攫金市，藂書以自藩。", "炯然如孤月，不受黄流渾。", "要知句律工，競病何足論。", "我生群末俗，涇渭非一源。", "同心無楚越，傾蓋如弟昆。", "人生各有役，不暇捧一尊。", "風蒲掛南浦，念欲東南奔。", "對牀定何夕，青燈照晤言。", "懸知知詩處，千尺銀河翻。"]'),
('64216d76-3003-4efd-89ad-21f143555efb','次韻夢得見示之什','朱松','宋','宋诗','song-poetry','','[]','居楚求齊音，美惡不同土。',96,'全唐诗/poet.song.107000.json','["居楚求齊音，美惡不同土。", "喧豗俗物華，群復有佳處。", "時從玉璧人，商畧窮萬古。", "詩如粟牛戲，誤得摩頂許。", "望道渺逾遠，久生真暫寓。", "忍持尺璧陰，空作秋蟲語。", "微言儻傾倒，河漢濯肺腑。", "向來說詩口，自此行可杜。"]'),
('177dad49-7a99-4078-bc9b-9ac1019a738f','送甌寧魏生赴武舉','朱松','宋','宋诗','song-poetry','','[]','建安少年請纓客，橫槊賦詩兩無敵。',64,'全唐诗/poet.song.107000.json','["建安少年請纓客，橫槊賦詩兩無敵。", "辭家去作入彀英，氣拂天狼夜無迹。", "廟堂尺箠鞭羌胡，智名勇功付壯夫。", "引弓沒羽世自有，敢聞上策當何如。"]'),
('9174ec49-47ff-4e92-8417-e75bf57ac825','陳仲仁止止堂','朱松','宋','宋诗','song-poetry','','[]','以我有限景，逐彼無涯知。',168,'全唐诗/poet.song.107000.json','["以我有限景，逐彼無涯知。", "失足踐畏途，投身試危機。", "舟車日奔覆，定無丘與夷。", "萬古踐此轍，嗟我與誰歸。", "仲仁古靜者，懷璧照褐衣。", "名途嘗一戲，回首羞前非。", "心如得坎水，不受狂風吹。", "功名憂不免，當復定所之。", "請觀本無作，今復止者誰。", "築堂市門側，著書園不窺。", "蓬藋深一丈，圖書周四圍。", "時有好事人，載酒問所疑。", "攫金奮敏手，倚市誇妍姿。", "回光時自照，何者非吾師。"]'),
('4d745a25-77fd-4721-b1b1-980c875b82e7','送志宏西上','朱松','宋','宋诗','song-poetry','','[]','九州眼一槩，餘子真瑣瑣。',144,'全唐诗/poet.song.107000.json','["九州眼一槩，餘子真瑣瑣。", "嶽立培塿中，喜此高岋峨。", "如公我輩人，取友亦到我。", "揮毫賦垂天，風雨卷蓬顆。", "相期八表遊，未覺夙心左。", "解龜醉江閣，酒面山月墮。", "起瞻帝鄉雲，感歎不成坐。", "何須飛霞佩，自辦凌風舸。", "瀛洲渺溟渤，萬里一掀簸。", "緘詩寄天涯，秉燭對新火。", "那知市門仙，斗祿事么麽。", "空餘腸九迴，上疏何日果。"]'),
('8ad7b41e-aa03-40e6-a452-8126f6bafa6b','有懷舍弟逢年時歸婺源以詩督之','朱松','宋','宋诗','song-poetry','','[]','木落天未霜，君歸定何時。',216,'全唐诗/poet.song.107000.json','["木落天未霜，君歸定何時。", "相思如驚鵲，中宵未安枝。", "夢中見阿連，鏘然詠新詩。", "寤驚衰葉翻，謂是步屧移。", "攬衣下中庭，風露浩淼瀰。", "遥知客衣薄，歸來一何遲。", "平生短檠燈，相對忽解頤。", "萬古一舒卷，佳處良在茲。", "是中及物心，上與稷契期。", "援古以自例，自笑無乃癡。", "夜叉叱九闕，側足不敢窺。", "坐令一寸心，日抱二柄疑。", "遲君商畧此，恐得兒輩嗤。", "况乃綠髮親，倚門鬢欲絲。", "狶膏非鳳喙，車轄無可脂。", "再拜壽百分，斑衣舞參差。", "秋芳未云歇，采采黄金蕤。", "萬鍾不足樂，古人豈吾欺。"]'),
('5221353a-3090-46dc-8138-1931aec82da8','九月十七日夜度蔡道嶺宿彌勒院','朱松','宋','宋诗','song-poetry','','[]','月出度松嶺，露香非羽衣。',144,'全唐诗/poet.song.107000.json','["月出度松嶺，露香非羽衣。", "肅肅夜氣清，蒼蒼烟徑微。", "川光浴秋容，蘿影挂夕輝。", "冰輪碾空闊，飛轍無因依。", "擬掬星渚波，恐觸天孫機。", "偓佺何時見，沆瀣聊獨揮。", "未應青霞志，即與素願違。", "稍休塵外軫，憩此巖下扉。", "清吟寫萬籟，妙想絕百非。", "不須河漢言，盡解紛華圍。", "飛仙亦戲劇，玄學乃庶幾。", "鰲山切丹極，歲晚行將歸。"]'),
('11b6b802-632c-4f8e-b256-e6456a8b71d9','遊鄭圃','朱松','宋','宋诗','song-poetry','','[]','城郭不去眼，而得林壑娛。',48,'全唐诗/poet.song.107000.json','["城郭不去眼，而得林壑娛。", "低回撫壯心，欲吐無與俱。", "鏗然一枝筇，細磴爭樵漁。", "挽衣徑與飲，不省誰爲吾。"]'),
('78ffbf26-c7ef-48ad-a80c-0704273c7217','女貧苦難妍','朱松','宋','宋诗','song-poetry','','[]','女貧苦難妍，士貧苦難高。',168,'全唐诗/poet.song.107000.json','["女貧苦難妍，士貧苦難高。", "了知論此者，不識一世豪。", "此身百斛鼎，流俗欲手操。", "寧當捨其中，局促計所遭。", "頗疑有若人，骯髒棲蓬蒿。", "考槃一丘壑，光景不可韜。", "斯人不我忘，空復踰垣逃。", "軒裳亦云華，唾去如腥臊。", "哀哉夸毗子，擾擾冠猿猱。", "恬無濟世心，閔默死滔滔。", "朅來事斗祿，俛仰身桔槔。", "一官戲人間，幾何非餮饕。", "誰言眷此幘，擲去輕秋毫。", "區區欲驕士，一哭嗟兒曹。"]'),
('e8fa2fe6-0af6-48f9-8f3d-1deef82a028c','谿南梅花','朱松','宋','宋诗','song-poetry','','[]','巉巉石逕鳴枯筇，意行詰曲無西東。',192,'全唐诗/poet.song.107000.json','["巉巉石逕鳴枯筇，意行詰曲無西東。", "心知幽壑梅已動，一枝寄我曾未蒙。", "暗香橫路忽驚顧，冰蕊的皪蠻烟中。", "有如佳人久去眼，邂逅相得情何窮。", "蔬畦壓霜翠羽亂，已覺雪片棲手茸。", "嗟吾辜此來已晚，攀條嚼蕊聊從容。", "玉仙遊戲下塵世，絕艷一洗朱鉛空。", "不知閬苑在何許，叱回風馭無怱怱。", "溪寒沙凈迷俯仰，坐待山月來朦朧。", "豈無尊酒相煖熱，錦裘起舞如驚鴻。", "仇池老仙羽化久，妙曲三疊餘仙風。", "歸時醉倒不知和，明日來此誰能同。"]'),
('eec206d1-81c8-4c39-9fcc-b456c2d35550','再和求首座','朱松','宋','宋诗','song-poetry','','[]','道人昔曳羌廬筇，五老負雪湓江東。',192,'全唐诗/poet.song.107000.json','["道人昔曳羌廬筇，五老負雪湓江東。", "犯寒貪覓玉梅句，雖有衲被何曾蒙。", "歸來苦雨熟梅子，卷裓深卧蠻烟中。", "詩傳絕境忽入手，置我鄉國情何窮。", "十年不踏江上路，漠漠海氣昏貂茸。", "異鄉歲晚慰流落，一笑頼此冰雪容。", "嶠南絕唱誰敢和，騎鯨人去塵寰空。", "崑墟下視堪笑閔，雕琢肝腎愁怱怱。", "那知幽子雲雨上，風斤玉斧修朣朧。", "讀詩今我一回首，杳若目送孤飛鴻。", "何時晤語折鐺側，坐聽萬籟號天風。", "拈花特地兩顔解，他時與子真參同。"]'),
('bc45d2da-2ddc-4ade-bd8a-72bd810ce170','奉酬令德寄示長句','朱松','宋','宋诗','song-poetry','','[]','閑官屋舍如幽棲，寒苦餘業償鹽虀。',208,'全唐诗/poet.song.107000.json','["閑官屋舍如幽棲，寒苦餘業償鹽虀。", "忽聞鵲聲作破竹，尺書入手誰所齎。", "交游勝絕似公少，矯矯鸞孔依蒿藜。", "青冥側足在咫尺，誰使狡獪捐其梯。", "秋風溪上共樽酒，擺落羈束忘畛畦。", "紅裳起舞意未足，缺月銜嶺星河低。", "只今跌宕走塵土，清夢往復無山谿。", "新詩驚怪爛盈幅，筆力拗怒蟠虹霓。", "遥知槃礴小窗底，得喪已著一理齊。", "此生同困造物戲，未覺與世誰雲泥。", "雖無絕唱追白雪，頼有妙契如靈犀。", "一笑從公豈無日，挽袖相屬空玻璃。", "不須俗物敗真賞，但覓佳處同攀躋。"]'),
('f7a6b57c-5af1-4163-bfe9-d81f55a4badf','答林康民見和梅花詩','朱松','宋','宋诗','song-poetry','','[]','寒崦人家碧谿尾，一樹江梅卧清泚。',160,'全唐诗/poet.song.107000.json','["寒崦人家碧谿尾，一樹江梅卧清泚。", "仙姿不受凡眼汙，風歛天香瘴烟裏。", "向來休沐偶無事，誰從我遊二三子。", "彎碕曲逕一携手，凍雀驚飛亂英委。", "班荆勸客小延佇，酌酒賦詩相料理。", "多情入骨憐風味，依倚橫斜嚼冰蕊。", "至今清夢掛殘月，强作短歌傳素齒。", "韻高常恨句難稱，頼有君詩清且美。", "天涯歲晚感鄉物，歸歟何時路千里。", "枕樓一笛雪漫空，回首江臯淚如洗。"]'),
('3f8403cd-f4ec-43ad-9f48-709b40889c6b','上丁餘膰置酒招綽中德粲德懋逢年','朱松','宋','宋诗','song-poetry','','[]','我生無幾求，畢願老葭菼。',168,'全唐诗/poet.song.107000.json','["我生無幾求，畢願老葭菼。", "誰令事斗祿，飯糲羹不糝。", "書生亦可憐，微物有先感。", "朝來食指動，膰肉豐咀啖。", "恭惟魯司寇，道大長坎壈。", "空餘祠千載，不救陳蔡慘。", "永言百世師，願學吾豈敢。", "當饑不忘歌，既飽復何憾。", "安能如王孫，長物貯頤頷。", "急呼講肆人，一醉捨鉛槧。", "相携桃李徑，歷亂蹴紅毿。", "言强三尺喙，氣溢一身膽。", "平生超然處，獨嗜逾昌歜。", "詩成持似君，莫遣兒輩覽。"]'),
('91fcbdf0-ae0f-4083-b9ce-dcb112b50a01','用綽中韻送正臣正臣欲歸隠而無資故廣其意以告識者云爾','朱松','宋','宋诗','song-poetry','','[]','華裾錦領烏紗幘，氣蓋當年五陵俠。',128,'全唐诗/poet.song.107000.json','["華裾錦領烏紗幘，氣蓋當年五陵俠。", "胸中磈磊不可平，拂衣歸來抱長鋏。", "軒然寄傲楸枰間，長恨坐隠非雲山。", "相逢笑我眷微粟，我歸未可君何難。", "世人錢作牛吼音，誰能立談壽千金。", "空令擁鼻誦招隠，知君心在仙峯陰。", "故山自欲無歸期，作詩但擬淵明詞。", "却愁他日林下信，千里寄我唯當歸。"]'),
('47f4f50d-eced-4461-a6bb-9a0fb62651dc','秋懷六首  其一','朱松','宋','宋诗','song-poetry','','[]','庭柯一葉失，風挾凉氣歸。',48,'全唐诗/poet.song.107000.json','["庭柯一葉失，風挾凉氣歸。", "湛湛陂水青，芙蕖脫紅衣。", "非無岑寂士，句法妙玄暉。", "獨懷履霜戒，德人貴知微。"]'),
('4cec6742-441b-46cf-8dee-dfe4b0ffb1a2','秋懷六首  其二','朱松','宋','宋诗','song-poetry','','[]','真儒六經學，文字聊解紛。',48,'全唐诗/poet.song.107000.json','["真儒六經學，文字聊解紛。", "長孺棄諸侯，漢庭相公孫。", "兒口乳未乾，妄作黑白分。", "誰能領斯會，事往風中雲。"]'),
('633cc236-e686-4d72-a250-35e91d973a4a','秋懷六首  其三','朱松','宋','宋诗','song-poetry','','[]','導江自岷山，源淺觴可濫。',48,'全唐诗/poet.song.107000.json','["導江自岷山，源淺觴可濫。", "下集大小川，千丈水府暗。", "策策井桐凉，炯炯窗月淡。", "後生抱奇志，黄墨勤點勘。"]'),
('44b5f81c-1c7f-44a7-b22e-e055b0869b9b','秋懷六首  其四','朱松','宋','宋诗','song-poetry','','[]','市朝富危機，匹夫死憑河。',48,'全唐诗/poet.song.107000.json','["市朝富危機，匹夫死憑河。", "何如狎鷗子，烟雨同一波。", "行藏各有趣，不在相詆訶。", "我師陋巷人，千古冠四科。"]'),
('de8bc0cc-ae92-4e68-8957-0b934d714c67','秋懷六首  其五','朱松','宋','宋诗','song-poetry','','[]','穿堵超玉繩，影倒夜窗寂。',48,'全唐诗/poet.song.107000.json','["穿堵超玉繩，影倒夜窗寂。", "火雲一洗空，月露清欲滴。", "幽人負痾卧，起坐三歎息。", "歸同對牀笫，晤語永佳夕。"]'),
('b5491f0e-5155-43df-a25e-4d80b0370147','秋懷六首  其六','朱松','宋','宋诗','song-poetry','','[]','掩窗耿不寐，道人亦無悰。',48,'全唐诗/poet.song.107000.json','["掩窗耿不寐，道人亦無悰。", "故山新稻香，粥魚響枯桐。", "夢中信了了，推枕聞西風。", "少遲穉金壯，歸轡與子同。"]'),
('cb61a69d-130c-4fef-b94c-e4ff0c49176c','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其一','朱松','宋','宋诗','song-poetry','','[]','丈室掩槐夏，與君同卧痾。',48,'全唐诗/poet.song.107000.json','["丈室掩槐夏，與君同卧痾。", "平生莫逆人，裹飯誰見過。", "跰𨇤起鑑井，萬古寂不波。", "觀心要知是，造物如吾何。"]'),
('f6233825-71e4-4a9a-90d4-558a6f5fae06','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其二','朱松','宋','宋诗','song-poetry','','[]','六年別故山，松竹故無恙。',48,'全唐诗/poet.song.107000.json','["六年別故山，松竹故無恙。", "此身已天涯，飄走復何向。", "清源老醫師，砭僂出投杖。", "勿辭一往勤，挹彼上池漲。"]'),
('f3033f41-09ea-4db0-8a1c-2f109d66842d','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其三','朱松','宋','宋诗','song-poetry','','[]','石梁跨蠔山，永與方壺久。',48,'全唐诗/poet.song.107000.json','["石梁跨蠔山，永與方壺久。", "憑君持一盃，往酹濟川手。", "遥知相携處，溟渤浸箕斗。", "作詩問大鈞，猶有斯人否。"]'),
('e05760f0-dda7-41bc-bc0a-e5db99196a91','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其四','朱松','宋','宋诗','song-poetry','','[]','山河我四大，物我同一體。',48,'全唐诗/poet.song.107000.json','["山河我四大，物我同一體。", "誰爲苦疾癢，搔按不容擬。", "多生抱此念，耿耿未云已。", "那知知魚樂，更有濠梁子。"]'),
('b177096d-2187-42ee-a64d-6bcde9d8cea4','與陳彥時會華嚴道人偶書','朱松','宋','宋诗','song-poetry','','[]','屋頭烟雲屯，屋下波濤喧。',264,'全唐诗/poet.song.107000.json','["屋頭烟雲屯，屋下波濤喧。", "團欒坐已久，起扣丹霞門。", "客至苦舌强，目擊翻無言。", "元龍湖海士，懷哉夙契敦。", "清坐鼎足峙，妙語流潺湲。", "君遊華嚴海，貝葉手自翻。", "此心於身世，鳥度空無痕。", "笑我流浪中，久被業識吞。", "讀書談古今，綺語生禍根。", "望道渺未見，况廼躐其藩。", "職卑困掣肘，見溺不得援。", "未知造物心，頗復哀黎元。", "近窺顔稷意，未敢遽掩關。", "躬耕亦細事，會要五畝園。", "釋羈牛在牧，駕鼓馬伏轅。", "居然見優劣，不比魚熊蹯。", "持問跏趺人，一笑霜眉掀。", "相携妙峯頂，暝色窺遠村。", "解衣畧輩行，班坐搴芳蓀。", "欲歸意未已，幽徑相與捫。", "蒼崖出玉醴，不受瘴毒溫。", "願言同酌此，我語庶不諼。"]'),
('79d4fe66-c3cd-43a5-bdc7-6d32150b6536','書栟櫚院壁','朱松','宋','宋诗','song-poetry','','[]','側身西來度千山，列仙仙去空孱顔。',64,'全唐诗/poet.song.107000.json','["側身西來度千山，列仙仙去空孱顔。", "斗升自役應笑我，何苦語曲嬉塵寰。", "歸耕無田仕難合，疑此二柄首鼠間。", "摩挲崖石三歎息，我心安得如汝頑。"]'),
('ec3514f3-8efe-4d71-9500-6bd0adde5afd','次志宏韻督成壽置酒','朱松','宋','宋诗','song-poetry','','[]','歸耕食吾言，回首愧江水。',144,'全唐诗/poet.song.107000.json','["歸耕食吾言，回首愧江水。", "方爭楊子席，誰置穆生醴。", "鄧侯傾蓋舊，小寢蓺桃李。", "走書納啖我，涎迸齧唇齒。", "朝來獨何事，怒色劇染指。", "雖微射鴻遊，顧有捩手鬼。", "平生談天口，得酒便鋒起。", "年來病不觴，但要謳貼耳。", "真成畫蛇足，足就酒空矣。", "樊川吐怨句，想見紫雲美。", "何時咄嗟辦，一醉吾亦擬。", "噂沓聽群兒，口實爭笑鄙。"]'),
('c0016d4b-752d-4c85-b3f5-ecf93da916df','內弟程十四復亨歸省用綽中韵作二章送之  其一','朱松','宋','宋诗','song-poetry','','[]','舅家今三世，筆耕未逢秋。',48,'全唐诗/poet.song.107000.json','["舅家今三世，筆耕未逢秋。", "後生抱奇志，肯爲虀鹽留。", "先廬江遶城，歸路柳暗洲。", "勉哉倘有立，離闊何足憂。"]'),
('d7ba87bf-6b3c-4c40-95f5-ad3e279db14c','內弟程十四復亨歸省用綽中韵作二章送之  其二','朱松','宋','宋诗','song-poetry','','[]','讀書學經綸，及壯吾已晚。',48,'全唐诗/poet.song.107000.json','["讀書學經綸，及壯吾已晚。", "譬如抱宿舂，求適萬里遠。", "留君商畧此，歸袖不可挽。", "流光莫控摶，力學副深懇。"]'),
('de37afc6-793a-4b8e-82a6-6150e5034c77','三月十日遊報國院小軒頗幽勝爲名曰雙清仍書此詩','朱松','宋','宋诗','song-poetry','','[]','千峯收宿雨，坐見空翠滴。',168,'全唐诗/poet.song.107000.json','["千峯收宿雨，坐見空翠滴。", "携筇出城隅，試此腰脚力。", "竹陰穿窈窕，僧戶扣岑寂。", "小軒清樾底，磐礴聊自適。", "闖然見幽禽，百囀深拔隙。", "即此與晤歌，絕勝眼前客。", "幽懷層冰結，屭贔不可釋。", "忽如散春風，回首無處覓。", "天遊失六鑿，真觀了千息。", "乾坤鼎鼎中，指馬坐可一。", "不知雙清老，何者爲心迹。", "持問跏趺人，首肯復面壁。", "山烟明欲合，歸舸兀深碧。", "此心除溪月，炯炯誰復識。"]'),
('185f14ed-3d58-4f58-bf3b-30bb0912727f','次韻謝綽中遊報國寺詩','朱松','宋','宋诗','song-poetry','','[]','掩關味詩書，青簡亦已槁。',120,'全唐诗/poet.song.107000.json','["掩關味詩書，青簡亦已槁。", "相携出東城，及此風日好。", "僧簷覆谿淥，共取一尊倒。", "眷此松桂陰，不接車馬道。", "慇懃玩流光，齒髮行且老。", "諸公奠九鼎，帝室欣再造。", "優遊容我輩，放浪事幽討。", "念君東山姿，文字富天藻。", "風期在經綸，彈冠苦不早。", "寧知如子雲，白首太玄草。"]'),
('e29d589d-d1f0-4443-8a52-7e4b6ffe30c3','丁未春懷舍弟時在京師','朱松','宋','宋诗','song-poetry','','[]','狂虜送死河南北，王事遥憐弟行役。',64,'全唐诗/poet.song.107000.json','["狂虜送死河南北，王事遥憐弟行役。", "胡命須臾魚在鼎，官軍低回鷙將擊。", "渴聞天語十行札，尤覺家書萬金直。", "何時同秉江上犂，萬里農桑吾願畢。"]'),
('fd9372bb-64f0-47fc-92f7-89b7ec852591','五言雜興七首  其一','朱松','宋','宋诗','song-poetry','','[]','側席憂宗周，負痾頭岑岑。',48,'全唐诗/poet.song.107000.json','["側席憂宗周，負痾頭岑岑。", "又傳衢梁盜，弄兵保山林。", "渴聞平虜詔，蟄戶跋雷音。", "欲舞恨袖短，諸君獨何心。"]'),
('6466e6a7-a055-45f4-b2db-e84d766cd7b7','五言雜興七首  其二','朱松','宋','宋诗','song-poetry','','[]','黄香卧講肆，日蕪五畝園。',48,'全唐诗/poet.song.107000.json','["黄香卧講肆，日蕪五畝園。", "兒誦聲九雛，未厭咽耳喧。", "古來避世士，或隠金馬門。", "云何北窗底，默默對幽諼。"]'),
('f053d24c-6d44-4527-a3a2-0fa545e78dd8','五言雜興七首  其三','朱松','宋','宋诗','song-poetry','','[]','聖門出嵩岱，領畧千丘岑。',48,'全唐诗/poet.song.107000.json','["聖門出嵩岱，領畧千丘岑。", "久矣暖姝子，蠹魚槁書林。", "曾參一唯後，曠古沈此音。", "願君同鑽仰，滿我初地心。"]'),
('fdfa7d6c-bf58-4c8b-96fb-b60d0cf4b334','五言雜興七首  其四','朱松','宋','宋诗','song-poetry','','[]','丹白春事了，灌木忽暗園。',48,'全唐诗/poet.song.107000.json','["丹白春事了，灌木忽暗園。", "卷書護岑寂，幽鳥時一喧。", "起携無事酒，往扣常關門。", "豈無素心人，之子不可諼。"]'),
('2859c676-1c4a-45e4-8eee-f1979ced00f3','五言雜興七首  其五','朱松','宋','宋诗','song-poetry','','[]','讀書評世故，自許了無猜。',48,'全唐诗/poet.song.107000.json','["讀書評世故，自許了無猜。", "忽然撫機會，往往鑿枘乖。", "時難既可歎，道大未易涯。", "歸來卧看屋，吾意亦悠哉。"]'),
('abd1c073-863a-4cf5-9da7-02e88d39b3ed','五言雜興七首  其六','朱松','宋','宋诗','song-poetry','','[]','湛湛天宇清，宛宛穹脊白。',48,'全唐诗/poet.song.107000.json','["湛湛天宇清，宛宛穹脊白。", "投深得僧窗，千嶂倚蒼壁。", "開卷與晤言，炷香伴岑寂。", "獨將萬里心，收歛入尋尺。"]'),
('42fda3a3-b36e-46d0-8cd3-6ef8095fe27e','五言雜興七首  其七','朱松','宋','宋诗','song-poetry','','[]','身輕客已去，睡美體新浴。',48,'全唐诗/poet.song.107000.json','["身輕客已去，睡美體新浴。", "南風吹好句，歷歷韻松竹。", "雖云天耳聽，擬以幽夢續。", "不辭舉似人，恨汝心眼肉。"]'),
('a6a7c565-5814-421d-bf55-e612ce6b70c5','遊西峰院留別友人','朱松','宋','宋诗','song-poetry','','[]','兀兀掩關坐，后土冒泥塗。',144,'全唐诗/poet.song.107000.json','["兀兀掩關坐，后土冒泥塗。", "繁陰忽披猖，懷哉歎離居。", "眷我二三子，共此一日娛。", "欣然忘華陋，意行非始圖。", "圍竹粉黏带，弄泉雲遶裾。", "共賭羊山棋，不釣溫水魚。", "野色一以暝，歸舟相與拏。", "豈無軟脚酒，新熟不用沽。", "急景棄尺璧，中原睠丘墟。", "丈夫患不免，低回竟何如。", "安能逐兒輩，飛翔爭腐餘。", "但憂著鞭子，滯留嘲賈胡。"]'),
('fe8baf98-e6e4-434a-bf8d-51e094a694e5','飲梅花下贈客','朱松','宋','宋诗','song-poetry','','[]','憶挽梅花與君別，終年夢掛南臺月。',96,'全唐诗/poet.song.107000.json','["憶挽梅花與君別，終年夢掛南臺月。", "天涯谿上一尊酒，依舊風巵舞香雪。", "高情絕艷兩無言，玉笛冰灘自幽咽。", "却憐造物太多事，更要和鼎調人舌。", "浮生蹤跡風花裏，鼠壤珠宮孰優劣。", "且當醉倒此花前，猶勝相思寄愁絕。"]'),
('1dfe8c0d-641e-49c1-92d1-2392edb8a31d','次韻和吳駿卿','朱松','宋','宋诗','song-poetry','','[]','學道日已媮，干時心同嬾。',120,'全唐诗/poet.song.107000.json','["學道日已媮，干時心同嬾。", "同懷能幾人，俛仰風雨散。", "晚得吳王孫，抱釁戢高翰。", "由來清廟質，不賦白石爛。", "笑我塵土中，坐受微粟絆。", "新詩中音會，天律度絃管。", "未能載酒問，但作焚硯歎。", "况聞翻貝葉，一悟了真幻。", "文章廼兒劇，安用黑白判。", "何時商畧此，得酒不待勸。"]'),
('368fd2b9-d2ff-429b-b998-7667dc40f72a','求道人自尤溪來三山出示同徐侯遊龍門洞長篇因次其韻送之時以檄走諸隘','朱松','宋','宋诗','song-poetry','','[]','阿游陸沈久，亦復太癡絕。',192,'全唐诗/poet.song.107000.json','["阿游陸沈久，亦復太癡絕。", "未成安一枝，况乃辦三穴。", "唯餘愛山意，如水必東折。", "首鼠今幾年，顧影愧瓊玦。", "那知龍門客，塵底抱關闑。", "虛簷日偃仰，蒼壁對橫㙞。", "拄藤危蹬響，濯足細泉潔。", "束薪取奇觀，滴乳當嘉設。", "摩挲石蜿蜒，信矣耆舊說。", "欻疑卷風雨，凜若踐冰雪。", "遠追神清遊，復作武陵別。", "能詩有老休，聯句媲前哲。", "相逢快吟哦，亹亹霏鋸屑。", "三山今入手，瀛海僅可啜。", "崎嶇走林谷，王事煩此傑。", "擬結汗漫期，更待攙槍滅。"]'),
('3c6ffbae-afe8-46f6-9260-6f02c89f947e','吳駿卿寄示和黄元廣詩多及古人爲己之學輒復次韻資一大笑兼簡元廣  其一','朱松','宋','宋诗','song-poetry','','[]','四物覓安心，駕言無停驅。',48,'全唐诗/poet.song.107000.json','["四物覓安心，駕言無停驅。", "忽然休歇去，本自一物無。", "那於前後際，而有新故吾。", "知津恨未達，敢以偷自愚。"]'),
('04bef120-8b1b-4e12-9267-868e4b2ed30b','吳駿卿寄示和黄元廣詩多及古人爲己之學輒復次韻資一大笑兼簡元廣  其二','朱松','宋','宋诗','song-poetry','','[]','君居泥自蔽，鄰客旅兩足。',48,'全唐诗/poet.song.107000.json','["君居泥自蔽，鄰客旅兩足。", "詩成各超然，不復念瓶粟。", "應憐市門客，俯仰對流俗。", "出言不嫵媚，人瞋大於屋。"]'),
('eb411517-8e47-47f2-a8e6-23ffc18e4355','吳駿卿寄示和黄元廣詩多及古人爲己之學輒復次韻資一大笑兼簡元廣  其三','朱松','宋','宋诗','song-poetry','','[]','我生非瓠瓜，於世豈無情。',48,'全唐诗/poet.song.107000.json','["我生非瓠瓜，於世豈無情。", "望道渺未見，諒知負平生。", "將求挃挃穫，奈何鹵莽耕。", "饑壤聽造物，吾願乃秋成。"]'),
('8c6b8495-bbd3-4904-89da-c709185454df','次韻鄧天啟遊南國','朱松','宋','宋诗','song-poetry','','[]','秋犬吠夷門，誰能拊其背。',144,'全唐诗/poet.song.107000.json','["秋犬吠夷門，誰能拊其背。", "懷安壯士羞，竊食替操耒。", "無由一當虜，鬰鬰嚼齒碎。", "故人何自來，適與芳時對。", "笑我塵土中，勃窣守闤闠。", "城南出携手，遠取韓孟配。", "心期汗漫遊，目極泬寥內。", "舞雩追點也，峴首畧湛輩。", "豫愁君興闌，復遣我心憒。", "歸來疑夢斷，清境皎不昧。", "哦君斜川詩，汲井沃枯肺。", "願言薦清廟，勿賦風雨晦。"]'),
('775be6c5-3ac6-4faf-b2c5-9dc9f6f25655','徐侯以詩送山藥次韻','朱松','宋','宋诗','song-poetry','','[]','山中白玉延，貴壓梁宋價。',72,'全唐诗/poet.song.107000.json','["山中白玉延，貴壓梁宋價。", "筠籃出輪囷，了不煩造化。", "因傳競病句，中的若神射。", "頗念坐穩人，鞍馬久不跨。", "谿橋梅欲動，玉雪短枝亞。", "何當同嚼蕊，一醉山月下。"]'),
('0c45f17c-c39d-4c05-ac8f-cb768924749c','次韻酬求道人','朱松','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','聽君話匡廬，風月妙無價。',72,'全唐诗/poet.song.107000.json','["聽君話匡廬，風月妙無價。", "罏峯忽在前，俛仰疑幻化。", "新詩未出袖，光怪炯如射。", "懸知得力處，島可不足跨。", "家山爲誰留，鐺粥香䆉䅉。", "我亦懷秋江，波清鴻鴈下。"]'),
('2b0496f1-f17b-46ee-809e-ae5bae2ed859','求道人示詩粲然有江湖間道人風味蓋嘗得句法於東溪可今以其韻作詩送之時將如瑞峰期朝夕還吉祥云','朱松','宋','宋诗','song-poetry','','[]','癩可湓江濱，覓句負光價。',72,'全唐诗/poet.song.107000.json','["癩可湓江濱，覓句負光價。", "君爲東溪客，伏鵠資妙化。", "想見箭鋒機，相拄不停射。", "伽陀入三昧，湯史欲凌跨。", "韋齋語清夜，挂月松偃亞。", "他年約相逢，禪榻慎勿下。"]'),
('8feb12f4-e363-4e1a-a90a-a77fd7da124c','贈永和西堂道人','朱松','宋','宋诗','song-poetry','','[]','蒼山抱岑寂，丈室掩虛白。',72,'全唐诗/poet.song.107000.json','["蒼山抱岑寂，丈室掩虛白。", "道人塵機斷，宇宙一西壁。", "是心如焦穀，浩劫永枯寂。", "一句從誰聞，投老承此力。", "相逢不相問，未省誰主客。", "咄去真俗人，胡爲來役役。"]'),
('d1843b2e-37b5-4655-bb90-07ff49d1c4e3','彥時過永和見和拙句輒復次韻以發一笑','朱松','宋','宋诗','song-poetry','','[]','老諗不下牀，胸次紛黑白。',72,'全唐诗/poet.song.107000.json','["老諗不下牀，胸次紛黑白。", "彌明亦强項，得句鼾負壁。", "相逢復何事，一笑萬慮寂。", "新詩追舊韻，俯仰見筆力。", "何時折鐺傍，鼎坐無主客。", "區區竟何補，斗粟真自役。"]'),
('37f6a62a-69db-4abe-a7ca-08d0742a1517','甲辰七月二日宿永和寺用舊詩韻','朱松','宋','宋诗','song-poetry','','[]','湛湛天宇清，宛宛穹脊白。',72,'全唐诗/poet.song.107000.json','["湛湛天宇清，宛宛穹脊白。", "投深得僧窗，千嶂倚蒼壁。", "開卷與晤言，炷香伴岑寂。", "了無魔嬈夢，皎皎知道力。", "鳴珂綠槐影，想見下朝客。", "笑我守吳門，心形等相役。"]'),
('afc41f90-cf8c-4a5f-8f4a-a6a1b9e92db1','寄陳蹈元','朱松','宋','宋诗','song-poetry','','[]','我生少所可，靡靡世一律。',192,'全唐诗/poet.song.107000.json','["我生少所可，靡靡世一律。", "如君素心人，指不三四屈。", "久與宵人遊，歸卧常自失。", "效尤起媮心，阿意增美疾。", "低回强酬酢，高論形敢出。", "緬懷參同子，蚤入伊洛室。", "聞道既先我，論詩又奇崛。", "縱橫談天口，卓犖扛鼎筆。", "勝我何足云，論交敢自必。", "桓公肯見規，寡過行有日。", "書來約過從，一笑破蕭瑟。", "新凉宜燈火，永夜勘書帙。", "豈無一尊酒，少促軟語膝。", "更呼小叢歌，未怕官長詰。", "跂予占騎氣，千嶺秋回鬰。", "著鞭及清境，灧灧月華溢。"]'),
('3d99a2d3-3abc-497e-a8c6-ebd8b770facf','次韻張漕茶山喜雨','朱松','宋','宋诗','song-poetry','','[]','天公積憤何曾雪，遑恤茶工貪攬擷。',160,'全唐诗/poet.song.107000.json','["天公積憤何曾雪，遑恤茶工貪攬擷。", "無聊桃李困遲遲，暗白蔫紅飛亂擷。", "誰疏天漢下穹窿，苦厭風霾昏嵽嵲。", "行臺使者掃雲手，釃酒叢祠拜靈蕝。", "歸來一雨動三日，溝壑遺民起垂絕。", "豈唯槍旗各呈露，更喜筍蕨爭芽茁。", "明朝擊鼓萬指集，雲蹬携籝穿曲折。", "紅塵一騎天容開，顧渚蒙山坐銷歇。", "帝觴嘗罷思苦口，公如子牟心魏闕。", "金鑾諫舌夜生塵，回首山中記同啜。"]'),
('224c0cd0-7443-43a6-baec-ba2529557579','沙谿口望梨山','朱松','宋','宋诗','song-poetry','','[]','衆山如連環，平野忽呀口。',108,'全唐诗/poet.song.107000.json','["衆山如連環，平野忽呀口。", "孤峯插深雲，氣壓萬培塿。", "區區何足傑，落落終自負。", "我行清谿曲，鶴立倚筇久。", "拂衣竟何時，塵土坐自垢。", "長梯弄玉井，奇字窺岣嶁。", "心知不能去，照水顔甲厚。", "永懷山中人，獨立誰與友。", "神交解此意，長嘯震林阜。"]'),
('43c4562a-c031-4f6c-a6a2-3e4b51e7be17','寄仁王求首座','朱松','宋','宋诗','song-poetry','','[]','片帆西借東風力，回首三山春一色。',96,'全唐诗/poet.song.107000.json','["片帆西借東風力，回首三山春一色。", "何人孤嘯月中聞，知是無塵岩上客。", "風山武夷之宗支，千岩萬壑帝所規。", "天憐傲吏賜我履，恨不與子相諧嬉。", "問法年來定成市，藤蔓遥知罥衣袂。", "手攀荔子約同嘗，絕勝林間啄殘柿。"]'),
('922727a2-942f-42d8-877b-0b4ebfff2bdc','汪彥允見和約遊東山作荔枝次韻','朱松','宋','宋诗','song-poetry','','[]','天工傾倒不餘力，唯有荔枝香味色。',96,'全唐诗/poet.song.107000.json','["天工傾倒不餘力，唯有荔枝香味色。", "君家桃李要爭妍，腸斷鬢絲禪榻客。", "書生甕葅天所支，煮茗誇妓非良規。", "腹饑眼寒君不忍，著詩喚作東山嬉。", "冰盤絳實光照市，歸來香滿巫陽袂。", "明日人傳玉蕊仙，絕勝空賦青龍柿。"]'),
('151ab963-fa61-4225-8396-3944c6f7c2fc','止戈堂','朱松','宋','宋诗','song-poetry','','[]','高堂巖巖面勢尊，洞見萬井開重門。',256,'全唐诗/poet.song.107000.json','["高堂巖巖面勢尊，洞見萬井開重門。", "元戎務簡玉帳靜，緩带酌客娛朝昏。", "憶初餓隸起篁竹，一嘯千里來黥髠。", "將軍攬鏡媚巾幗，何異搏虎驅狐豚。", "只今休父八州牧，身佩重寄憂元元。", "驚塵錯莫羽書密，雖有美酒誰同樽。", "沈機且復長轡御，瀝懇何啻血面論。", "樓船一夕飛度海，漢家上將來天閽。", "狂童束手赴烈火，琱戈不污妖血痕。", "坐譙飲至凱歌入，船粟往哺遺民存。", "五兵包裹高閣束，止戈新榜真成言。", "便當頻與方外吏，徙倚風月星河翻。", "幾年牡籥飛不守，河濟逆氣腥乾坤。", "知公快挽天河手，坐視黠虜方遊魂。", "權輿閩越聊小試，寧復久此淹遐藩。", "農桑萬里望公等，願見四海無營屯。"]'),
('90a00d6e-021e-4481-9ed9-7a601279daaf','侏儒','朱松','宋','宋诗','song-poetry','','[]','侏儒飽官粟，適市行勃窣。',48,'全唐诗/poet.song.107000.json','["侏儒飽官粟，適市行勃窣。", "但知隨衆笑，了不見優拙。", "暮歸遭客問，閔默羞齰舌。", "心知續鳬悲，慎莫尤造物。"]'),
('5ce8e19c-d939-410f-911e-844e5495fd9f','中秋賞月','朱松','宋','宋诗','song-poetry','','[]','去年中秋雨，野蘆凄薄寒。',168,'全唐诗/poet.song.107000.json','["去年中秋雨，野蘆凄薄寒。", "驚塵暗一方，客枕那得安。", "起呼對牀笫，攬衣步蹣跚。", "握手仰太息，宇宙何時寬。", "今年中秋月，並海窺濤瀾。", "坐看鬰藍天，忽湧白玉盤。", "眷言雙峰客，倚閭念衣單。", "亦復取樽酒，承顔有餘歡。", "天涯等牢落，世路方艱難。", "且遵秉燭語，毋爲泣河歎。", "停盃玩飛轍，河漢靜不湍。", "癡兒亦不眠，苦覓蛙兔看。", "洲出暗潮落，鬢衰香霧漙。", "佳句付惠連，何時解歸鞍。"]'),
('a11aa060-c02c-4e31-a16b-5d23a3fecc45','記草木雜詩七首 月桂花','朱松','宋','宋诗','song-poetry','','[]','窗前小桂叢，著花無曠月。',84,'全唐诗/poet.song.107000.json','["窗前小桂叢，著花無曠月。", "月行晦朔周，一再開復歇。", "初如醉肌紅，忽作絳裙色。", "誰人相料理，耿耿自開落。", "有如貧家女，信美乏風格。", "春風木芍藥，穠艷傾一國。", "芳根維無恙，歲晚但枯枿。"]'),
('53d496c5-ef9f-4d96-b59d-0abc51ccf959','記草木雜詩七首 萱草','朱松','宋','宋诗','song-poetry','','[]','水菽怡慈顔，萬鍾亦土苴。',72,'全唐诗/poet.song.107000.json','["水菽怡慈顔，萬鍾亦土苴。", "時從班衣兒，蓺萱北堂下。", "穠華夫豈少，愛此入風雅。", "紛敷翠羽叢，絳英爛如赭。", "諸孫遶銀鹿，采摘動盈把。", "誰言壺中春，在此眉壽斝。"]'),
('a5291f51-b467-4ca8-b1d4-a2efb2356510','記草木雜詩七首 紫竹','朱松','宋','宋诗','song-poetry','','[]','新移紫玉幹，羅列才十餘。',108,'全唐诗/poet.song.107000.json','["新移紫玉幹，羅列才十餘。", "枝葉一何病，意色慘不舒。", "旱久土膏燥，抱甕愁僕夫。", "雖無樵蘇厄，苦欠雨露濡。", "我來侶魚蝦，滄溟在階除。", "月窗瀉水墨，天風韻虛徐。", "誰言居無友，此君良不疏。", "三年爲主人，籜孫定紛如。", "他時報安否，誰寄青泥書。"]'),
('74c1cc5d-45f1-48e9-af70-4e3ef98bbe85','記草木雜詩七首 茱菊','朱松','宋','宋诗','song-poetry','','[]','海上作重九，菊揉青蕊香。',72,'全唐诗/poet.song.107000.json','["海上作重九，菊揉青蕊香。", "近墟買茱萸，枯顆出藥囊。", "兒曹記土風，歉歉事祈禳。", "老夫未免俗，聊爾答風光。", "災祥理不僭，此柄孰主張。", "譌言眩末俗，吾欲案長房。"]'),
('c88de98a-2f8b-40a2-85a4-9aee1d876d93','記草木雜詩七首 吉貝','朱松','宋','宋诗','song-poetry','','[]','炎海霜雪少，畏寒直過憂。',108,'全唐诗/poet.song.107000.json','["炎海霜雪少，畏寒直過憂。", "駝褐阻關河，吉貝亦可裘。", "投種望著花，期以三春秋。", "茸茸鵞毳凈，一一野繭抽。", "南北走百價，白氎光欲流。", "似聞邊烽急，緣江列貔貅。", "裁襦襯鐵衣，愛此溫且柔。", "天乎未厭亂，利厚人益媮。", "誰知海濱客，獨歎無人酬。"]'),
('5ebb2398-dedc-418d-9fe3-300847dd229b','記草木雜詩七首 芭蕉','朱松','宋','宋诗','song-poetry','','[]','地鹵不敏樹，珍植何由暢。',96,'全唐诗/poet.song.107000.json','["地鹵不敏樹，珍植何由暢。", "斸根移芭蕉，美蔭跂可望。", "芳心日卷舒，翠葉忽張王。", "偏工鳴秋雨，疏密眇難狀。", "霜風一以厲，狼籍坐惆悵。", "誰言繿縷中，秋子得佳餉。", "緗囊貯瑞露，厚味天所貺。", "懷哉臘毒言，節口畏生瘴。"]'),
('8521a26d-3ad4-4c31-93c0-52f4b05ae34e','記草木雜詩七首 菖蒲','朱松','宋','宋诗','song-poetry','','[]','東山在眉宇，未到心鬰紆。',96,'全唐诗/poet.song.107000.json','["東山在眉宇，未到心鬰紆。", "流泉撞哀玉，清洌生菖蒲。", "聞有嬋娟子，棄家來結廬。", "窈窕雲霧窗，參差冰玉膚。", "絕粒屏香節，仙姿清且腴。", "邇來隠身去，冷落愁臞儒。", "靈方無由乞，石斗移根鬚。", "相看意已消，何必見子都。"]'),
('78bbc9a9-b5d7-4cd4-95d8-9625d0e108c5','海上','朱松','宋','宋诗','song-poetry','','[]','落日弄雲海，閬風欲手攀。',96,'全唐诗/poet.song.107000.json','["落日弄雲海，閬風欲手攀。", "秀色不可解，西山如連環。", "緬懷避世人，結屋棲孱顔。", "眎世一蝸角，笑憫觸與蠻。", "我生笑癡仙，遂恬升斗慳。", "尚餘詩書債，倖此朱墨閑。", "纓冠出救鬬，安得長閉關。", "仙人形識此，妄自憑愚頑。"]'),
('bf2152bd-3ba2-44a4-b3fe-e44304894fdf','送祝仲容歸新安','朱松','宋','宋诗','song-poetry','','[]','歷亂百憂心，漂零一涯天。',168,'全唐诗/poet.song.107000.json','["歷亂百憂心，漂零一涯天。", "讀禮不盈尺，眼萎坐自憐。", "君來訪安否，春風柳吹綿。", "篝燈語平生，惝恍夜不眠。", "那知歲月度，但怪冰雪堅。", "感君懷親意，使我淚貫泉。", "高堂急榮養，躬耕恨無田。", "筆端日五色，氣壓諸生前。", "聖門要鑽仰，至味研簡編。", "經綸出緒餘，文字忘蹄筌。", "他年閒擊竹，妙契琴無絃。", "此時一瓣香，竟爲何人然。", "江湖多北風，懷哉歸袖翩。", "刮目看奮飛，此道更著鞭。"]'),
('ebcdc014-d245-4f1f-96d4-8eb085c8c511','次韻彥繼用前輩韻三首 餽歲','朱松','宋','宋诗','song-poetry','','[]','歲晚追土風，獨甕誰與佐。',96,'全唐诗/poet.song.107000.json','["歲晚追土風，獨甕誰與佐。", "人心感流光，臺餽屏奇貨。", "雞豚取牢柵，門戶隨小大。", "去鄉二十年，憶此但愁卧。", "兒癡元未識，但索梨飣坐。", "何時鴉識村，莫作馿轉磨。", "不須志四方，教子求寡過。", "歸哉及强健，老去煩劑和。"]'),
('c9dbeee5-9536-4dee-8dd5-c40255ddfcc6','次韻彥繼用前輩韻三首 別歲','朱松','宋','宋诗','song-poetry','','[]','舊歲已趣駕，爲我不少遲。',96,'全唐诗/poet.song.107000.json','["舊歲已趣駕，爲我不少遲。", "凡心畏增年，而歲豈容追。", "丈夫有蠖屈，牢落天南涯。", "收功英妙年，豪傑彼一時。", "寧當如秦越，坐視瘠與肥。", "鄰翁意誠厚，酌酒寬愁悲。", "慇懃何時忘，祝我致好辭。", "撫世非吾事，諸公正扶衰。"]'),
('35f1dffd-bd5c-45e2-8c55-51127f509975','次韻彥繼用前輩韻三首 守歲','朱松','宋','宋诗','song-poetry','','[]','庭燎夜未央，旌旗煥龍蛇。',96,'全唐诗/poet.song.107000.json','["庭燎夜未央，旌旗煥龍蛇。", "九門一放鎖，萬馬誰能遮。", "亂離憶舊事，安眠夢無何。", "目眩燈燭光，坐厭兒女譁。", "念此亦土風，雖癡不容撾。", "更爲盧白戲，紛爭起橫斜。", "故歲不足計，新歲莫蹉跎。", "努力誦書史，從人笑翁誇。"]'),
('4d9c3bfa-f77a-461a-be8e-cc45389095e1','奉同胡德輝八月十四日夜玩月次韻  其一','朱松','宋','宋诗','song-poetry','','[]','我夢故山月，蘿影垂秋光。',72,'全唐诗/poet.song.107000.json','["我夢故山月，蘿影垂秋光。", "誰言九衢曉，莽莽吹塵黄。", "群公直道山，晤語清夜央。", "飛轍轉空闊，積暑蘇蒼凉。", "哦詩中天律，流光惜堂堂。", "雞肥社酒熟，吾亦懷吾鄉。"]'),
('ee2da93e-ef2b-404a-beab-87a0fe0aae56','奉同胡德輝八月十四日夜玩月次韻  其二','朱松','宋','宋诗','song-poetry','','[]','亭亭月初高，河漢坐可搴。',72,'全唐诗/poet.song.107000.json','["亭亭月初高，河漢坐可搴。", "病餘久制酒，灝氣兩爭先。", "振衣萬里風，歸袖何時翩。", "懷哉故山友，共此今夕圓。", "離離雲飛鴻，何意影沈川。", "觀心要知是，出處直悠然。"]'),
('2ec36950-b091-409e-91e6-6c8a7270a90e','巖桂花','朱松','宋','宋诗','song-poetry','','[]','開門驚積葉，秋氣日以厲。',48,'全唐诗/poet.song.107000.json','["開門驚積葉，秋氣日以厲。", "獨芳摇落中，粲粲巖下桂。", "幽芳不自憐，怊悵紛滿地。", "未忍蹋殘英，何以娛晚歲。"]'),
('86a0e480-efa5-498d-bc1e-a85584b06654','中秋夜雨','朱松','宋','宋诗','song-poetry','','[]','秋雲定何心，忍翳今夕月。',96,'全唐诗/poet.song.107000.json','["秋雲定何心，忍翳今夕月。", "尚嫌微點綴，况廼都漫滅。", "他日任氛霾，數日望清澈。", "倦投衲子窗，竹雨聽騷屑。", "對牀不成夢，有酒那能設。", "螢飛矜意氣，蟲語轉幽咽。", "心知層陰表，皎皎玉輪潔。", "何當凌倒景，徙倚玩飛轍。"]'),
('98fd5d36-3864-476e-8f67-5fb35db360b0','夜坐','朱松','宋','宋诗','song-poetry','','[]','棲遲客異縣，名氏藏丹丘。',120,'全唐诗/poet.song.107000.json','["棲遲客異縣，名氏藏丹丘。", "希世非夙尚，素餐愧前修。", "日耗大倉陳，一飽寬百憂。", "眷焉撫平生，信亦無幾求。", "蒙籠小窗底，圖史漫不收。", "篝燈揩病眼，昏花亂蚍蜉。", "愚儒未忘世，撫事非所謀。", "不如遂捐書，卒歲以優游。", "懷膠睨崑墟，濁浪排高秋。", "知難有明訓，吾其老鋤耰。"]'),
('f54764a1-5cd4-4cb1-a1ea-3d95d3846a61','秋懷二首  其一','朱松','宋','宋诗','song-poetry','','[]','鏗然一葉脫，中夜歎以驚。',48,'全唐诗/poet.song.107000.json','["鏗然一葉脫，中夜歎以驚。", "及茲遂摇落，風露漭難平。", "晼晚愁自滋，淹留謇何營。", "騰騰任天運，庶幾得吾生。"]'),
('e8c85f2c-3862-4082-9c43-45e5469568ab','秋懷二首  其二','朱松','宋','宋诗','song-poetry','','[]','中郎章句儒，失身徇邦仇。',48,'全唐诗/poet.song.107000.json','["中郎章句儒，失身徇邦仇。", "一歎不自知，邂逅死孤囚。", "凜凜南昌仙，斗食身百憂。", "渺然元始後，滅跡不可求。"]'),
('ed7b1d18-f675-4e03-99ee-148ae97d380b','圍棋','朱松','宋','宋诗','song-poetry','','[]','投老一寸心，獨立無攀緣。',120,'全唐诗/poet.song.107000.json','["投老一寸心，獨立無攀緣。", "兀兀不自聊，愔愔誰與宣。", "時有素心人，一枰奉周旋。", "得雋非至數，三捷亦偶然。", "危思寄方罫，積威下虛弦。", "驕矜不須臾，奔北已可憐。", "志士珍短景，顧謂璧可捐。", "聖門未及藩，遠道要著鞭。", "緬想運甓翁，操具投長川。", "自强聖所臧，懷哉撫韋編。"]'),
('9cd2adcc-086d-4335-b770-634f8843f186','談命','朱松','宋','宋诗','song-poetry','','[]','岑寂契心賞，棲遲幸身閑。',120,'全唐诗/poet.song.107000.json','["岑寂契心賞，棲遲幸身閑。", "却掃味道腴，未厭藜藿慳。", "久絕子公書，羞訪季主關。", "肯爲空際塵，起此胸中山。", "曆翁推始生，邂逅盃酒間。", "自今半運中，且作尺蠖跧。", "蕭蕭兩鬢髮，已白不復斑。", "功名日以疏，落落難强顔。", "譬如坐穩人，正苦步作艱。", "夸毗付餘子，彼哉謝追攀。"]'),
('b3c1a33f-87d6-4a9d-bffa-0bf8014ddf1c','吳江曲','朱松','宋','宋诗','song-poetry','','[]','吳江女兒白如玉，花底紗窗傍谿淥。',64,'全唐诗/poet.song.107000.json','["吳江女兒白如玉，花底紗窗傍谿淥。", "玉簫春暖貼朱脣，故作陽春斷腸曲。", "扁舟掠水去如飛，不見嫣然一笑時。", "回首江城只孤塔，向來一念復因誰。"]'),
('4402342f-c018-42d2-8475-73a459d1121a','梨','朱松','宋','宋诗','song-poetry','','[]','一霜木葉紛紛妥，園夫獻梨紅頰橢。',32,'全唐诗/poet.song.107000.json','["一霜木葉紛紛妥，園夫獻梨紅頰橢。", "亦知胸次本清凉，且欲與君充飣坐。"]'),
('540e71b3-0cbc-4fd3-a8a3-64f2dd14da11','解汲舟','朱松','宋','宋诗','song-poetry','','[]','上國經年客，春流一棹波。',48,'全唐诗/poet.song.107000.json','["上國經年客，春流一棹波。", "已醒離帳酒，猶記客亭歌。", "水枕殘歸夢，霜衾擁獨哦。", "蓬窗橫落月，作意傍人多。"]'),
('f723bbd3-3705-4fd7-91f9-0db5e6ff63d0','淮南道中微雪','朱松','宋','宋诗','song-poetry','','[]','密密雲陰合，斜斜雪態妍。',48,'全唐诗/poet.song.107000.json','["密密雲陰合，斜斜雪態妍。", "似欺春力淺，故傍客愁邊。", "宿鳥投村暝，寒梅抱蕊鮮。", "無人命尊酒，清絕裊茶烟。"]'),
('8ed26817-40aa-44ca-9309-a7a578a46939','送沈昌時赴寧海令兼敘別二首  其一','朱松','宋','宋诗','song-poetry','','[]','俯仰塵埃二十年，天涯初此試鳴絃。',64,'全唐诗/poet.song.107000.json','["俯仰塵埃二十年，天涯初此試鳴絃。", "正緣五斗羞陶令，莫歎三江阻鄭虔。", "饞吏誅求何日饜，羸民凋瘵豈容鞭。", "故人便使來當路，終恐勞公自挽船。"]'),
('dc884620-75d4-4339-81d1-939d3883a7fa','送沈昌時赴寧海令兼敘別二首  其二','朱松','宋','宋诗','song-poetry','','[]','午潮平處落歸帆，已覺離情兩不堪。',64,'全唐诗/poet.song.107000.json','["午潮平處落歸帆，已覺離情兩不堪。", "轉手便成千日別，悲歌聊倚一盃酣。", "波翻別壑聞車水，青遍柔桑趁浴蠶。", "歸路春深風日美，伴誰操筆賦幽探。"]'),
('07b9f75c-2044-4530-8dbf-b6930038a0ca','西湖泛舟','朱松','宋','宋诗','song-poetry','','["\u897f\u6e56"]','望湖樓下照衰顔，羞見塵埃兩鬢斑。',64,'全唐诗/poet.song.107000.json','["望湖樓下照衰顔，羞見塵埃兩鬢斑。", "風艇縱看山轉側，烟堤儘逐水回還。", "喚人歸去城鐘急，觸處相親嶺月彎。", "不用新詩摹絕境，定知長到夢魂間。"]'),
('eb3768c7-827e-435d-a14f-3c9549a4bbd5','和舜明晚雨','朱松','宋','宋诗','song-poetry','','[]','一雨平龜坼，層臺轉小凉。',48,'全唐诗/poet.song.107000.json','["一雨平龜坼，層臺轉小凉。", "吟羞東野窘，醉想謫仙狂。", "濕翠生苔徑，餘清襲芰裳。", "王郎不相顧，掃地靜焚香。"]'),
('427cd4cb-b883-47df-a638-27f1ce305c20','贈言命張生','朱松','宋','宋诗','song-poetry','','[]','俛仰塵埃的自羞，稍看寒餓復誰憂。',64,'全唐诗/poet.song.107000.json','["俛仰塵埃的自羞，稍看寒餓復誰憂。", "小兒造物巧相戲，窮鬼逐人殊未休。", "我所不知煩子算，世如無取更何求。", "服箱挹酒真么麽，那用區區問斗牛。"]'),
('7c441a53-8a11-4c4f-ad23-358bc5c30813','東陽社日泛舟觀競渡','朱松','宋','宋诗','song-poetry','','[]','誰喚思家客，來爲蕩槳嬉。',48,'全唐诗/poet.song.107000.json','["誰喚思家客，來爲蕩槳嬉。", "鬢華羞照水，雨意解催詩。", "疊鼓飛文鷁，香鬟出短籬。", "醉歸真夢覺，猶憶湔裙時。"]'),
('ffdd3ce8-c7d2-46b2-b59d-adcf0396a80a','熊積道桂軒','朱松','宋','宋诗','song-poetry','','[]','覓種老蟾窟，培根芹水傍。',72,'全唐诗/poet.song.107000.json','["覓種老蟾窟，培根芹水傍。", "書燈移素影，詩筆带餘香。", "家計傳韋業，孫枝繼郄芳。", "山川供秀潤，蘭玉競輝光。", "那把攀雲手，空持種樹方。", "嗟無月脇句，惡語汙君梁。"]'),
('aa1e355c-f2b3-4a3f-bbac-6dbbef11591c','宿延慶寺','朱松','宋','宋诗','song-poetry','','[]','浮榮過眼旋銷忘，惟有谿山意味長。',64,'全唐诗/poet.song.107000.json','["浮榮過眼旋銷忘，惟有谿山意味長。", "身健不嫌穿犖确，塵空那復戲滄浪。", "林鍾喚客烟藏寺，風葉鳴秋竹蔭廊。", "一似雲谿醉眠處，只應軟語欠支郎。"]'),
('2fa2212b-4265-4757-95e6-7781554767fb','贈僧','朱松','宋','宋诗','song-poetry','','[]','知有叢林特地過，幅巾迎笑出巖阿。',64,'全唐诗/poet.song.107000.json','["知有叢林特地過，幅巾迎笑出巖阿。", "杖藜同覓牛羊路，濯足來分鷗鷺波。", "豈不倦遊貪斗粟，坐令歸思動漁蓑。", "他年會有相逢日，稍食吾言聽子呵。"]'),
('e74495d2-fbda-40b5-be88-1700a6346f91','三峰長老送紙被','朱松','宋','宋诗','song-poetry','','[]','笑我布衾故，分君楮幅溫。',48,'全唐诗/poet.song.107000.json','["笑我布衾故，分君楮幅溫。", "尚嫌肱當枕，端稱蓆爲門。", "敗篋薪錢盡，幽窗雪意昏。", "寤驚雙脚暖，猶恐錦鯨存。"]'),
('88b75414-8678-49db-bf09-6bf34ba3d8ac','盆中梅花','朱松','宋','宋诗','song-poetry','','[]','兀兀天涯客，依依雪谷花。',48,'全唐诗/poet.song.107000.json','["兀兀天涯客，依依雪谷花。", "莫辭遮病眼，相伴送年華。", "勸我三盃釂，熏心一念邪。", "幽香戀吟筆，半墮墨池漥。"]'),
('5e453d59-e9d3-4915-b4ea-a0ecac468fe9','月下','朱松','宋','宋诗','song-poetry','','[]','幽獨不自得，出門誰適從。',48,'全唐诗/poet.song.107000.json','["幽獨不自得，出門誰適從。", "滔滔我不即，踽踽世寧容。", "吾道固應爾，何人此意同。", "唯餘穿戶月，照我一尊空。"]'),
('dd1b6d47-ffd8-473e-b5a2-ff4f7b73944a','留別卓民表','朱松','宋','宋诗','song-poetry','','[]','末俗紛紛事不情，天涯懷抱向誰傾。',64,'全唐诗/poet.song.107000.json','["末俗紛紛事不情，天涯懷抱向誰傾。", "漂流空度三秋日，邂逅來逢四海兄。", "剪燭西窗驚睡夢，對牀夜雨話平生。", "滔滔世路方同騖，何日相期問耦耕。"]'),
('fe9410a0-771b-4414-b8dd-8eb028b994d2','寒食','朱松','宋','宋诗','song-poetry','','[]','粥冷春餳凍，泥開臘酒斟。',48,'全唐诗/poet.song.107000.json','["粥冷春餳凍，泥開臘酒斟。", "故鄉空淚滿，華髮正愁侵。", "山暝雨還住，烟孤村更深。", "誰知江海客，浩蕩濟時心。"]'),
('3f390dac-6144-4e61-bc6a-9188e9f254bd','延福寺觀酴醾','朱松','宋','宋诗','song-poetry','','[]','幽棲一壑無來轍，睡起忽驚春已深。',64,'全唐诗/poet.song.107000.json','["幽棲一壑無來轍，睡起忽驚春已深。", "踏青不趁溱洧女，曳杖來尋薝蔔林。", "長條挽處雲籠袖，幽佩歸時月滿襟。", "武谿回首醉眠地，香力一熏愁到今。"]'),
('6931392b-ea01-4792-ae0b-18cd827d3de6','寄吳及之','朱松','宋','宋诗','song-poetry','','[]','世事今人舌本强，滔滔何處是吾鄉。',64,'全唐诗/poet.song.107000.json','["世事今人舌本强，滔滔何處是吾鄉。", "未成微服隠吳市，且可携筇訪草堂。", "欲買雞豚投近社，少陪風月坐胡牀。", "共將絕唱追韓孟，一飲還須釂百觴。"]'),
('eac68757-642d-446f-af08-9b36c6ed43e2','答卓民表送茶','朱松','宋','宋诗','song-poetry','','[]','攪雲飛雪一番新，誰念幽人尚食陳。',64,'全唐诗/poet.song.107000.json','["攪雲飛雪一番新，誰念幽人尚食陳。", "髣髴三生玉川子，破除千餠建谿春。", "喚回窈窈清都夢，洗盡蓬蓬渴肺塵。", "便欲乘風度芹水，却悲狡獪得君嗔。"]'),
('c5b489ef-5b26-48fe-88f9-bced18514d4c','和人遊仙峰庵三首  其一','朱松','宋','宋诗','song-poetry','','[]','千巖萬壑翠縈回，一洗衰翁病眼開。',64,'全唐诗/poet.song.107000.json','["千巖萬壑翠縈回，一洗衰翁病眼開。", "落日多情留別嶺，秋空無地著浮埃。", "雲閑出岫初無意，松老參天豈願材。", "我是散仙君記取，更鞭鸞鳳少徘徊。"]'),
('72f14ebb-7828-40fd-bf00-6a2285ec5c89','和人遊仙峰庵三首  其二','朱松','宋','宋诗','song-poetry','','[]','誰麾俗駕挽今回，珍重山翁小徑開。',64,'全唐诗/poet.song.107000.json','["誰麾俗駕挽今回，珍重山翁小徑開。", "去覓雲峯攀碧落，下看沙劫壞飛埃。", "掬寒露井銷塵想，擷翠筠籃富藥材。", "彷彿三生曾到此，樓鐘重聽一徘徊。"]'),
('b97d4374-598d-41f1-b026-23eea43294b8','和人遊仙峰庵三首  其三','朱松','宋','宋诗','song-poetry','','[]','脚底千峯翠浪奔，雲端掛此一豪身。',64,'全唐诗/poet.song.107000.json','["脚底千峯翠浪奔，雲端掛此一豪身。", "山河了了窮千界，物我紛紛共一塵。", "浪趁下方追日步，恨非本色住庵人。", "他年八極浮遊遍，來讀新詩迹未陳。"]'),
('896a3e14-df16-4613-a9d4-4a375dadbce5','寄金確然','朱松','宋','宋诗','song-poetry','','[]','金子卧空谷，何人賦白駒。',48,'全唐诗/poet.song.107000.json','["金子卧空谷，何人賦白駒。", "僧斟三味酒，客薦一囊書。", "歸夢寒應短，詩腸饑自呼。", "强穿東郭履，來煮雪畦蔬。"]'),
('5090c91d-b586-42ef-a966-fa855e982547','次韻菊坡','朱松','宋','宋诗','song-poetry','','[]','露浥秋英濕曉陰，小坡新斸佇幽尋。',64,'全唐诗/poet.song.107000.json','["露浥秋英濕曉陰，小坡新斸佇幽尋。", "似欺蘭畹方披羽，聊對風巵旋屑金。", "采采遶籬吟欲就，垂垂壓帽醉難任。", "使君致主唐虞了，三徑無忘此日心。"]'),
('d0709d62-3928-46f7-96ce-1591d658c15e','蘆檻','朱松','宋','宋诗','song-poetry','','[]','手斸修蘆著檻栽，使君公退幾徘徊。',64,'全唐诗/poet.song.107000.json','["手斸修蘆著檻栽，使君公退幾徘徊。", "想當風雨翻叢急，疑卷江湖入座來。", "未辦松窗眠綠浦，且將屐齒印蒼苔。", "種成桃李人間滿，應念孤根首屢回。"]'),
('719841a0-19d5-491f-ac95-cde564982909','春晚五言寄夢得','朱松','宋','宋诗','song-poetry','','[]','美景足可惜，殘春尤不堪。',48,'全唐诗/poet.song.107000.json','["美景足可惜，殘春尤不堪。", "晚英餘燕蹴，熟顆墜鶑含。", "歲月蓬雙鬢，生涯粟一甔。", "唯思對公瑾，把酒話江南。"]'),
('568d0cf4-8ffb-4d14-bb13-1c422571f6dd','再答諸公','朱松','宋','宋诗','song-poetry','','[]','芳節坐晼晚，客懷無一堪。',48,'全唐诗/poet.song.107000.json','["芳節坐晼晚，客懷無一堪。", "柳眠猶自困，花笑爲誰含。", "風揭拾遺屋，塵生執㦸甔。", "聯詩頼諸友，妙句壓城南。"]'),
('1297c598-29b1-4475-9da1-7deb73a401ed','董邦則求茶軒詩次韻','朱松','宋','宋诗','song-poetry','','[]','一軒新築敞柴荆，北苑塵飛客思清。',64,'全唐诗/poet.song.107000.json','["一軒新築敞柴荆，北苑塵飛客思清。", "更買樵青娛晚景，便應盧老是前生。", "千門北闕夢不到，一卷玉杯心自明。", "冷看田侯堂上客，醉中談笑起相烹。"]'),
('673828f4-b3f5-463c-b8cc-1ec870727efb','送仲猷北歸二首  其一','朱松','宋','宋诗','song-poetry','','[]','一丘胸次有餘師，空此淹留歲月遲。',64,'全唐诗/poet.song.107000.json','["一丘胸次有餘師，空此淹留歲月遲。", "黄墨工夫憐我倦，簞瓢風味要君知。", "新詩落筆驚翻水，俗學回頭笑畫脂。", "伊洛參同得力句，還家欲舉定從誰。"]'),
('d76ef540-12ad-4011-b53f-0c2cdba2de61','送仲猷北歸二首  其二','朱松','宋','宋诗','song-poetry','','[]','欲尋當日故山盟，身世今如海一萍。',64,'全唐诗/poet.song.107000.json','["欲尋當日故山盟，身世今如海一萍。", "歸路上心真了了，愁根入鬢已星星。", "挽衣共釂東西酒，折柳送行長短亭。", "念我知君回首處，萱叢菖葉一時青。"]'),
('4534d1bc-198e-48bf-9e32-b5f03c9eeeae','寄吳致一','朱松','宋','宋诗','song-poetry','','[]','相逢一笑兩忘懷，夢遶親庭首重回。',64,'全唐诗/poet.song.107000.json','["相逢一笑兩忘懷，夢遶親庭首重回。", "世事難磨三尺喙，離愁都付一分盃。", "秋生林薄歲時晚，水落江湖鴻鴈來。", "賸作新詩頻寄我，天涯時對兩眉開。"]'),
('0ba77d58-b7f5-4546-b631-194a31cd9b6f','四月十五日上元道中','朱松','宋','宋诗','song-poetry','','[]','亂山身逐簡書來，梅子黄時雨未開。',64,'全唐诗/poet.song.107000.json','["亂山身逐簡書來，梅子黄時雨未開。", "一葦橫斜風葉度，千灘贔屭雪城催。", "危機種種那容避，俗駕駸駸底未回。", "聊復浮遊隨造物，故園回首思悠哉。"]'),
('7e3d2f18-8b8e-4f14-95c8-d9ef34754080','送黄彥武西上','朱松','宋','宋诗','song-poetry','','[]','門掩蓬蒿氣浩然，西風筆勢更翩翩。',64,'全唐诗/poet.song.107000.json','["門掩蓬蒿氣浩然，西風筆勢更翩翩。", "未忘大學虀鹽味，時說定林文字禪。", "蘆葉風光傾上國，槐花心緒記當年。", "里門歸日車應下，置酒遲君沈水邊。"]'),
('ec603131-9804-4185-94fa-fe23efd5d9e9','林丈挽詩','朱松','宋','宋诗','song-poetry','','[]','沈谿耆舊半丘墟，猶有期頤隠市區。',64,'全唐诗/poet.song.107000.json','["沈谿耆舊半丘墟，猶有期頤隠市區。", "未展武侯牀下拜，已傳顔子夢中呼。", "門人會築三年室，跡客誰留一束芻。", "歸卧九原應不恨，何蕃聲譽滿京都。"]'),
('28c1dccb-4d91-4432-a971-a455db2e858b','有懷黄元聲時聞在建上詩中所記建上舊遊也','朱松','宋','宋诗','song-poetry','','[]','積雨山城久卧痾，起看橫港漲晴波。',64,'全唐诗/poet.song.107000.json','["積雨山城久卧痾，起看橫港漲晴波。", "空餘九尺鬚眉好，奈此一樽風月何。", "懷抱故人長在念，經行佳境想重過。", "東谿回首醉眠處，爲問紅蕖何許多。"]'),
('e4060221-edf3-41a5-8516-9deffcbee2ee','書室述懷奉寄民表兄是日得民表書','朱松','宋','宋诗','song-poetry','','[]','丈室無塵棐几橫，吏休鳬鶩散無聲。',64,'全唐诗/poet.song.107000.json','["丈室無塵棐几橫，吏休鳬鶩散無聲。", "舞風竹影僛僛轉，縈夢鑪香嫋嫋清。", "已笑榮枯盧白戲，不須物我觸蠻爭。", "故人剪燭西窗約，知復何時話此生。"]'),
('da8ec985-5daa-40ba-a658-6f1a4d14e1ef','答人留別之什','朱松','宋','宋诗','song-poetry','','[]','家在大江東復東，去君一舍碧流通。',64,'全唐诗/poet.song.107000.json','["家在大江東復東，去君一舍碧流通。", "那知臨水登山處，同寄飛蓬斷梗中。", "愁絕盃中千里月，夢縈江上一帆風。", "只今且作須臾意，更典雲裘醉小藂。"]'),
('2eeedb00-d38c-40b4-9992-b065a73633f6','七月四日宿丹谿道中','朱松','宋','宋诗','song-poetry','','[]','日出露芒重，凉生風葉翻。',48,'全唐诗/poet.song.107000.json','["日出露芒重，凉生風葉翻。", "秋秔已照眼，社酒欲香村。", "牛下草萊濕，人歸園屋昏。", "箇中吾不淺，擾擾與誰論。"]'),
('65992ab7-754e-4213-ba28-220b3acdd1c5','求道人自尤溪來還冷齋有詩次其韻','朱松','宋','宋诗','song-poetry','','[]','五年沈水照衰顔，谿上今誰獨往還。',64,'全唐诗/poet.song.107000.json','["五年沈水照衰顔，谿上今誰獨往還。", "身插亂峯隨一錫，夢回蕭寺遶千間。", "西風潮落挐音急，斜日尊空醉袖班。", "更覺難追詩力健，大弨久廢若爲彎。"]'),
('81cb8916-14b5-4564-bbd7-45a1299ea1e9','送劉道醇歸烏石  其一','朱松','宋','宋诗','song-poetry','','[]','一廛避地本依劉，聞得更書始欲愁。',64,'全唐诗/poet.song.107000.json','["一廛避地本依劉，聞得更書始欲愁。", "舊德鎸碑在人口，歸裝載石壓溪舟。", "寄書莫忘青泥信，把酒誰同黄菊秋。", "新閣詩增風月價，自應神物護銀鈎。"]'),
('a9772641-8179-4099-aa54-e90c33fb6afd','送劉道醇歸烏石  其二','朱松','宋','宋诗','song-poetry','','[]','胸中一壑故超然，耿耿羞爭倚市妍。',64,'全唐诗/poet.song.107000.json','["胸中一壑故超然，耿耿羞爭倚市妍。", "萬事一尊陶令酒，群兒滿世祖生鞭。", "欲投烏石農桑社，尚有靈山香火緣。", "持節重來慰父老，蹊頭相送各携錢。"]'),
('9d8ae3f5-05d7-453e-9844-242e6b9d216c','題白鹿庵壁  其一','朱松','宋','宋诗','song-poetry','','[]','鹿門龐老携客隠，耳冷十年難與俱。',64,'全唐诗/poet.song.107000.json','["鹿門龐老携客隠，耳冷十年難與俱。", "螻蟻夢中求曩事，芭蕉林裏見今吾。", "遊絲弄影分陰轉，喬木摩空萬壑趨。", "香妙心清無一事，不知何處是華胥。"]'),
('b401842f-01a2-45a6-a9f6-5bd4a3fa338d','題白鹿庵壁  其二','朱松','宋','宋诗','song-poetry','','[]','滔滔一世强留連，頭上從渠歲月遷。',64,'全唐诗/poet.song.107000.json','["滔滔一世强留連，頭上從渠歲月遷。", "老子養生寧解事，小兒有口慣談天。", "醉來莫負持螯手，老矣終尋種玉田。", "若怪微吟漏消息，九江誰識市門仙。"]'),
('8db66ca9-40b8-49fa-810b-9b720ac91f30','與求道人同之福唐','朱松','宋','宋诗','song-poetry','','[]','縛屋雙峯雲一塢，拋來伴我事幽尋。',64,'全唐诗/poet.song.107000.json','["縛屋雙峯雲一塢，拋來伴我事幽尋。", "風花蹤跡趣雖各，香火因緣情自深。", "浮峽未興圓澤歎，乘桴還有仲由心。", "三山他日記耆舊，鑿齒彌天無古今。"]'),
('35b6f696-7df3-408b-8fff-7ff8a18f3415','次韻李堯端見嘲食蕨','朱松','宋','宋诗','song-poetry','','[]','真人官府未夤緣，且向龍山作散仙。',64,'全唐诗/poet.song.107000.json','["真人官府未夤緣，且向龍山作散仙。", "春入曉痕催采蕨，雨翻泥隴憶歸田。", "蔬腸我若枵蟬腹，詩格君如擊鶻拳。", "筯下萬錢謀更鄙，諸公飽死太官羶。"]'),
('7429949f-01f8-44c5-a9c8-0789519ee4f2','次韻堯端試茶','朱松','宋','宋诗','song-poetry','','[]','龍文新夸薦緗羅，園吏分嘗苦未多。',64,'全唐诗/poet.song.107000.json','["龍文新夸薦緗羅，園吏分嘗苦未多。", "自瀹雲腴𣂏露井，坐知雪粒采陽坡。", "撐腸君要澆黄卷，愛酒渠方捲白波。", "我亦箇中殊不淺，斷無蹤跡到無何。"]'),
('921b55c1-bfaf-4128-8611-008c7045313d','送友生','朱松','宋','宋诗','song-poetry','','[]','剝喙門前久未嗔，定知我輩不羈人。',64,'全唐诗/poet.song.107000.json','["剝喙門前久未嗔，定知我輩不羈人。", "午窗喚起夢魂好，一語便知風味真。", "身嬰世網坐營口，心識醉鄉慵問津。", "忽先秋燕背人去，四角何由生客輪。"]'),
('f65d94c4-a772-4665-937f-7a573d66ad45','贈范直夫','朱松','宋','宋诗','song-poetry','','[]','將軍競病詩成處，南浦春歸蘭玉叢。',64,'全唐诗/poet.song.107000.json','["將軍競病詩成處，南浦春歸蘭玉叢。", "漸減心情身老大，久乖談笑路西東。", "鄉關落日蒼茫外，樽酒寒花寂歷中。", "且與寓公同放曠，浩歌相屬倚秋風。"]'),
('ca559b79-768b-4284-b21f-cee89721e189','招友生','朱松','宋','宋诗','song-poetry','','[]','雨收天氣欲清明，猶有餘寒在粥餳。',64,'全唐诗/poet.song.107000.json','["雨收天氣欲清明，猶有餘寒在粥餳。", "馬隊客勤貪晝永，鱣堂人病想身輕。", "讀書有味虀鹽好，對境無情夢寐清。", "欲話此懷須我輩，一來蠟屐伴春行。"]'),
('b30b1449-0eff-4baf-a56f-c78de4cb3699','辛亥中秋不見月','朱松','宋','宋诗','song-poetry','','[]','今夕九秋半，心期負隔年。',48,'全唐诗/poet.song.107000.json','["今夕九秋半，心期負隔年。", "勞生灰劫裏，微雨客遊邊。", "旅泊正無酒，陰雲遑怨天。", "何時草堂月，相對藉糟眠。"]'),
('ff4b158d-055d-4ad7-ab1c-15d9133ddc8a','次韻羅源謝成章作不烹鳴雞詩','朱松','宋','宋诗','song-poetry','','[]','彼美司晨族，膠膠職效鳴。',72,'全唐诗/poet.song.107000.json','["彼美司晨族，膠膠職效鳴。", "爲憐君子操，寧乏小人羹。", "恩重棲時穩，心危失旦驚。", "未甘烏轉夜，聊學鴈全生。", "結客觀酣鬬，要君事割烹。", "那知競辰子，力學務時成。"]'),
('4f9a48c2-4a72-41c6-9d7a-380feec8545c','次徐謝韻還江公詩卷','朱松','宋','宋诗','song-poetry','','[]','大條祠官閑日月，絕知聖處著功深。',64,'全唐诗/poet.song.107000.json','["大條祠官閑日月，絕知聖處著功深。", "榮枯舉世爭盧白，枉直何人較尺尋。", "身比香山差得計，詩看正始有遺音。", "應容下客遊東閣，要話朱游夙昔心。"]'),
('d4619395-900f-4cef-ac52-b3f49858054b','次韻汪彥允見寄','朱松','宋','宋诗','song-poetry','','[]','北苑乖期恨昔年，異鄉牢落夢江天。',64,'全唐诗/poet.song.107000.json','["北苑乖期恨昔年，異鄉牢落夢江天。", "約遊汗漫傳新句，許出嬋娟有舊緣。", "種種鬢絲何計換，摇摇心旆不勝懸。", "歸耕要伴君難老，相與笞鸞作散仙。"]'),
('b80919c3-5c5d-416d-99e3-8955dfb92227','與吳昌國同遊靈水院二首  其一','朱松','宋','宋诗','song-poetry','','[]','算舟吏散了無事，與客意行初不謀。',64,'全唐诗/poet.song.107000.json','["算舟吏散了無事，與客意行初不謀。", "飽看雲濤舞空闊，欣逢泉石媚深幽。", "西漢未試補天手，上界那知鞭鳳遊。", "剪燭他年憶真賞，莫嗟身世尚沉浮。"]'),
('29b316e1-8963-4e4b-ae7b-634f6dd22afa','與吳昌國同遊靈水院二首  其二','朱松','宋','宋诗','song-poetry','','[]','來往風流記兩翁，天涯今作九秋蓬。',64,'全唐诗/poet.song.107000.json','["來往風流記兩翁，天涯今作九秋蓬。", "坐驚秀色懸眉宇，便覺仙峯入手中。", "傲世真成漆園吏，輸君不負北窗風。", "書生浪發新亭歎，自笑尊前氣吐虹。"]'),
('1bc740d5-0126-442e-8636-325cf69901dc','贈吳昌國二首  其一','朱松','宋','宋诗','song-poetry','','[]','居越與誰語，得君寬我愁。',48,'全唐诗/poet.song.107000.json','["居越與誰語，得君寬我愁。", "頗驚三日別，更爲一樽留。", "食藿有餘味，泣河非所謀。", "相看撫身世，容與愧蒼鷗。"]'),
('a72daab9-0a7d-428f-89a5-19b2b39101ec','贈吳昌國二首  其二','朱松','宋','宋诗','song-poetry','','[]','憶我少年日，遊君大父閒。',48,'全唐诗/poet.song.107000.json','["憶我少年日，遊君大父閒。", "諸孫嗟契闊，雙鬢各斕斑。", "未覺歸愚晚，俱嘗適俗艱。", "絕知歸思急，更覓玉梅攀。"]'),
('d03e9997-a2ae-4508-bb5a-9ff093aa11e4','孔生示二詩答一篇','朱松','宋','宋诗','song-poetry','','[]','歲晚尊前一笑譁，憐君孤憤老天涯。',64,'全唐诗/poet.song.107000.json','["歲晚尊前一笑譁，憐君孤憤老天涯。", "諸豪雖識臨邛客，陋族難當闕里家。", "會有孟光求共隠，不應牧犢但長嗟。", "青衫華髮春風裏，擇婿猶堪駐寶車。"]'),
('7c74a849-10dc-46ab-9cf6-dfc31580d0bb','寄江少明','朱松','宋','宋诗','song-poetry','','[]','龍卷風雲一髮蟠，不妨聊作侍祠官。',64,'全唐诗/poet.song.107000.json','["龍卷風雲一髮蟠，不妨聊作侍祠官。", "高情未許群兒覺，萬事何須正眼看。", "問道從公春信近，談天容我酒盃寬。", "乘桴亦有平生意，回首紛紛行路難。"]'),
('c81dde7b-c9fc-4cb7-b384-2314a363aaa2','次韻劉仲高懷外舅家梅花','朱松','宋','宋诗','song-poetry','','["\u897f\u6e56"]','柯山月下嬋娟影，前度劉郎餘故情。',64,'全唐诗/poet.song.107000.json','["柯山月下嬋娟影，前度劉郎餘故情。", "詩成回首戀三宿，我亦惜花癡半生。", "鴈沉寒水菩提長，蟲蝕真詮章句清。", "西湖懸絕得鸞喙，可但能專五字城。"]'),
('1ee77679-7786-45ad-8a63-30d62492a8c5','送景思奉祠之溫州','朱松','宋','宋诗','song-poetry','','[]','司祀名郎下紫宸，王師載主尚時巡。',64,'全唐诗/poet.song.107000.json','["司祀名郎下紫宸，王師載主尚時巡。", "丕承配極威靈在，對越垂休命秩新。", "幽夢想多春草句，清江爲洗湼衣塵。", "行觀前席來宣室，可但從容問鬼神。"]'),
('a68d1c81-8fd9-41c7-9297-1165dd340a60','次韻鄭德與歸舟中感懷','朱松','宋','宋诗','song-poetry','','[]','兩牛鳴地隔寒流，病起相望客鬢秋。',64,'全唐诗/poet.song.107000.json','["兩牛鳴地隔寒流，病起相望客鬢秋。", "聞道喚船歸別浦，坐懷聯策倚滄洲。", "騷人空復驚摇落，胡賈何須歎滯留。", "會擁蒙衝入河渭，看君黄色上眉頭。"]'),
('0babda89-ccdc-4075-b0c2-d0cb3ecbbd07','李似表取告歸晉陵','朱松','宋','宋诗','song-poetry','','[]','酌酒摻歸袂，繁陰殊未收。',48,'全唐诗/poet.song.107000.json','["酌酒摻歸袂，繁陰殊未收。", "心知非遠別，自不柰離愁。", "蓬渚倦懷槧，雲臺歸借籌。", "遄來閶闔路，萬馬避前騶。"]'),
('8d4e5dd9-9742-4d61-a5ee-7f0de5a7437f','致政宣教魏公挽詩二首  其一','朱松','宋','宋诗','song-poetry','','[]','己自應無憾，人猶歎不遭。',48,'全唐诗/poet.song.107000.json','["己自應無憾，人猶歎不遭。", "簪纓門已大，湖海氣方豪。", "舊國牛磯外，新阡馬鬣高。", "流芳傳教子，步武接夔臯。"]'),
('caeb94a6-a0bc-4343-8128-8f6772a3c383','致政宣教魏公挽詩二首  其二','朱松','宋','宋诗','song-poetry','','[]','交蓋歲云晚，向人懷自傾。',48,'全唐诗/poet.song.107000.json','["交蓋歲云晚，向人懷自傾。", "爭棋消永晝，酌茗話平生。", "轉手便陳迹，撫書增故情。", "無由從執紼，空想葬簫聲。"]'),
('a1f4caf9-7230-427a-95e3-64541c8e4956','劉氏挽詩','朱松','宋','宋诗','song-poetry','','[]','餘慶鍾蘭秀，初占合鳳飛。',48,'全唐诗/poet.song.107000.json','["餘慶鍾蘭秀，初占合鳳飛。", "那知風不止，遽作露先晞。", "鬻髢筵方徹，齊眉事已非。", "魂車春陌上，空背夕陽歸。"]'),
('c1adce1d-b925-4711-a7ae-60af8d1301ca','次釗彥仲傅茂先韻','朱松','宋','宋诗','song-poetry','','[]','强蹋府塵從傅子，立談江閣識釗郎。',64,'全唐诗/poet.song.107000.json','["强蹋府塵從傅子，立談江閣識釗郎。", "一尊此地見眉宇，十載相思成鬢霜。", "秋燈煜煜照情話，夜浪翻翻吹客床。", "投名徑入農圃社，老矣不夢天門翔。"]'),
('a84af29d-91f5-452b-a385-5987f6b5580d','建安道中','朱松','宋','宋诗','song-poetry','','[]','犖确復犖确，秋山殊未晴。',48,'全唐诗/poet.song.107000.json','["犖确復犖确，秋山殊未晴。", "流年半羈旅，此地幾經行。", "雪嶺今慵照，茅簷欲謾營。", "大鈞渾莫問，流坎任餘生。"]'),
('3658fd77-7ad6-4b31-834c-a2e7ee55942b','送藺廷彥之衡州','朱松','宋','宋诗','song-poetry','','[]','牆東新徑去年開，二老扶筇便往來。',64,'全唐诗/poet.song.107000.json','["牆東新徑去年開，二老扶筇便往來。", "數面何曾三日別，離懷都寄十分杯。", "客亭繫馬梅爭落，官舍裁書鴈欲回。", "秉執樞機有知己，未須卜築向蒿萊。"]'),
('1c66117e-e16a-4f9f-a16e-5e780b5d1903','商羊','朱松','宋','宋诗','song-poetry','','[]','異鳥來齊國，仍依殿陛翔。',72,'全唐诗/poet.song.107000.json','["異鳥來齊國，仍依殿陛翔。", "從容詢魯相，物色是商羊。", "欲雨追童語，懷山驗水祥。", "民寧因備豫，政美謝祈禳。", "止異爰居久，鳴無垤鸛長。", "願言蘇旱虐，主上似宣王。"]'),
('fd4bf896-3a82-4bcc-b567-2ab1f330b8aa','次張演翁林元惠韻','朱松','宋','宋诗','song-poetry','','[]','朱門小駐使君車，二老風流入畫圖。',64,'全唐诗/poet.song.107000.json','["朱門小駐使君車，二老風流入畫圖。", "但有觥籌供笑語，從教歲月上髯鬚。", "詩成華燭留殘蠟，客醉高歌叩缺壺。", "更起爭棋誇得雋，不應局蹙守邊隅。"]'),
('7ab9be18-bcc1-4460-9473-a91d4db3d6a4','公相起犂鋤','朱松','宋','宋诗','song-poetry','','[]','帝室尊公相，潭潭大府居。',72,'全唐诗/poet.song.107000.json','["帝室尊公相，潭潭大府居。", "從容調鼎鉉，奮發自犂鋤。", "弼亮恢賢業，班聯冠廣除。", "艱難同耦日，慷慨輟耕初。", "厚幣來莘野，幽人出冀墟。", "渴賢才仄席，何計老田廬。"]'),
('219801de-4caf-42f2-9ce1-2fea554110b6','太康道中二首  其一','朱松','宋','宋诗','song-poetry','','[]','得春榆柳遍平郊，猶見藏鴉影未交。',32,'全唐诗/poet.song.107000.json','["得春榆柳遍平郊，猶見藏鴉影未交。", "動地風來一披拂，青黄淺淺抹林稍。"]'),
('c1a5a2c8-162e-4467-9c47-1783588b632b','太康道中二首  其二','朱松','宋','宋诗','song-poetry','','[]','一色春勻萬樹紅，坐愁吹作雪漫空。',32,'全唐诗/poet.song.107000.json','["一色春勻萬樹紅，坐愁吹作雪漫空。", "誰知榆莢楊花意，只擬春殘卷地風。"]'),
('208a1646-4b38-4e05-b8a1-26d66979d9da','燈夕時在泗上五首  其一','朱松','宋','宋诗','song-poetry','','[]','燈花作意照歸人，短棹扁舟寂寞濱。',32,'全唐诗/poet.song.107000.json','["燈花作意照歸人，短棹扁舟寂寞濱。", "帝力如春蘇萬物，遥知太一不威神。"]'),
('dc5e2ec5-99b2-4874-850c-e4117016d728','燈夕時在泗上五首  其二','朱松','宋','宋诗','song-poetry','','[]','雲窗月檻仰乘輿，俯看香車出繡襦。',32,'全唐诗/poet.song.107000.json','["雲窗月檻仰乘輿，俯看香車出繡襦。", "九陌人人歌帝力，不須微服過康衢。"]'),
('603dd7e0-8b59-4712-bb60-5accb6cbda42','燈夕時在泗上五首  其三','朱松','宋','宋诗','song-poetry','','[]','鸞駕翩翩馭晚風，積蘇宮闕夜濛濛。',32,'全唐诗/poet.song.107000.json','["鸞駕翩翩馭晚風，積蘇宮闕夜濛濛。", "明朝遣覓鐵如意，應在凉州酒肆中。"]'),
('1544e5ad-10ac-432f-b10f-0c23c10c64c0','燈夕時在泗上五首  其四','朱松','宋','宋诗','song-poetry','','[]','我欲安心未有方，至人遺跡已茫茫。',32,'全唐诗/poet.song.107000.json','["我欲安心未有方，至人遺跡已茫茫。", "自非窣堵波中老，誰直先生一瓣香。"]'),
('4804a03f-5365-4b33-90c0-1ab35683edcb','燈夕時在泗上五首  其五','朱松','宋','宋诗','song-poetry','','[]','我觀世界只兒嬉，一戲相從更莫辭。',32,'全唐诗/poet.song.107000.json','["我觀世界只兒嬉，一戲相從更莫辭。", "綺語未忘餘習在，明朝與和紫姑詩。"]'),
('a6382f12-4084-4120-852a-6b1d0cf45bee','松江三首  其一','朱松','宋','宋诗','song-poetry','','[]','塵緣挽我去漁磯，回首滄洲此願違。',32,'全唐诗/poet.song.107000.json','["塵緣挽我去漁磯，回首滄洲此願違。", "偶寄一舟江上去，只無箬笠與蓑衣。"]'),
('47f56488-71a7-46a9-9bed-5bd22e1f7966','松江三首  其二','朱松','宋','宋诗','song-poetry','','[]','表裏江湖眼界新，解誇奇觀屬詩人。',32,'全唐诗/poet.song.107000.json','["表裏江湖眼界新，解誇奇觀屬詩人。", "要須一釂三江水，凈洗多生舌本塵。"]'),
('4bc85203-2950-4e28-bc9a-58def9bfc548','松江三首  其三','朱松','宋','宋诗','song-poetry','','[]','晴江渺渺跨江干，春漲平湖萬頃寒。',32,'全唐诗/poet.song.107000.json','["晴江渺渺跨江干，春漲平湖萬頃寒。", "欲挽銀潢供硯滴，坐如震澤在毫端。"]'),
('838993b1-cf96-4676-9d04-4cfa2622474a','翠碧','朱松','宋','宋诗','song-poetry','','[]','長橋畫柱照清淪，俯見游鯈不可緡。',32,'全唐诗/poet.song.107000.json','["長橋畫柱照清淪，俯見游鯈不可緡。", "山影半溪叢篠密，誰知翠碧解藏身。"]'),
('731bd0ff-9f9f-4b9e-a897-0ce4bc5c8e0c','賦王伯溫家酴醾','朱松','宋','宋诗','song-poetry','','[]','翩翩風馭駕花神，更遣酴醾殿晚春。',32,'全唐诗/poet.song.107000.json','["翩翩風馭駕花神，更遣酴醾殿晚春。", "壓架穠香千尺雪，喚回中酒惜花人。"]'),
('a6330919-0432-4fac-8d8c-97e4a3c997c9','王彥行送櫻桃','朱松','宋','宋诗','song-poetry','','[]','香英狼籍了無餘，償我殘春一斛珠。',32,'全唐诗/poet.song.107000.json','["香英狼籍了無餘，償我殘春一斛珠。", "猶带微酸餉佳客，爲嫌啼鳥啄紅膚。"]'),
('69cada4a-df57-4760-be38-7a3fb51d385c','芍藥二首  其一','朱松','宋','宋诗','song-poetry','','[]','紅顔素臉出春殘，裊裊傳傳態自完。',32,'全唐诗/poet.song.107000.json','["紅顔素臉出春殘，裊裊傳傳態自完。", "聞道揚州冠天下，何年跨鶴往吟看。"]'),
('9a71acf1-84e0-45fe-841d-898603c4eff8','芍藥二首  其二','朱松','宋','宋诗','song-poetry','','[]','舞困春風睡思深，東君更與纏腰金。',32,'全唐诗/poet.song.107000.json','["舞困春風睡思深，東君更與纏腰金。", "頹簷醉尉花應笑，那有當年幕客心。"]'),
('34271bf4-5bde-44e4-87a0-482d7abe6441','月巖去上饒十里山有側穴腹背皆洞如月','朱松','宋','宋诗','song-poetry','','[]','鑿透巉巖不記春，山腰千古掛冰輪。',32,'全唐诗/poet.song.107000.json','["鑿透巉巖不記春，山腰千古掛冰輪。", "誰知擘破三峯手，聊出嬋娟戲路人。"]'),
('11b7d7c6-7133-4e3c-9626-bebb918d38a9','蟬','朱松','宋','宋诗','song-poetry','','[]','陰陰葉底午蟬嘶，滿腹春風寄一枝。',32,'全唐诗/poet.song.107000.json','["陰陰葉底午蟬嘶，滿腹春風寄一枝。", "下有行人正愁絕，不知幽咽自緣饑。"]'),
('4e0d40f2-3450-4082-8f6e-97be4bd01237','寄湛師','朱松','宋','宋诗','song-poetry','','[]','一月分身入萬池，道人何處不相隨。',32,'全唐诗/poet.song.107000.json','["一月分身入萬池，道人何處不相隨。", "卧聽絕壑傳風籟，歷歷新詩世不知。"]'),
