('ae467728-7509-4569-9eb4-b11bee64c508','題趙守中江行初雪圖','朱松','宋','宋诗','song-poetry','','[]','江闊雲垂滿袖風，急須下馬一尊同。',32,'全唐诗/poet.song.107000.json','["江闊雲垂滿袖風，急須下馬一尊同。", "正應無奈催詩雪，句在渠儂擁鼻中。"]'),
('6d87d1a1-05c6-4c27-a9c1-30f4bca5d412','楚江觀梅','朱松','宋','宋诗','song-poetry','','[]','莫笑山翁老據鞍，探梅今夕到江干。',64,'全唐诗/poet.song.107000.json','["莫笑山翁老據鞍，探梅今夕到江干。", "半灘流水浸殘月，一夜清霜催曉寒。", "倚醉更教重秉燭，怕愁元自怯憑欄。", "誰知携客芳華日，曾費纏頭錦百端。"]'),
('07de77ad-a16f-45bd-83fa-e51d9f5adc4e','春晚書懷','朱松','宋','宋诗','song-poetry','','[]','萬里西遊爲覓詩，錦城更付一官癡。',64,'全唐诗/poet.song.107000.json','["萬里西遊爲覓詩，錦城更付一官癡。", "脫巾漉酒從人笑，拄笏看山頗自奇。", "疏雨池塘魚避釣，曉鶑窗戶客爭棋。", "老來怕與春爲別，醉過殘紅滿地時。"]'),
('e7b1f9f8-6066-4920-8df4-94cac5e5c0a5','送五二郎讀書','朱松','宋','宋诗','song-poetry','','[]','爾去事齋居，操持好在初。',96,'全唐诗/poet.song.107000.json','["爾去事齋居，操持好在初。", "故鄉無厚業，舊篋有殘書。", "夜寑燈遲滅，晨興髮蚤梳。", "詩囊應令滿，酒盞固宜疏。", "貘羈寧似犬，龍化本由魚。", "鼎薦緣中實，鐘鳴應體虛。", "洞洞春天發，悠悠白日除。", "成家全頼汝，逝此莫躊躇。"]'),
('1aa3a466-1582-455e-a2be-675a078ea5ec','負暄','朱松','宋','宋诗','song-poetry','','[]','宵寒卧增裯，晝寒起增衣。',120,'全唐诗/poet.song.107000.json','["宵寒卧增裯，晝寒起增衣。", "如何負暄樂，高堂日輝輝。", "引光扉盡闢，追影榻屢移。", "妙趣久乃酣，瞑目潜自知。", "初如擁紅爐，凍粟消頑肌。", "漸如飲醇醪，暖力中融怡。", "欠伸百骸舒，爬搔隨意爲。", "頗回驕佚氣，頓改寒酸姿。", "熏然沐慈仁，天恩豈予私。", "願披橫空雲，四海同熙熙。"]'),
('3acbae46-3301-4b0b-a3a3-797b7cca5ca6','飲租戶','朱松','宋','宋诗','song-poetry','','[]','我病不任耕，歲收仰微租。',48,'全唐诗/poet.song.107000.json','["我病不任耕，歲收仰微租。", "蒙成每自愧，一飽便有餘。", "連觴使之釂，醉語雜叫呼。", "野人無他腸，吾輩恐不如。"]'),
('a5fbfdca-5491-43cb-9775-5e26dc0f1b51','種菜','朱松','宋','宋诗','song-poetry','','[]','傍舍植桑蔬，携鋤理荒穢。',48,'全唐诗/poet.song.107000.json','["傍舍植桑蔬，携鋤理荒穢。", "桔槔勤俯仰，一雨功百倍。", "朝來綠映土，新葉摇肺肺。", "牛羊勿踐履，食肉屠爾輩。"]'),
('20045e11-eceb-4ba8-831d-900ebfbb8420','次韻梅花','朱槔','宋','宋诗','song-poetry','','[]','陰陰雪意雲垂地，曳策微行傍清泚。',160,'全唐诗/poet.song.107000.json','["陰陰雪意雲垂地，曳策微行傍清泚。", "眼明橫路出江梅，烟瞑沙寒迷表裏。", "當年一夢山月明，依約瑶臺見仙子。", "俗緣掣肘意未了，弄出飛瓊亂紛委。", "摩娑銅狄豈須話，滄海揚塵固其理。", "花神縱步來閬苑，羞怕唐昌偷玉蕊。", "回風自作粧半面，泣露真成愁齲齒。", "相看一笑豈易得，分與天香更清美。", "那知脫屣塵寰去，頃刻蓬萊三萬里。", "黄昏誰伴醉鄉歸，天色無情淡如洗。"]'),
('3a2cf353-85e4-4b01-803c-c3014ad0ee66','次韻寄求道人','朱槔','宋','宋诗','song-poetry','','[]','天工憒憒春無力，桃李顰心少顔色。',96,'全唐诗/poet.song.107000.json','["天工憒憒春無力，桃李顰心少顔色。", "夢中矯首望三山，我是東南未歸客。", "岩壑交游人姓支，相思江月半成規。", "遥知草木代說法，豈是畫餠隨兒嬉。", "此身分不過朝市，何日相從拂衣袂。", "豈容陶令載白蓮，會作鄭虔書落柿。"]'),
('889306f1-728b-4f45-91da-8c152c8f35b2','二詩寄德粲并簡內觀諸友  其一','朱槔','宋','宋诗','song-poetry','','[]','春風本自掣肘去，那更病留過一旬。',64,'全唐诗/poet.song.107000.json','["春風本自掣肘去，那更病留過一旬。", "滿眼山川雖不改，連天桃李已成塵。", "銀河誰與洗兵馬，寶唾安能泣鬼神。", "悵望故人分雪此，飛雲落日在綸巾。"]'),
('e307fadf-0bb8-4161-988e-f7ba34a9f548','二詩寄德粲并簡內觀諸友  其二','朱槔','宋','宋诗','song-poetry','','[]','九淵亭上二三子，見說年來事事新。',64,'全唐诗/poet.song.107000.json','["九淵亭上二三子，見說年來事事新。", "隔水不容招手喚，曲窗已有畫眉人。", "酴醾香好急携酒，鶗鴂聲繁催送春。", "笑我江南未歸客，飄然天地一閑身。"]'),
('387e30a1-b9f6-4343-a5f1-86f789664787','寄人','朱槔','宋','宋诗','song-poetry','','[]','一牛鳴地兩禪林，霧雨初晴翠靄深。',64,'全唐诗/poet.song.107000.json','["一牛鳴地兩禪林，霧雨初晴翠靄深。", "熟路緣溪穿窈窕，疏鐘喚客出嶇嶔。", "未求黄卷成功處，且辦青山避世心。", "悵望不來還獨返，秋風聊作暮雲吟。"]'),
('6f0ee89c-1634-4ebb-aca8-c5d71a1be643','十月上休日示求道人','朱槔','宋','宋诗','song-poetry','','[]','老禪獨卧千岩表，枯木寒雲伴此身。',64,'全唐诗/poet.song.107000.json','["老禪獨卧千岩表，枯木寒雲伴此身。", "只倚藜根作詩本，肯分秋色與騷人。", "心源落落故難合，筆勢翩翩想絕倫。", "記取濠梁斷金語，三山好處要傳真。"]'),
('c8a22892-0b3e-4016-9076-cdd7e8cf6eb7','同蹈元看竹了軒因用去年方字韻作此','朱槔','宋','宋诗','song-poetry','','[]','淇澳渭川那復夢，而今天遣出南方。',64,'全唐诗/poet.song.107000.json','["淇澳渭川那復夢，而今天遣出南方。", "要觀大節須霜雪，莫說此君無肺腸。", "照水形容殊不惡，臨風言語一何長。", "山僧豈識留連意，千里故人逢異鄉。"]'),
('6c95c026-7f5b-4d46-8c79-30225aae8a5f','和德粹三絕  其一','朱槔','宋','宋诗','song-poetry','','[]','平生樂事在三餘，不管梧陰過玉除。',32,'全唐诗/poet.song.107000.json','["平生樂事在三餘，不管梧陰過玉除。", "絕尾忽參嫠緯句，風塵今日正愁予。"]'),
('fec0226a-fa2f-4b38-bd7c-a4e2c2c355d6','和德粹三絕  其二','朱槔','宋','宋诗','song-poetry','','[]','心賞南樓一味凉，波光山影上藜牀。',32,'全唐诗/poet.song.107000.json','["心賞南樓一味凉，波光山影上藜牀。", "莫言體國非吾事，好夢不能千里長。"]'),
('aac67a46-35ff-4f04-aa4a-0f9014d8afb1','和德粹三絕  其三','朱槔','宋','宋诗','song-poetry','','[]','未坐他年百尺樓，浮雲身上且悠悠。',32,'全唐诗/poet.song.107000.json','["未坐他年百尺樓，浮雲身上且悠悠。", "眼高四海騎鯨客，不見長安亦解愁。"]'),
('99482b9b-e28a-4dee-8b1e-3d4dfc37f0ce','三山次潘靜之升書記韻','朱槔','宋','宋诗','song-poetry','','[]','客路那知歲月長，掀眉一笑苾蒭房。',64,'全唐诗/poet.song.107000.json','["客路那知歲月長，掀眉一笑苾蒭房。", "且傾徐邈聖賢酒，不問陳登上下牀。", "雲影翻空迷海嶠，秋聲隨夢到江鄉。", "明朝各聽船窗雨，猶憶枯棋戰四郎。"]'),
('f3cc56b0-d517-41e7-bbe0-e3ecf44d4720','邈書寄出與李知哲唱和詩次韻','朱槔','宋','宋诗','song-poetry','','[]','邂逅招提頓客輈，十年塵土且休休。',64,'全唐诗/poet.song.107000.json','["邂逅招提頓客輈，十年塵土且休休。", "三人月下從渠便，二老風流到我不。", "南北只今無好語，山川如許更悲秋。", "故應賸作鏘金句，莫羨群兒萬戶侯。"]'),
('1fa269b0-ed9e-4222-96ca-0308b8a57dbf','老兵種菊以詩謝之','朱槔','宋','宋诗','song-poetry','','[]','蔬畦雨徑策勳時，徙種鄰牆菊兩枝。',64,'全唐诗/poet.song.107000.json','["蔬畦雨徑策勳時，徙種鄰牆菊兩枝。", "九日無人過朱放，十分舉酒酌王尼。", "花裁栗玉秋風健，香近龍涎曉夢知。", "負口不應還負眼，長鑱煩爾鎮相隨。"]'),
('bd992a55-2b07-44c9-bbe9-899e587cbacf','鄭德予同遊桃花山次韻  其一','朱槔','宋','宋诗','song-poetry','','[]','江村卜築路斜斜，模寫癯仙四壁家。',64,'全唐诗/poet.song.107000.json','["江村卜築路斜斜，模寫癯仙四壁家。", "聞道讀書忘肉味，不緣避世宿桃花。", "青山自作千年調，白眼空驚一望賒。", "欲買雞豚投近社，烟蓑雨笠寄生涯。"]'),
('ca663d14-d15e-4153-9d3c-491b3d39a431','鄭德予同遊桃花山次韻  其二','朱槔','宋','宋诗','song-poetry','','[]','春紅萬樹抱山斜，落落真源自一家。',64,'全唐诗/poet.song.107000.json','["春紅萬樹抱山斜，落落真源自一家。", "雲起坐中疑有雨，酒行杯面恐飛花。", "塵緣未斷心雖勝，他日重來約尚賒。", "畧倩淵明記遺事，武陵今不在天涯。"]'),
('c2a2307e-0d48-43ca-aeef-80b998cbbd0c','九日與客語慨然有廬山之興','朱槔','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','九日黄花笑白頭，分將牢落付林丘。',64,'全唐诗/poet.song.107000.json','["九日黄花笑白頭，分將牢落付林丘。", "半川暝色聊償夢，別嶺秋聲旋寄愁。", "江國經年成浪語，匡廬入手是真休。", "未能免俗須登陟，睨視元龍百尺樓。"]'),
('cf2b9cb2-a651-4053-87f7-19d836e9ed57','草堂諸陳同遊崧山精舍冕仲携琴先歸用壁間韻  其一','朱槔','宋','宋诗','song-poetry','','[]','來伴秋風十日閑，筆端久已識波瀾。',32,'全唐诗/poet.song.107000.json','["來伴秋風十日閑，筆端久已識波瀾。", "煩君一醉雙峰月，乞與兒曹白眼看。"]'),
('6b64708b-d3a9-4580-a10a-d04080e653f5','草堂諸陳同遊崧山精舍冕仲携琴先歸用壁間韻  其二','朱槔','宋','宋诗','song-poetry','','[]','破塵妙語慰畸人，鶴髮深衣雨墊巾。',32,'全唐诗/poet.song.107000.json','["破塵妙語慰畸人，鶴髮深衣雨墊巾。", "獨自抱琴山下去，石橋月色爲誰新。"]'),
('59b2664e-140e-4fb5-b8c1-03e1d6e4c534','三山次鄭德予韻  其一','朱槔','宋','宋诗','song-poetry','','[]','日脚微明雨脚疏，誰將雲夢賦相如。',32,'全唐诗/poet.song.107000.json','["日脚微明雨脚疏，誰將雲夢賦相如。", "西南山好君知不，一見全勝讀異書。"]'),
('3bac0adc-bec9-47ad-b825-23ebf8dec8b8','三山次鄭德予韻  其二','朱槔','宋','宋诗','song-poetry','','[]','何日歸舟片葉輕，白鷗相伴艣微鳴。',32,'全唐诗/poet.song.107000.json','["何日歸舟片葉輕，白鷗相伴艣微鳴。", "只應潮打蓬窗處，已作離騷一半清。"]'),
('691a686c-cc71-4831-bd24-5b6784cf51b9','次韻梅花兩絕句  其一','朱槔','宋','宋诗','song-poetry','','[]','一月尤溪烟雨濃，玉梅渾作玉人逢。',32,'全唐诗/poet.song.107000.json','["一月尤溪烟雨濃，玉梅渾作玉人逢。", "江南他日摘香處，莫忘雲間雙髻峯。"]'),
('b1593808-4b44-441f-827a-4f49801dcf66','次韻梅花兩絕句  其二','朱槔','宋','宋诗','song-poetry','','[]','清淺彎環遶故牆，一身將影理殘妝。',32,'全唐诗/poet.song.107000.json','["清淺彎環遶故牆，一身將影理殘妝。", "西施俗處無人見，冷落吳宮溪水香。"]'),
('80b8afa0-7994-4328-9771-e49fabc8480e','徐彥猷以仇池詩句爲韻作詩十四章見示答之','朱槔','宋','宋诗','song-poetry','','[]','徐侯筆下波濤寬，新詩示我清且閑。',192,'全唐诗/poet.song.107000.json','["徐侯筆下波濤寬，新詩示我清且閑。", "誰能辛苦學飯顆，格轍已到元和間。", "春寒十日不出戶，坐想江柳分烟鬟。", "東坡老仙有奇句，析韻琢句光斕斑。", "疾雷一洗牛蟻閙，羯鼓畧驚桃李頑。", "周郎知音亦已久，仲車著語誰當刪。", "大弨六鈞古稱重，汝自力弱無由彎。", "胡爲坎坎事嗤點，今古可笑兒童孱。", "鄉關春物入意匠，水光花氣相回環。", "莫嫌衆口亂如沸，當見三耳生其顔。", "嗟吾和詩雖已晚，識君妙意存高山。", "告君詩妙須飲酒，社甕一醉寧當慳。"]'),
('74f97c84-6a66-434e-a20f-9267e3a6692e','寓居南軒','朱槔','宋','宋诗','song-poetry','','[]','雲氣披猖月意孤，冬青倒影上庭隅。',64,'全唐诗/poet.song.107000.json','["雲氣披猖月意孤，冬青倒影上庭隅。", "燈橫老薺蛾方去，書掩新芸蠹已無。", "一世盡知關魯酒，十年不擬歎齊竽。", "支頤坐覺疏星沒，獨扣龍頭瀉酪奴。"]'),
('60976044-9f3c-4a00-b760-890fb0b70e3f','答戲昭文梅花','朱槔','宋','宋诗','song-poetry','','[]','臘到方留此日寒，雨多未覺過雲殘。',64,'全唐诗/poet.song.107000.json','["臘到方留此日寒，雨多未覺過雲殘。", "共驚臺柳怱怱去，獨抱園花細細看。", "洗面不勞千點雪，薰衣剩破一分檀。", "詩人窮苦誰料理，只倚東風酒量寬。"]'),
('ba438e7c-5a38-44c7-a6e6-4147b1ecea1f','乙丑臘月','朱槔','宋','宋诗','song-poetry','','[]','自數今年臘，天饒半月春。',48,'全唐诗/poet.song.107000.json','["自數今年臘，天饒半月春。", "酒船欺白首，桃靨笑青唇。", "避地疏同隊，逢人試問津。", "傷心穿豺虎，未肯盡奔秦。"]'),
('9f40b73f-5148-42db-866a-7cb898428611','延平道中  其一','朱槔','宋','宋诗','song-poetry','','[]','一溪春漲午晴初，日透波光綠浸裾。',32,'全唐诗/poet.song.107000.json','["一溪春漲午晴初，日透波光綠浸裾。", "却憶孤山山下路，石橋清澈看叉魚。"]'),
('6087b8c0-c7d2-49f5-b4b4-c64c2374c278','延平道中  其二','朱槔','宋','宋诗','song-poetry','','[]','雲間三十六峯高，北望思歸夢亦勞。',32,'全唐诗/poet.song.107000.json','["雲間三十六峯高，北望思歸夢亦勞。", "來客雙峯莫相笑，少低吾眼爲兒曹。"]'),
('4a29866e-713f-46e6-9b75-2cfd6d620b45','舟次黿湖阻水因由董山  其一','朱槔','宋','宋诗','song-poetry','','[]','山雨疏疏心又驚，起瞻天色斗微明。',32,'全唐诗/poet.song.107000.json','["山雨疏疏心又驚，起瞻天色斗微明。", "他年一枕江關夢，知憶蓬窗此夜聲。"]'),
('78e940af-00fc-4afc-b7c9-b15a1f529bc5','舟次黿湖阻水因由董山  其二','朱槔','宋','宋诗','song-poetry','','[]','一川黄濁寫崑崘，苦恨南溪不盡吞。',32,'全唐诗/poet.song.107000.json','["一川黄濁寫崑崘，苦恨南溪不盡吞。", "三老亦知行意速，時時插竹記沙痕。"]'),
('fd6bfd19-8f4f-4cf9-a1c8-b2818d7e591a','舟次黿湖阻水因由董山  其三','朱槔','宋','宋诗','song-poetry','','[]','拂拂朝霞到客舟，苦疑雨意在鳴鳩。',32,'全唐诗/poet.song.107000.json','["拂拂朝霞到客舟，苦疑雨意在鳴鳩。", "好峯天半元相識，且作僧牀挾策遊。"]'),
('5cbd6a55-0a0d-45db-a5d8-16d27bba91c6','舟次黿湖阻水因由董山  其四','朱槔','宋','宋诗','song-poetry','','[]','夢好山晴曉不知，船邊今日見鬚眉。',32,'全唐诗/poet.song.107000.json','["夢好山晴曉不知，船邊今日見鬚眉。", "向來快寫崑崘地，元有薰風綠盡時。"]'),
('f45e6345-1709-4124-8e6f-f62fa671cb9d','向年舟自三山上延平和人韻兩絕  其一','朱槔','宋','宋诗','song-poetry','','[]','春江一月困揚舲，醉夢無人與喚醒。',32,'全唐诗/poet.song.107000.json','["春江一月困揚舲，醉夢無人與喚醒。", "欲識故交金石處，相逢詩裏眼猶青。"]'),
('7ef7ee25-e68d-4302-ab5f-762a26399c21','向年舟自三山上延平和人韻兩絕  其二','朱槔','宋','宋诗','song-poetry','','[]','春風一夢收桃李，雙燕不知愁絕時。',32,'全唐诗/poet.song.107000.json','["春風一夢收桃李，雙燕不知愁絕時。", "卧向蓬窗飽聽雨，無人識此是新詩。"]'),
('44da8aca-a611-47f6-9d7f-3c1e95fdfac9','元英折惠柚花','朱槔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白玉繁花五葉芳，春風吹盡洞庭霜。',32,'全唐诗/poet.song.107000.json','["白玉繁花五葉芳，春風吹盡洞庭霜。", "河西道眼分明處，識破此中知見香。"]'),
('eab614b5-de9d-439c-89fa-bee2075f2f5a','乙丑除夜寓永興寄五二姪一首','朱槔','宋','宋诗','song-poetry','','[]','殘臘避新正，疾馳不可鞚。',192,'全唐诗/poet.song.107000.json','["殘臘避新正，疾馳不可鞚。", "梅花相行色，更以風雨送。", "傷哉綠林豪，支派出章貢。", "荐食今幾年，金帛既充棟。", "王旅走山澤，魄散失饑凍。", "空聞米粟廉，不救干戈痛。", "冥冥紙錢底，千室羅盎甕。", "祀先不暇嘗，一夜驚入夢。", "書生口擊賊，自愧脫嘲弄。", "經營華陽馬，想像丹穴鳳。", "融融聲教中，焉得餘此衆。", "由基執弧矢，鼷鼠何足中。", "浮烟起南舍，春事行倥傯。", "桃寒强破蕊，鳥靜獨成哢。", "詩情寫物色，心匠與折衷。", "章草簡阿戎，溪頭試微諷。"]'),
('23601d74-a8bc-4ea2-93b2-f49955b44fee','僕自以四月十四日自延平歸所寓之南軒積雨陰濕體中不佳二十五日夜夢至一處流水被道色清絕若有欄檻而無屋宇有筆硯皆浸水中予驚問何地旁有應者曰此玉瀾堂也夢中欲取水中筆硯作詩詩未成而覺意緒蕭爽殆不類人世雞已一再鳴矣因賦此','朱槔','宋','宋诗','song-poetry','','[]','蘧蘧飛夢過雲鄉，物色清輝眼界長。',64,'全唐诗/poet.song.107000.json','["蘧蘧飛夢過雲鄉，物色清輝眼界長。", "閶闔未招金馬士，蓬萊先立玉瀾堂。", "千尋濯足衣裘冷，六字哦詩筆硯香。", "當與瑶池作同社，紅巾青鳥兩相忘。"]'),
('feb625d8-2c69-480b-a32a-ee651186a68e','贈周功崇','朱槔','宋','宋诗','song-poetry','','[]','閩嶺浮沈二十年，歸心日夜夢江天。',64,'全唐诗/poet.song.107000.json','["閩嶺浮沈二十年，歸心日夜夢江天。", "謾題甲乙煩君看，若說功名只自憐。", "造物小兒知薄相，箇中老子已忘筌。", "一筇聞作東南去，豈欲求人左海邊。"]'),
('f46b4e8c-cfb9-4a8d-bbae-c983b4137442','悼鄭彥繼書墓亭','朱槔','宋','宋诗','song-poetry','','[]','蒼梧翠柏泣西風，尺冢巍然宿草中。',64,'全唐诗/poet.song.107000.json','["蒼梧翠柏泣西風，尺冢巍然宿草中。", "寶劍何心求季子，隻雞今日過橋公。", "麟經有味人誰識，鶴陣論功氣自雄。", "欲拂蒼厓寫奇節，陳琳檄手語言工。"]'),
('7b3145eb-420d-4a62-bf7c-4859a963a26d','竹醉日懷故山','朱槔','宋','宋诗','song-poetry','','[]','一室真容膝，何人客子猷。',48,'全唐诗/poet.song.107000.json','["一室真容膝，何人客子猷。", "土浮迎竹醉，雲凈對山羞。", "無地青歸幌，他年翠繞樓。", "且從鄰寺去，烟雨看沙鷗。"]'),
('5d35910a-2a92-4f7e-8fae-d74ec4b892cf','繁暑','朱槔','宋','宋诗','song-poetry','','[]','繁暑不可度，病餘少見招。',48,'全唐诗/poet.song.107000.json','["繁暑不可度，病餘少見招。", "投鄰借軒卧，信手得書饒。", "壽我藥雙笈，驚人詩一瓢。", "醒心憑雪鷺，只恐日薰銷。"]'),
('267ab3e8-1a0e-410c-b1b0-8eb7d1fc8be2','大食瓶','朱槔','宋','宋诗','song-poetry','','[]','窳質謝天巧，風輪出鬼謀。',48,'全唐诗/poet.song.107000.json','["窳質謝天巧，風輪出鬼謀。", "入窯奔閼伯，隨舶震陽侯。", "獨鳥藏身穩，雙虹繞腹流。", "可充王會賦，漆簡寫成周。"]'),
('c18759d9-0d38-4e99-ad3a-f5e69d85278d','春寒','朱槔','宋','宋诗','song-poetry','','[]','人道春寒早繫舟，楚山一夜雨瀏瀏。',32,'全唐诗/poet.song.107000.json','["人道春寒早繫舟，楚山一夜雨瀏瀏。", "此生削跡江邊路，嫩綠紛紅只自愁。"]'),
('73d00566-778e-41c3-b09b-f74dd4c83301','夏夜極凉','朱槔','宋','宋诗','song-poetry','','[]','素簡久辭夜，清風先戒秋。',48,'全唐诗/poet.song.107000.json','["素簡久辭夜，清風先戒秋。", "稻深群蛤吠，草暗一螢流。", "舌在殊無計，心空尚有求。", "按圖尋分野，楚尾見吾州。"]'),
('3724b141-bbcd-43e3-a71f-370055fc67db','六月二十日','朱槔','宋','宋诗','song-poetry','','[]','天涯明月見秋風，錯莫誰驚碧樹空。',64,'全唐诗/poet.song.107000.json','["天涯明月見秋風，錯莫誰驚碧樹空。", "豈意楚山招隠處，盡歸蜀客廣騷中。", "釣魚聊爾針方直，乞米茫然帖自工。", "獨卧南軒聽南澗，蠻花猶作杜鵑紅。"]'),
('fc26fa30-dd25-4144-a9ea-d63987aeab73','尤溪縣之南李花千樹無一雜木春時嘗飲其中酒家小軒可愛不知何故不曾作詩追賦二首明年修故事當書之壁間  其一','朱槔','宋','宋诗','song-poetry','','[]','橋外茅茨好，相過問酒錢。',48,'全唐诗/poet.song.107000.json','["橋外茅茨好，相過問酒錢。", "李花今若此，白髮自茫然。", "落日雲千步，春風雪一川。", "明朝記來處，石澗響濺濺。"]'),
('53c633b2-cebb-4285-9db4-60f4df5c443a','尤溪縣之南李花千樹無一雜木春時嘗飲其中酒家小軒可愛不知何故不曾作詩追賦二首明年修故事當書之壁間  其二','朱槔','宋','宋诗','song-poetry','','[]','見說小軒久，無人喚我來。',48,'全唐诗/poet.song.107000.json','["見說小軒久，無人喚我來。", "直如春力快，故遣客懷開。", "玉立花千樹，霞翻酒一盃。", "江陵二月尾，襟韻信難陪。"]'),
('28388eb6-6d78-44e5-add0-1563c25a006c','春間小詩書趙園壁追錄之  其一','朱槔','宋','宋诗','song-poetry','','[]','柳態隨時秀，花容近酒輕。',24,'全唐诗/poet.song.107000.json','["柳態隨時秀，花容近酒輕。", "綠窗京洛語，盡抹早鶑聲。"]'),
('b409a645-e761-4820-927b-01fe95d700cc','春間小詩書趙園壁追錄之  其二','朱槔','宋','宋诗','song-poetry','','[]','小語不知夕，幽香無盡時。',24,'全唐诗/poet.song.107000.json','["小語不知夕，幽香無盡時。", "影寒人欲醉，明月照酴醾。"]'),
('5aed7b71-af0b-4c94-9e88-1329ad3793e6','春間小詩書趙園壁追錄之  其三','朱槔','宋','宋诗','song-poetry','','[]','自得春風信，開懷待此花。',24,'全唐诗/poet.song.107000.json','["自得春風信，開懷待此花。", "餘寒固艱棘，今夕雪斜斜。"]'),
('1d52b73d-af53-4b4f-b00c-796d455a6053','春間小詩書趙園壁追錄之  其四','朱槔','宋','宋诗','song-poetry','','[]','夜月閩杯淺，春風楚製輕。',24,'全唐诗/poet.song.107000.json','["夜月閩杯淺，春風楚製輕。", "故鄉空費夢，來此聽谿聲。"]'),
('49d4d9e7-62ba-4b45-bfd8-92c5adb00a58','夜坐池上用簡齋韻','朱槔','宋','宋诗','song-poetry','','[]','落日解衣無一事，移牀臨水已三回。',64,'全唐诗/poet.song.107000.json','["落日解衣無一事，移牀臨水已三回。", "斗沉北嶺魚方樂，月過秋河鴈不來。", "疏翠庭前供答話，淺紅木末勸持盃。", "明明獨對蒼華影，莫上睢陽萬死臺。"]'),
('c952daa8-e699-4646-bd6d-e61cac5880ea','平津','朱槔','宋','宋诗','song-poetry','','[]','西風扶病上江樓，老眼凄迷一色秋。',64,'全唐诗/poet.song.107000.json','["西風扶病上江樓，老眼凄迷一色秋。", "帆影戛雲追斷鴈，角聲吹月舞潜虯。", "栽培白業初無路，點檢青山始欲愁。", "左海此中纔咫尺，何年烟雨解扁舟。"]'),
('427c458f-dcb2-4151-ab21-625265eae715','九日與數客登善福院之絕頂晚飲茗飲閣予以病先歸賦十二韻','朱槔','宋','宋诗','song-poetry','','[]','風日迫佳節，一川秋意昏。',144,'全唐诗/poet.song.107000.json','["風日迫佳節，一川秋意昏。", "臨高分石磴，却立數煙村。", "楚製隨雲物，蠻花照酒痕。", "龍山嗟未久，藍水想空存。", "鴻鴈頻收唳，茱萸幾斷魂。", "拍肩尋熟路，登閣換餘樽。", "鍾梵規繩闊，親朋笑語溫。", "加籩携海嶠，聞笛憶鄉園。", "夢記南柯守，兵看左角奔。", "詩凡羞晉宋，髮短任乾坤。", "汝輩禪心起，今生道眼渾。", "不知東嶂外，灧灧湧金盆。"]'),
('1b02a273-3300-48fb-a892-4c11d64051e3','秋日  其一','朱槔','宋','宋诗','song-poetry','','[]','鳴蜩初歇樹猶陰，黄菊紅榴色轉深。',32,'全唐诗/poet.song.107000.json','["鳴蜩初歇樹猶陰，黄菊紅榴色轉深。", "管領秋風有今日，留仙群稱辟寒金。"]'),
('281cf16d-df9e-4ccf-abba-a9d8bc97e42a','秋日  其二','朱槔','宋','宋诗','song-poetry','','[]','簸弄天風髮彩凉，西河一笑問吳剛。',32,'全唐诗/poet.song.107000.json','["簸弄天風髮彩凉，西河一笑問吳剛。", "借君玉斧煩輕手，留取箇中秋影香。"]'),
('dff973b2-07cd-4ef1-a4ef-8f608525c6a6','秋日  其三','朱槔','宋','宋诗','song-poetry','','[]','山靜溪回樹綠晴，鷺群點點雪分明。',32,'全唐诗/poet.song.107000.json','["山靜溪回樹綠晴，鷺群點點雪分明。", "影沉寒水初無意，只是魚兒獨自驚。"]'),
('70a5421d-4bd7-4ac0-a97f-9e38410bb5e1','葵道人之三山','朱槔','宋','宋诗','song-poetry','','[]','君家雙峯下，祝髮事香火。',96,'全唐诗/poet.song.107000.json','["君家雙峯下，祝髮事香火。", "豈無遠遊志，困此萬山裹。", "坐閲腰包中，未接話已墮。", "翩然問知津，九仙入風柁。", "冥冥荔枝浦，華屋紛砐硪。", "邂逅儻逢渠，周旋寧作我。", "閉門造車語，雖陋佛所可。", "他年笑相視，此計無乃左。"]'),
('cf486e10-6f14-4f22-ba8e-0e538552e39c','次嶺上壁間韻','朱槔','宋','宋诗','song-poetry','','[]','雲卧雙峯祇對亭，黄塵縈拂玉梅驚。',32,'全唐诗/poet.song.107000.json','["雲卧雙峯祇對亭，黄塵縈拂玉梅驚。", "春風一棹歸來早，誰作窗間擁鼻聲。"]'),
('0dc18fb9-3d3a-4372-bcdd-d94f429a8797','春風','朱槔','宋','宋诗','song-poetry','','[]','一舉造物手，萬生和氣中。',48,'全唐诗/poet.song.107000.json','["一舉造物手，萬生和氣中。", "酒邊排雪意，詩裏要春風。", "了了誰孤起，滔滔我即空。", "試詢三世事，猶有讀書功。"]'),
('2ce12def-bd2e-4b12-af7a-55ea5a4482e3','折山道中六言寄湧翠道人  其一','朱槔','宋','宋诗','song-poetry','','[]','折山有路可上，他日雲藏萬家。',28,'全唐诗/poet.song.107000.json','["折山有路可上，他日雲藏萬家。", "用處何曾觸石，一禪指頂天涯。"]'),
('ead8ddca-7f6e-4122-9583-eea41419680f','折山道中六言寄湧翠道人  其二','朱槔','宋','宋诗','song-poetry','','[]','雲暖網橫危磴，日沉舟泊平沙。',28,'全唐诗/poet.song.107000.json','["雲暖網橫危磴，日沉舟泊平沙。", "欵乃一聲歸去，炊烟遥起蘆花。"]'),
('3d78f62e-1c24-4cd2-be4c-3aecd671223b','折山道中六言寄湧翠道人  其三','朱槔','宋','宋诗','song-poetry','','[]','牛卧黄茅岡底，鷺歸紅葉村邊。',28,'全唐诗/poet.song.107000.json','["牛卧黄茅岡底，鷺歸紅葉村邊。", "可是太平無象，溪橋醉舞華顛。"]'),
('30e4da93-8e16-4f1b-aff1-9f4f875d08fa','折山道中六言寄湧翠道人  其四','朱槔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','玉梅無意相惱，嗾人烟雨疏疏。',28,'全唐诗/poet.song.107000.json','["玉梅無意相惱，嗾人烟雨疏疏。", "擬寫箇中妙處，語煩不到西湖。"]'),
('156467b8-7f96-4f10-8fb5-14ad4d457af2','折山道中六言寄湧翠道人  其五','朱槔','宋','宋诗','song-poetry','','[]','草枯蟲躍驚響，溪靜魚行閃光。',28,'全唐诗/poet.song.107000.json','["草枯蟲躍驚響，溪靜魚行閃光。", "只麽時時管带，可須細細商量。"]'),
('8e71a370-d1b1-40ae-abc7-d46418ca69c9','折山道中六言寄湧翠道人  其六','朱槔','宋','宋诗','song-poetry','','[]','既有女名靈照，何妨自作維摩。',28,'全唐诗/poet.song.107000.json','["既有女名靈照，何妨自作維摩。", "要見諸天辦供，問他風月山河。"]'),
('cbd61916-c67e-46d3-a03f-3ceb0e5d64f8','寄龔十三','朱槔','宋','宋诗','song-poetry','','[]','支頤獨揖北窗風，怪事從今咄咄空。',64,'全唐诗/poet.song.107000.json','["支頤獨揖北窗風，怪事從今咄咄空。", "簡策不知春色晚，山川渾落戰塵中。", "花飄茵席三生凈，草入池塘一句工。", "想見楚龔懷我處，扁舟遨蕩夕陽紅。"]'),
('acb870b4-1138-44d5-b433-0f48e57030a4','穀雨','朱槔','宋','宋诗','song-poetry','','[]','大點紛林際，虛簷寫夢中。',48,'全唐诗/poet.song.107000.json','["大點紛林際，虛簷寫夢中。", "明朝知穀雨，無策禁花風。", "石渚收機巧，烟蓑建事功。", "越禽牢閉口，吾道寄天公。"]'),
('930a329e-4ee7-41ee-afa7-5198f141c96a','磻叟書云牡丹酴醾已盡胡不歸','朱槔','宋','宋诗','song-poetry','','[]','客次驚衰白，歸期先牡丹。',48,'全唐诗/poet.song.107000.json','["客次驚衰白，歸期先牡丹。", "空枝兼病力，啼鳥問愁端。", "平日長相憶，東風忍不看。", "冰容亦零落，唯是有春寒。"]'),
('5bd08238-b19b-4679-9d62-87c69ad56d49','姚大本以李義山詩韻作詩題息軒繼作','朱槔','宋','宋诗','song-poetry','','[]','隠几心疑水，携盂影照山。',96,'全唐诗/poet.song.107000.json','["隠几心疑水，携盂影照山。", "六窗開畔岸，一榻埽中間。", "柏子方饒舌，花枝忽解顔。", "定餘牛自牧，夢起蝶相關。", "閶闔初無路，蓬萊別有班。", "藏舟知夜失，面壁竟西還。", "老矣從他笑，公乎伴我閑。", "體坤詩更好，分寸許躋攀。"]'),
('dcb435f6-5403-4a5e-ba34-da613a4a8d36','書報國壁向年寓學於此嘗見虹下飲溪中復聞子規','朱槔','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔與春風來此時，携書齪齪伴兒嬉。',64,'全唐诗/poet.song.107000.json','["昔與春風來此時，携書齪齪伴兒嬉。", "山晴欄楯投雌霓，身病林巒號子規。", "短髮蕭蕭吹易盡，長江滾滾去何之。", "欲追舊事無言說，更作三生石上期。"]'),
('e6f3309a-7275-47b0-9c53-3f8f72d6281f','蓋竹與陳和仲昆季','朱槔','宋','宋诗','song-poetry','','[]','玉樹成群不可攀，謾將牢落待蒼山。',64,'全唐诗/poet.song.107000.json','["玉樹成群不可攀，謾將牢落待蒼山。", "五年分手河梁外，一夕連牀風雨間。", "梅蕊凌寒春欲動，酒杯無力病相關。", "朱陳自古同鄉社，更約青雲作往還。"]'),
('5104ebba-099a-405d-a72c-dbdb06541868','寄夢肇','朱槔','宋','宋诗','song-poetry','','[]','滄海橫流無處安，只今且作夢中看。',64,'全唐诗/poet.song.107000.json','["滄海橫流無處安，只今且作夢中看。", "豈須遊戲兩蝸角，收此微茫一彈丸。", "老境懷人山宛轉，春風著物鬢摧殘。", "窮愁似與詩增氣，嚼雪敲冰字字寒。"]'),
('b875d082-37e5-4887-9ef8-6d06cf717af5','辛酉五月望簡陳和仲','朱槔','宋','宋诗','song-poetry','','[]','秀出雪峯一千衆，挽回廬阜三十年。',64,'全唐诗/poet.song.107000.json','["秀出雪峯一千衆，挽回廬阜三十年。", "赤烏白馬吐傑句，黄花翠竹通幽禪。", "竺師不假報文度，鑿齒本自知彌天。", "可憐烏石嶺下路，榕葉炯炯凝雲烟。"]'),
('ed0494c1-f70e-4587-9c45-ecdc8aa089b7','用東坡武昌寒溪韻三篇  其一','朱槔','宋','宋诗','song-poetry','','[]','漫郎古邑埋蒿萊，五柳合抱何人栽。',224,'全唐诗/poet.song.107000.json','["漫郎古邑埋蒿萊，五柳合抱何人栽。", "浯溪未作天寶頌，爽氣已壓南昌梅。", "蘇公鄧公先後到，一時玉立高嵬嵬。", "扁舟載酒渡江水，千山軟翠昏樓臺。", "漥尊抔飲追太古，雲荒石老無紛埃。", "歸來玉署念赤壁，側身西望銀濤堆。", "英辭傑句相震發，尚記野鳥窺空罍。", "只今却數未百載，蟲篆想見留巖隈。", "中原膻腥雜夷夏，淮北城壘生莓苔。", "公乎天與濟世具，曷不手引梟鸞開。", "空遺筆力配元祐，頓覺紙上千軍摧。", "禁中頗牧知在即，號令前日頒風雷。", "丹青元向大羽出，貂蟬要自兜鍪來。", "數公文字雖勝絕，莫使變作離騷哀。"]'),
('6c572bd8-1423-4075-a8ae-dd68b180361e','用東坡武昌寒溪韻三篇  其二','朱槔','宋','宋诗','song-poetry','','[]','東坡謫官未放回，桃花不繫玄都栽。',224,'全唐诗/poet.song.107000.json','["東坡謫官未放回，桃花不繫玄都栽。", "機牙愛觸造物手，五見江雨肥江梅。", "扁舟一笑凌浩渺，瘦筇結伴登崔嵬。", "漥尊故事逢浪叟，鳥篆真迹追浯臺。", "漂流長有北闕夢，邂逅果踏東華埃。", "玉堂夜直對同舍，金燭照座花成堆。", "帝觴雨露澆舌本，忽憶樊口傾山罍。", "聯詩共刻醉眠處，至今寶氣蟠巖隈。", "關西夫子獨好事，掖垣行即吟蒼苔。", "斯文突過元祐上，已覺萬丈光芒開。", "臨風弔客感赤壁，公瑾孟德俱彫摧。", "英雄割據亦兒戲，安用匕筯驚蚊雷。", "東坡羽化不復返，浪叟何日成歸來。", "鸚鵡洲前舊時路，寒波荒葦令人哀。"]'),
('0dd1b29d-026b-459d-a7a0-034433c15adf','用東坡武昌寒溪韻三篇  其三','朱槔','宋','宋诗','song-poetry','','[]','故園山水真奇哉，三徑蘭菊當年栽。',224,'全唐诗/poet.song.107000.json','["故園山水真奇哉，三徑蘭菊當年栽。", "自嗟流浪不知返，江城曉角愁吹梅。", "詩書邀我忽半世，車轂前却連崔嵬。", "試尋夷路到聖處，馬力已竭煩輿臺。", "去天尺五吐傑句，孔丘盜跖俱塵埃。", "坐疑蓬島尋丈爾，扁舟徑入浮雲堆。", "肩摩嵇向挽焦賀，欲倒瀛海爲尊罍。", "夢中失脚在何許，千里閩越天南隈。", "隻身形影自相弔，俯仰馬鬣迷青苔。", "蘭階彫謝知葉落，荆樹慘淡無花開。", "向來愚公不自度，一手欲以太華摧。", "那知天目山頂露，兒啼下視雲間雷。", "華亭黄耳竟安在，遼東白鶴還飛來。", "終尋三十六峯去，要假聶許平餘哀。"]'),
('81740d52-559f-4f1b-ae68-102414aa2de3','感事  其一','朱槔','宋','宋诗','song-poetry','','[]','大弓竊陽氏，神鼎淪泗淵。',48,'全唐诗/poet.song.107000.json','["大弓竊陽氏，神鼎淪泗淵。", "何須識微士，周魯必不全。", "武庫一朝火，斬蛇逐飛烟。", "傷心睨前事，氐虜定紛然。"]'),
('5c8baa0e-54b8-4c8c-8c0d-319cfebbb449','感事  其二','朱槔','宋','宋诗','song-poetry','','[]','山川非晉土，悲泣效楚囚。',48,'全唐诗/poet.song.107000.json','["山川非晉土，悲泣效楚囚。", "一語强自慰，凄迷望神州。", "刺史下荆水，司農來石頭。", "土園管夷吾，過計非私憂。"]'),
('c336a19d-d186-4112-af56-bbfcf45b6ba9','感事  其三','朱槔','宋','宋诗','song-poetry','','[]','元規負康濟，徒手嬰群雄。',48,'全唐诗/poet.song.107000.json','["元規負康濟，徒手嬰群雄。", "兵從歷陽來，無地逃姦鋒。", "誰乎死社稷，千載一卞公。", "英風與義氣，建立成江東。"]'),
('a43adeb6-f619-4651-99a4-7cfffaf42905','雪梅  其一','朱槔','宋','宋诗','song-poetry','','[]','去年雪欺客，平地一尺深。',48,'全唐诗/poet.song.107000.json','["去年雪欺客，平地一尺深。", "謝遣東閣花，那顧西牀琴。", "故人初不知，屋側乃見尋。", "悠然振永起，誰復明此心。"]'),
('a46aa76a-c4c9-43e1-af59-9252ed519b87','雪梅  其二','朱槔','宋','宋诗','song-poetry','','[]','寒梅卧烟雨，山澤有奇氣。',48,'全唐诗/poet.song.107000.json','["寒梅卧烟雨，山澤有奇氣。", "六龍扶翼之，月袂攬雲轡。", "先生九疑仙，心識真筌秘。", "裁詩作花骨，瘦凈乃可貴。"]'),
('dc09ac35-04ee-4efa-b4c1-4bdb70c8eac2','道中','朱槔','宋','宋诗','song-poetry','','[]','疢憂倦征行，金火方牴牾。',144,'全唐诗/poet.song.107000.json','["疢憂倦征行，金火方牴牾。", "宵分餉群僕，乘月問前路。", "小兒何自至，檝我陳洲渡。", "暗浪擊層崖，平沙起驚鷺。", "莽蒼川花開，冥蒙山氣聚。", "物情豈不嘉，悶滯非所遇。", "鈴語出林表，風期呼我住。", "尋幽本素志，觸熱詠嘉句。", "午枕得高深，復覺清景駐。", "誰云適所願，永乏濟世具。", "以茲一夢頃，可况百年遇。", "咄哉郭氏子，破甑尚欲顧。"]'),
('b7cf3a29-334e-420b-bb82-cd59316f8258','自作挽歌辭','朱槔','宋','宋诗','song-poetry','','[]','憂幽坐南軒，萬壑取我囚。',216,'全唐诗/poet.song.107000.json','["憂幽坐南軒，萬壑取我囚。", "疾雷且不聞，焉知草蟲愁。", "强顔理編簡，閲世如東流。", "滔滔竟不返，誰復操戈矛。", "天涯念孤姪，携母依諸劉。", "書來話悲辛，心往形輒留。", "先塋託仙峯，山僧掃梧楸。", "二女隨母住，外翁今白頭。", "伯氏尚書郎，名字騰九州。", "仲兄中武舉，氣欲無羌酋。", "棣華一朝集，荆樹三枝稠。", "堂堂相繼去，遺我歸山丘。", "漆園夢方覺，白衣雲正浮。", "憑陵若蹈空，何處停華輈。", "故鄉豈不懷，屋食良易謀。", "自我識廢興，於天無怨尤。", "平生喜聞詩，此詩當挽謳。", "不須生芻奠，君從二兄游。"]'),
('12982ef2-babe-41eb-81b6-ba0ab46fef5a','頌','劉子羽','宋','宋诗','song-poetry','','[]','趙州柏樹太無端，境上追尋也大難。',32,'全唐诗/poet.song.107000.json','["趙州柏樹太無端，境上追尋也大難。", "處處綠楊堪繫馬，家家門底透長安。"]'),
('1c6d453f-7101-4491-8750-eecbd0fd0dd2','題武夷山鍾模石','劉子羽','宋','宋诗','song-poetry','','[]','誰鑄三鍾欒乳形，不須筍簴自能鳴。',32,'全唐诗/poet.song.107000.json','["誰鑄三鍾欒乳形，不須筍簴自能鳴。", "仙君欲奏賓雲曲，只感清霜便發聲。"]'),
('8c0fecd1-27e7-4270-a47a-f6c202605250','題瑞岩扣冰古佛','劉子羽','宋','宋诗','song-poetry','','[]','古木千章覆地陰，微風披拂遞幽吟。',64,'全唐诗/poet.song.107000.json','["古木千章覆地陰，微風披拂遞幽吟。", "化身大士久圓寂，歸命群黎無古今。", "能使兵戈長偃息，要知願力本宏深。", "中原赤子方魚肉，願廣當年濟物心。"]'),
('c0600dee-e2a5-41db-afd9-0dcb5a51151f','焦山','范同','宋','宋诗','song-poetry','','[]','客星底事犯宸居，輸與焦君卧草廬。',64,'全唐诗/poet.song.107000.json','["客星底事犯宸居，輸與焦君卧草廬。", "萬樹遮山難覓寺，百川入海此歸墟。", "浮沉心事盟鷗鳥，獻替功名愧䱥魚。", "獨愛烟波開霽景，微雲不遣滓清虛。"]'),
('db30dc7c-e401-4e12-a8f6-cf7377376d32','挽和靖先生','高閌','宋','宋诗','song-poetry','','[]','身占河南第一功，力行篤信守家風。',64,'全唐诗/poet.song.107000.json','["身占河南第一功，力行篤信守家風。", "淵源漫說斯文喪，深切今知此道東。", "七日夢楹終有待，三年築室恨無從。", "嵩伊千古溫淳氣，收入稽山鑑影中。"]'),
('67446957-eae4-4d06-996f-12947de232e6','句','萬世延','宋','宋诗','song-poetry','','[]','莫放山虧簣，終教井及泉。',12,'全唐诗/poet.song.107000.json','["莫放山虧簣，終教井及泉。"]'),
('d4b69ef0-bb28-4f2d-b2ec-fd9ab5f2c0d2','老人村','宋汝爲','宋','宋诗','song-poetry','','[]','憔悴應憐范叔寒，南北東西萬里謫。',32,'全唐诗/poet.song.107000.json','["憔悴應憐范叔寒，南北東西萬里謫。", "朱顔荏苒變黎黑，走遍天涯常是客。"]'),
('2501d756-6810-4da5-aff6-9fee7311d21a','句','宋汝爲','宋','宋诗','song-poetry','','[]','平日慣從山外看，不禁煩惱著山圍。',16,'全唐诗/poet.song.107000.json','["平日慣從山外看，不禁煩惱著山圍。"]'),
('473208ed-c5d2-48cd-9d77-9c9704405dc7','岳陽','沈大廉','宋','宋诗','song-poetry','','[]','夜共瀟湘月，朝連巫峽雲。',24,'全唐诗/poet.song.107000.json','["夜共瀟湘月，朝連巫峽雲。", "烟愁賈太傅，雨泣屈平君。"]'),
('d34db606-f963-459c-b52b-62632b0bf01f','鼓山','沈大廉','宋','宋诗','song-poetry','','[]','屴崱峰頭萬丈梯，上方高與白雲齊。',32,'全唐诗/poet.song.107000.json','["屴崱峰頭萬丈梯，上方高與白雲齊。", "青山盡處海門闊，紅日上來天宇低。"]'),
('b084a7ea-3271-46a8-be99-cfee3ee62450','馮城開元寺留題','張深','宋','宋诗','song-poetry','','[]','本自無涯宦海游，如何杖策訪田疇。',32,'全唐诗/poet.song.107000.json','["本自無涯宦海游，如何杖策訪田疇。", "太平豈是渾無象，兩兩耕夫話有秋。"]'),
('737d0784-105d-4a41-bd55-8549deb74e4b','句','陳璹','宋','宋诗','song-poetry','','[]','活計魚蝦蟹，此事屬漁舟。',12,'全唐诗/poet.song.107000.json','["活計魚蝦蟹，此事屬漁舟。"]'),
('f9e9154c-70f1-4880-9e6b-7e0f9950bc82','述懷','何宏中','宋','宋诗','song-poetry','','[]','馬革盛尸每恨遲，西山餓踣更何辭。',32,'全唐诗/poet.song.107000.json','["馬革盛尸每恨遲，西山餓踣更何辭。", "姓名不到中興曆，付與皇天后土知。"]'),
('272f2db0-a028-41ac-b67c-155e6212ab8d','贈何定遠','傅慎微','宋','宋诗','song-poetry','','[]','故人何定遠，造物不虛生。',48,'全唐诗/poet.song.107000.json','["故人何定遠，造物不虛生。", "骨骼棱棱瘦，詩篇字字清。", "世皆尊道義，我獨見忠誠。", "尊酒分携後，何時蓋復傾。"]'),
('7d953a16-0b73-4595-8817-979908760a1e','偈五首  其一','釋宗璉','宋','宋诗','song-poetry','','[]','暗穿玉線，密度金針。',20,'全唐诗/poet.song.107000.json','["暗穿玉線，密度金針。", "如水入水，似金博金。"]'),
('d0fb07ee-b80b-455e-8b0f-583253c4df77','偈五首  其二','釋宗璉','宋','宋诗','song-poetry','','[]','破無明暗，截生死流。',28,'全唐诗/poet.song.107000.json','["破無明暗，截生死流。", "度三有城，泛無爲海。", "須是識這箇始得。"]'),
('965740da-f8b7-4ada-8e9b-3cafff7d98ab','偈五首  其三','釋宗璉','宋','宋诗','song-poetry','','[]','喚作拄杖則觸，不喚作拄杖則背。',51,'全唐诗/poet.song.107000.json','["喚作拄杖則觸，不喚作拄杖則背。", "若也識得，荆棘林中撒手，是非海裏橫身。", "脫或未然，普賢乘白象，土宿跨泥牛。"]'),
('78c644bd-4439-4306-afbb-dc6b3113b1cb','偈五首  其四','釋宗璉','宋','宋诗','song-poetry','','[]','宗乘一唱殊途絕，萬別千差俱泯滅。',32,'全唐诗/poet.song.107000.json','["宗乘一唱殊途絕，萬別千差俱泯滅。", "通身是口難分雪，金剛腦後三斤鐵。"]'),
('87da21a0-c8ef-44ec-82bc-11804cd2f69b','偈五首  其五','釋宗璉','宋','宋诗','song-poetry','','[]','是是，放出南山真鼈鼻。',64,'全唐诗/poet.song.107000.json','["是是，放出南山真鼈鼻。", "不是不是，勒回千里追風驥。", "終成敗壞可憐生，塞斷咽喉無出氣。", "無出氣，有巴鼻。", "趙州東壁挂葫蘆，堪笑維摩談不二。"]'),
('d4ed5188-69fb-4e08-a887-486b3135b012','頌古三首  其一','釋宗璉','宋','宋诗','song-poetry','','[]','南來本欲破邪說，紙燈滅處難分雪。',32,'全唐诗/poet.song.107000.json','["南來本欲破邪說，紙燈滅處難分雪。", "踏著秤鎚硬似鐵，錯認烏龜喚作鼈。"]'),
('acd7d1f7-0143-4246-9362-a3add4dea3a6','頌古三首  其二','釋宗璉','宋','宋诗','song-poetry','','[]','新婦騎馿阿家牽，草裏尋常萬萬千。',32,'全唐诗/poet.song.107000.json','["新婦騎馿阿家牽，草裏尋常萬萬千。", "誰在後兮誰在先，不須特地苦加鞭。"]'),
('70421a9e-3409-4961-952d-7da50d62f8e0','頌古三首  其三','釋宗璉','宋','宋诗','song-poetry','','[]','馿尾豬頭牛脚跡，三斤麻子露消息。',32,'全唐诗/poet.song.107000.json','["馿尾豬頭牛脚跡，三斤麻子露消息。", "誌公杖頭剪刀尺，從來雨下階頭濕。"]'),
('43023b8e-e99d-4acc-839a-6dda6bf5ea5c','贊月庵','釋宗璉','宋','宋诗','song-poetry','','[]','這箇老漢，渾無縫罅。',138,'全唐诗/poet.song.107000.json','["這箇老漢，渾無縫罅。", "點鐵成金，指鹿爲馬。", "以張拙秀才語擒縱多口，阿師跨三脚馿兒，指點諸方話霸。", "遇賤時三世諸佛正眼難窺，遇貴時八大龍王亦難酬價。", "阿呵呵，也大差。", "只因會春園裏失却眼睛，從此惡名滔滔流遍天下。", "高挂虛堂兮如師子全威，一任百怪千妖暗中驚訝。", "燈禪燈禪，第一不得容易與伊點化。"]'),
('015e1f66-4ab2-476f-adc1-cd55adbc0ba4','頌古','釋行','宋','宋诗','song-poetry','','[]','滿滿彎弓射不著，長長揮劍斫無痕。',32,'全唐诗/poet.song.107000.json','["滿滿彎弓射不著，長長揮劍斫無痕。", "堪笑日月不到處，箇中別是一乾坤。"]'),
('f88795f1-2301-4790-a735-198c4522a006','頌古','釋祖燈','宋','宋诗','song-poetry','','[]','趙州眼放光，爍破四天下。',24,'全唐诗/poet.song.107000.json','["趙州眼放光，爍破四天下。", "鉢盂上安柄，至今成話霸。"]'),
('c75bf6ba-c9f2-4c5d-910d-0093857994c6','偈','釋德淳','宋','宋诗','song-poetry','','["\u534e\u5c71"]','俱胝一指頭，一毛拔九牛。',48,'全唐诗/poet.song.107000.json','["俱胝一指頭，一毛拔九牛。", "華嶽連天碧，黄河徹底流。", "截却指，急回眸。", "青箬笠前無限事，綠簑衣底一時休。"]'),
('cd864c3d-21d0-4054-ab6c-f4d857e5d406','頌古','釋德淳','宋','宋诗','song-poetry','','[]','昨日定今日不定，正令已行皆逐正。',32,'全唐诗/poet.song.107000.json','["昨日定今日不定，正令已行皆逐正。", "卓下靈山皂纛旗，百萬麾軍皆乞命。"]'),
('08a193a0-5274-446d-9c01-c78c19d9f36f','偈','釋祖璿','宋','宋诗','song-poetry','','[]','喫粥了也未，趙州無忌諱。',104,'全唐诗/poet.song.107000.json','["喫粥了也未，趙州無忌諱。", "更令洗鉢盂，太煞沒巴鼻。", "悟去由來不丈夫，這僧那免受糊塗。", "有指示，無指示，韶石四楞渾塌地。", "入地獄，如箭射，雲岫清風生大厦。", "相逢携手上高山，作者應須辨真假。", "真假分，若爲論，午夜寒蟾出海門。"]'),
('0259fefd-b22f-4510-b352-cb495b6a2b5d','頌古七首  其一','釋祖璿','宋','宋诗','song-poetry','','[]','盡却耳根并眼底，不知何處見如來。',32,'全唐诗/poet.song.107000.json','["盡却耳根并眼底，不知何處見如來。", "數聲幽鳥啼寒木，一片閑雲鋪斷崖。"]'),
('f0c4d063-70e7-4aa6-8eb1-8f4df3aa4fb8','頌古七首  其二','釋祖璿','宋','宋诗','song-poetry','','[]','道吾作舞，一曲無譜。',20,'全唐诗/poet.song.107000.json','["道吾作舞，一曲無譜。", "若將耳聞，未敢相許。"]'),
('bc033573-5409-4cfc-be60-afde5f77d95d','頌古七首  其三','釋祖璿','宋','宋诗','song-poetry','','[]','直下是非著不得，著不得處好承當。',32,'全唐诗/poet.song.107000.json','["直下是非著不得，著不得處好承當。", "木人昨夜通消息，南海波斯過大唐。"]'),
('7a464141-bc55-4c48-a636-31ad6757bf0c','頌古七首  其四','釋祖璿','宋','宋诗','song-poetry','','[]','安貼邦鄉老趙州，時辰使得最風流。',32,'全唐诗/poet.song.107000.json','["安貼邦鄉老趙州，時辰使得最風流。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('5e27369f-fac8-40c2-bbbb-fb50addbd9e1','頌古七首  其五','釋祖璿','宋','宋诗','song-poetry','','[]','指出長生地不迷，造成無縫塔巍巍。',32,'全唐诗/poet.song.107000.json','["指出長生地不迷，造成無縫塔巍巍。", "大家從此無餘事，渴飲饑餐且度時。"]'),
('8403ac4b-e44b-43f9-9031-cd1562a9eecd','頌古七首  其六','釋祖璿','宋','宋诗','song-poetry','','[]','石羊頭子向東看，大地茫茫被眼謾。',32,'全唐诗/poet.song.107000.json','["石羊頭子向東看，大地茫茫被眼謾。", "月映寒潭清徹底，雲收華岳露巑岏。"]'),
('d9e1a95d-ec78-4e41-a5f4-86c280eadfb0','頌古','釋德會','宋','宋诗','song-poetry','','[]','放行把住謾周遮，一段風流出當家。',32,'全唐诗/poet.song.107000.json','["放行把住謾周遮，一段風流出當家。", "不是當年漆桶破，爭能撒土又拋沙。"]'),
('5fc98f6f-63d8-451f-ad02-334626d4c11f','偈','釋宗鑒','宋','宋诗','song-poetry','','[]','送舊年，迎新歲，動用不離光影閃。',64,'全唐诗/poet.song.107000.json','["送舊年，迎新歲，動用不離光影閃。", "澄輝湛湛夜堂寒，借問諸人會不會。", "若也會，增瑕纇。", "若不會，依前昧。", "與君指箇截流機，白雲更在青山外。"]'),
('a531a693-a90d-4495-9889-142e797af1d9','偈','釋坦','宋','宋诗','song-poetry','','[]','徑山有箇竹篦，直下別無道理。',28,'全唐诗/poet.song.107000.json','["徑山有箇竹篦，直下別無道理。", "佛殿厨庫三門，穿過衲僧眼耳。"]'),
('8594a5d2-823b-4deb-99e0-ea846ec3bb02','偈三首  其一','釋慧方','宋','宋诗','song-poetry','','[]','沔水江頭叫一聲，此時方得契平生。',32,'全唐诗/poet.song.107000.json','["沔水江頭叫一聲，此時方得契平生。", "多年不識重相見，千聖同歸一路行。"]'),
('a77bd715-55cd-46f8-8591-ed104509623c','偈三首  其二','釋慧方','宋','宋诗','song-poetry','','[]','臨老方稱住持，全無些子玄機。',62,'全唐诗/poet.song.107000.json','["臨老方稱住持，全無些子玄機。", "開口十字九乖，問東便乃答西。", "如斯出世，討甚玄微。", "有時拈三放兩，有時就令而施。", "雖然如是，同道方知。"]'),
('ee44686e-1bb7-48b9-a9ad-c99c342458e4','偈三首  其三','釋慧方','宋','宋诗','song-poetry','','[]','達磨祖師在脚底，踏不著兮提不起。',68,'全唐诗/poet.song.107000.json','["達磨祖師在脚底，踏不著兮提不起。", "子細當頭放下看，病在當時誰手裏。", "張公會看脈，李公會使藥。", "兩個競頭醫，一時用不著。", "藥不相投，錯錯，喫茶去。"]'),
('b07bb89e-4dcf-4aa3-bd86-132f447ee7a5','頌古三十八首  其一','釋慧方','宋','宋诗','song-poetry','','[]','金槌影動，寶劍光寒。',20,'全唐诗/poet.song.107000.json','["金槌影動，寶劍光寒。", "百萬之衆，齊著眼看。"]'),
('9eeb5e7a-b86e-498f-911e-d8e9468cf770','頌古三十八首  其二','釋慧方','宋','宋诗','song-poetry','','[]','文殊彈指，罔明出定。',30,'全唐诗/poet.song.107000.json','["文殊彈指，罔明出定。", "今日重新，打翻舊令。", "女子瞿曇，在我心鏡。"]'),
('ab7ac199-cf93-4eef-b424-b3d9e95c855d','頌古三十八首  其三','釋慧方','宋','宋诗','song-poetry','','[]','善財拈起一枝草，持來度與文殊老。',32,'全唐诗/poet.song.107000.json','["善財拈起一枝草，持來度與文殊老。", "殺活雖然在手中，徧界不藏光杲杲。"]'),
('1d12dd52-2221-4323-b835-365c3d90e3b2','頌古三十八首  其四','釋慧方','宋','宋诗','song-poetry','','[]','靈山用處許誰知，迦葉偷顔笑展眉。',32,'全唐诗/poet.song.107000.json','["靈山用處許誰知，迦葉偷顔笑展眉。", "動便最初先漏泄，兒孫扶取上玄機。"]'),
('d6d17c0b-9dee-489f-a55d-547afd07ba88','頌古三十八首  其五','釋慧方','宋','宋诗','song-poetry','','[]','不是風旛不是心，從來只爲少知音。',32,'全唐诗/poet.song.107000.json','["不是風旛不是心，從來只爲少知音。", "舉頭萬里長空外，唯見白雲流水深。"]'),
('76f90573-3541-4fa2-8b33-632ab98c7b37','頌古三十八首  其六','釋慧方','宋','宋诗','song-poetry','','[]','布毛一吹，當下知歸。',20,'全唐诗/poet.song.107000.json','["布毛一吹，當下知歸。", "冷光徧地，獨露針錐。"]'),
('b61f5ddb-b514-4392-9e55-6f0538ff7d54','頌古三十八首  其七','釋慧方','宋','宋诗','song-poetry','','[]','卷起堂堂露眼睛，拈來覿面更相呈。',32,'全唐诗/poet.song.107000.json','["卷起堂堂露眼睛，拈來覿面更相呈。", "鼻頭脫盡誰能覷，把手歸來相並行。"]'),
('ec351d35-dbb6-4a7c-afe6-b64365baa25f','頌古三十八首  其八','釋慧方','宋','宋诗','song-poetry','','[]','日面月面，頭頭出現。',20,'全唐诗/poet.song.107000.json','["日面月面，頭頭出現。", "捏聚放開，成團成片。"]'),
('d3dbe7da-83a9-4cde-9590-cdf80f7fcf79','頌古三十八首  其九','釋慧方','宋','宋诗','song-poetry','','[]','掛拂親遭喝，當下舌頭脫。',36,'全唐诗/poet.song.107000.json','["掛拂親遭喝，當下舌頭脫。", "把起便相呈，爲君重提掇。", "要知三日聾，大地如塵末。"]'),
('4a164c44-b741-41d2-9596-5ff0a5de60ae','頌古三十八首  其一○','釋慧方','宋','宋诗','song-poetry','','[]','南泉提起爲諸人，自是諸人眼不親。',32,'全唐诗/poet.song.107000.json','["南泉提起爲諸人，自是諸人眼不親。", "付與趙州呈好手，拈來覿面便翻身。"]'),
('eeeb9664-70cd-4d7a-b18f-139e89a50170','頌古三十八首  其一一','釋慧方','宋','宋诗','song-poetry','','[]','閉戶敲門向誰道，遂公言下便知歸。',32,'全唐诗/poet.song.107000.json','["閉戶敲門向誰道，遂公言下便知歸。", "從前活計都拋下，爭奈時人會者稀。"]'),
('8ddebe1d-c545-4711-9e83-1875df757c2c','頌古三十八首  其一二','釋慧方','宋','宋诗','song-poetry','','[]','一口吸西江，通身不隠藏。',24,'全唐诗/poet.song.107000.json','["一口吸西江，通身不隠藏。", "聖凡不到處，頂上放祥光。"]'),
('1e954cc4-6872-40c9-8fe2-7b38177761c4','頌古三十八首  其一三','釋慧方','宋','宋诗','song-poetry','','[]','藥山用處少人扶，堪笑雲巖與道吾。',32,'全唐诗/poet.song.107000.json','["藥山用處少人扶，堪笑雲巖與道吾。", "猶向榮枯生解會，豈知潘閬倒騎馿。"]'),
('c42e0525-e092-4a9d-bf75-e78097c335c4','頌古三十八首  其一四','釋慧方','宋','宋诗','song-poetry','','[]','覿面難藏向上機，家風千古爲人施。',32,'全唐诗/poet.song.107000.json','["覿面難藏向上機，家風千古爲人施。", "銀山鐵壁重重透，頼有丹霞院主知。"]'),
('e80c218f-fe3d-4073-97ee-46631ac8875f','頌古三十八首  其一五','釋慧方','宋','宋诗','song-poetry','','[]','異類中行得自由，須知千聖亦難收。',32,'全唐诗/poet.song.107000.json','["異類中行得自由，須知千聖亦難收。", "和光日照溪山曉，笑指乾坤那一頭。"]'),
('44288629-b086-404f-84a1-66f0282f1639','頌古三十八首  其一六','釋慧方','宋','宋诗','song-poetry','','[]','插鍬叉手異何同，要顯全機立大功。',32,'全唐诗/poet.song.107000.json','["插鍬叉手異何同，要顯全機立大功。", "雖然有數通呈了，留得高傳振祖風。"]'),
('8833cfee-4632-49ab-a63e-69e433830760','頌古三十八首  其一七','釋慧方','宋','宋诗','song-poetry','','[]','捧來前面請安名，黄蘗高高喚一聲。',32,'全唐诗/poet.song.107000.json','["捧來前面請安名，黄蘗高高喚一聲。", "剖出從前真面目，從茲佐得國風清。"]'),
('b84aa87a-e10f-4907-b04e-0bb82b9eeb91','頌古三十八首  其一八','釋慧方','宋','宋诗','song-poetry','','[]','趙州曾探水，茱萸無一滴。',36,'全唐诗/poet.song.107000.json','["趙州曾探水，茱萸無一滴。", "東覷西覷了，拄杖便靠壁。", "滄海深處歸，何人辨端的。"]'),
('163b4118-0789-49c2-bc97-caeba65bae4a','頌古三十八首  其一九','釋慧方','宋','宋诗','song-poetry','','[]','臺山路上人難進，獨有趙州親到來。',32,'全唐诗/poet.song.107000.json','["臺山路上人難進，獨有趙州親到來。", "勘破老婆回首處，從此行人眼不開。"]'),
('de244a9a-2a93-4180-b516-cd47492e10cd','頌古三十八首  其二○','釋慧方','宋','宋诗','song-poetry','','[]','狗子佛性無，寶劍出規模。',24,'全唐诗/poet.song.107000.json','["狗子佛性無，寶劍出規模。", "落在將軍手，橫按立當途。"]'),
