('173f5912-7075-4d4a-94fd-fc08e4b52269','頌古三十八首  其二五','釋慧方','宋','宋诗','song-poetry','','[]','睦州擔板幾人扶，喪者多應在半途。',32,'全唐诗/poet.song.107000.json','["睦州擔板幾人扶，喪者多應在半途。", "言下要教通徹去，迥然心眼顧醒甦。"]'),
('6d7d0349-3e21-4157-83af-657d9bbaa222','頌古三十八首  其二六','釋慧方','宋','宋诗','song-poetry','','[]','壞與不壞，言端語端。',40,'全唐诗/poet.song.107000.json','["壞與不壞，言端語端。", "舌頭咬破，自覺心酸。", "大隨投子，終無兩般。", "萬里區區，獨自往還。"]'),
('4f015f31-ca57-443e-8aec-2509267fde22','頌古三十八首  其二七','釋慧方','宋','宋诗','song-poetry','','[]','桃花端的悟靈雲，添得玄沙劫外春。',32,'全唐诗/poet.song.107000.json','["桃花端的悟靈雲，添得玄沙劫外春。", "滿地不知何處去，塵塵剎剎露全身。"]'),
('182a12e7-a90e-4d70-b413-91f70545f87c','頌古三十八首  其二八','釋慧方','宋','宋诗','song-poetry','','[]','曾透龍潭向上機，便將一棒力橫揮。',32,'全唐诗/poet.song.107000.json','["曾透龍潭向上機，便將一棒力橫揮。", "當頭突出何人辨，只許叢林作者知。"]'),
('d9cfaf1f-b378-4314-96be-079103da0015','頌古三十八首  其二九','釋慧方','宋','宋诗','song-poetry','','[]','生邪不道，死邪不道，一片清風閙浩浩。',34,'全唐诗/poet.song.107000.json','["生邪不道，死邪不道，一片清風閙浩浩。", "一時漏泄道吾機，反著襴衫倒頂帽。"]'),
('7c13fdd6-fafa-433b-8861-045977ff01f5','頌古三十八首  其三○','釋慧方','宋','宋诗','song-poetry','','[]','風信不來春色老，却憶後園馿喫草。',32,'全唐诗/poet.song.107000.json','["風信不來春色老，却憶後園馿喫草。", "滿天明月贈行人，野客溪邊歸路早。"]'),
('2f9f3bc8-e4c4-46de-8667-f3816a6f0c4d','頌古三十八首  其三一','釋慧方','宋','宋诗','song-poetry','','[]','樹倒藤枯笑未休，箇中誰解辨宗由。',32,'全唐诗/poet.song.107000.json','["樹倒藤枯笑未休，箇中誰解辨宗由。", "堂堂蹉路溈山老，空去空來一肚愁。"]'),
('e90ec23e-a873-4f4f-bc9e-944d7e7640db','頌古三十八首  其三二','釋慧方','宋','宋诗','song-poetry','','[]','添得溈山笑轉新，當時覿面已呈君。',32,'全唐诗/poet.song.107000.json','["添得溈山笑轉新，當時覿面已呈君。", "明招漏泄溈山句，無限風光付與人。"]'),
('c801d8df-02dd-457f-b82c-1838b7bf3600','頌古三十八首  其三三','釋慧方','宋','宋诗','song-poetry','','[]','東嶺西巖路暗通，有誰曾見老乾峯。',32,'全唐诗/poet.song.107000.json','["東嶺西巖路暗通，有誰曾見老乾峯。", "雲門把手雖同步，白雲飛蓋月含空。"]'),
('f5f0bf77-4657-4e1c-be46-cedacb93549a','頌古三十八首  其三四','釋慧方','宋','宋诗','song-poetry','','[]','三種病兮二種光，法身於此露堂堂。',32,'全唐诗/poet.song.107000.json','["三種病兮二種光，法身於此露堂堂。", "時人不會箇中意，猶把法身謾度量。"]'),
('49372c40-8cba-4aa7-9604-02062aeb2972','頌古三十八首  其三五','釋慧方','宋','宋诗','song-poetry','','[]','滔滔無問說，只爲太親切。',24,'全唐诗/poet.song.107000.json','["滔滔無問說，只爲太親切。", "有誰曾共聞，山河齊漏泄。"]'),
('273ebfca-ff4e-4691-bbfb-24fcde7bd010','頌古三十八首  其三六','釋慧方','宋','宋诗','song-poetry','','[]','雲門透法身，分明語露親。',24,'全唐诗/poet.song.107000.json','["雲門透法身，分明語露親。", "移步登山頂，峯高與月鄰。"]'),
('5153b050-e301-4724-b4a2-37b027e4327e','頌古三十八首  其三七','釋慧方','宋','宋诗','song-poetry','','[]','問佛還云是惠超，和根带子上枝條。',32,'全唐诗/poet.song.107000.json','["問佛還云是惠超，和根带子上枝條。", "春風浩浩難回避，發起乾坤那一苗。"]'),
('10d4108b-6830-4079-87ea-ff611fa4db43','頌古三十八首  其三八','釋慧方','宋','宋诗','song-poetry','','[]','親得摇來始息狂，風動荷花滿座香。',32,'全唐诗/poet.song.107000.json','["親得摇來始息狂，風動荷花滿座香。", "自從一得真歸趣，無意凉人人自凉。"]'),
('bb9b6a31-e786-40c0-a814-ec04731fb18a','偈頌二首  其一','釋思業','宋','宋诗','song-poetry','','[]','昨日夜叉心，今朝菩薩面。',24,'全唐诗/poet.song.107000.json','["昨日夜叉心，今朝菩薩面。", "菩薩與夜叉，不隔一條綿。"]'),
('a9418ed5-07b7-4746-8828-3e1cfba9062c','偈頌二首  其二','釋思業','宋','宋诗','song-poetry','','[]','勘破婆子，面青眼黑。',20,'全唐诗/poet.song.107000.json','["勘破婆子，面青眼黑。", "趙州老漢，瞞我不得。"]'),
('6214e0f5-d261-4382-8c1c-ecaeaada543e','偈','釋守緣','宋','宋诗','song-poetry','','[]','綠暗紅稀日，蜂忙蝶困時。',24,'全唐诗/poet.song.107000.json','["綠暗紅稀日，蜂忙蝶困時。", "本來真面目，一點不曾移。"]'),
('f1b950e5-2ead-4ff3-bc04-86bcda0aad7c','頌古','釋守緣','宋','宋诗','song-poetry','','[]','世間無物可羅籠，獨立嵯峨萬仞峰。',32,'全唐诗/poet.song.107000.json','["世間無物可羅籠，獨立嵯峨萬仞峰。", "忽若有人猛推落，騰身雲外不留縱。"]'),
('1cde89b4-ba58-4d07-992e-9e2f6962cc5e','偈二首  其一','釋守仁','宋','宋诗','song-poetry','','[]','百千三昧，無量妙門。',30,'全唐诗/poet.song.107000.json','["百千三昧，無量妙門。", "今日日庵不惜窮性命，只做一句子說與諸人。"]'),
('b63fe4f5-3334-4a2a-90f0-e9d912468c2a','偈二首  其二','釋守仁','宋','宋诗','song-poetry','','[]','雲從龍，風從虎，吹散江村寒露雨。',56,'全唐诗/poet.song.107000.json','["雲從龍，風從虎，吹散江村寒露雨。", "麗天杲日絕纖埃，有路明明吞佛祖。", "物見主，眼卓豎。", "天邊白雁送寒歸，籬下黄華香半吐。"]'),
('0357b1d8-991e-46d9-abf8-4db42bea165a','頌古','釋守仁','宋','宋诗','song-poetry','','[]','多方竊得破衣裳，壁倒籬坍沒處藏。',32,'全唐诗/poet.song.107000.json','["多方竊得破衣裳，壁倒籬坍沒處藏。", "更有一般無頼漢，不曾同伴要分贓。"]'),
('10930ee7-23fb-4da5-be3f-c4df0ea5014c','臺山婆話頌','釋守仁','宋','宋诗','song-poetry','','[]','開箇燈心皂角鋪，日求升合度朝昏。',32,'全唐诗/poet.song.107000.json','["開箇燈心皂角鋪，日求升合度朝昏。", "只因風雨連綿久，本利一空愁倚門。"]'),
('623752da-1939-46f4-90a4-2ddaa98ca981','頌古五首  其一','釋守仁','宋','宋诗','song-poetry','','[]','如舍利弗與麽去，千人萬人攔不住。',32,'全唐诗/poet.song.107000.json','["如舍利弗與麽去，千人萬人攔不住。", "優游自在涅槃城，步步蓮華隨足舉。"]'),
('ccf7165b-3fdc-496d-8b98-28b74c33010f','頌古五首  其二','釋守仁','宋','宋诗','song-poetry','','[]','氣直語直，眼親手親。',36,'全唐诗/poet.song.107000.json','["氣直語直，眼親手親。", "峯巒競秀，紅紫爭春。", "神通妙用施呈盡，要見國師猶隔津。"]'),
('0789969e-3f68-4c82-a1ec-a1b29f3b80dd','頌古五首  其三','釋守仁','宋','宋诗','song-poetry','','[]','相逢陪酒又陪歌，醉倒家中要我駝。',32,'全唐诗/poet.song.107000.json','["相逢陪酒又陪歌，醉倒家中要我駝。", "駝到家中猶駡詈，不知醒後又如何。"]'),
('78d80eb2-9631-43f3-ae4b-da9f91eaa6e7','頌古五首  其四','釋守仁','宋','宋诗','song-poetry','','[]','鋸解秤鎚，油煎石磉。',20,'全唐诗/poet.song.107000.json','["鋸解秤鎚，油煎石磉。", "兩手擎來，有功者賞。"]'),
('9f96c74b-080d-4cac-97ee-f44e98124db5','頌古五首  其五','釋守仁','宋','宋诗','song-poetry','','[]','凉宵愛月上危樓，幾處笙歌幾處愁。',32,'全唐诗/poet.song.107000.json','["凉宵愛月上危樓，幾處笙歌幾處愁。", "歌管未闌愁未歇，忽然天曉一時休。"]'),
('237aba0d-5559-4eea-8c94-fedde71b42e6','偈','釋彥岑','宋','宋诗','song-poetry','','[]','今朝八月初五，好事分明爲舉。',72,'全唐诗/poet.song.107000.json','["今朝八月初五，好事分明爲舉。", "嶺頭漠漠秋雲，樹底鳴鳩喚雨。", "昨夜東海鯉魚，吞却南山猛虎。", "雖然有照有用，畢竟無賓無主。", "唯有文殊普賢，住，住，我識得你。"]'),
('4d060f3c-fbd0-47c5-9388-e96d579a257d','頌古五首  其一','釋彥岑','宋','宋诗','song-poetry','','[]','胡孫喫毛蟲，烏狗上佛殿。',24,'全唐诗/poet.song.107000.json','["胡孫喫毛蟲，烏狗上佛殿。", "大地雪漫漫，澄江浄如練。"]'),
('4f1da236-55c4-4edb-9f8c-851c345db6ec','頌古五首  其二','釋彥岑','宋','宋诗','song-poetry','','[]','蠻奴赤脚上皇州，賣盡奇珍跨白牛。',64,'全唐诗/poet.song.107000.json','["蠻奴赤脚上皇州，賣盡奇珍跨白牛。", "貪著市朝人作市，又隨歌舞上官樓。", "多意氣，好風流，月冷珠簾掛玉鈎。", "分明忘却來時路，百尺竿頭輥繡毬。"]'),
('9568cdc5-77b3-4f17-868b-8872bf021c5f','頌古五首  其三','釋彥岑','宋','宋诗','song-poetry','','[]','岣嶁峯頭神禹碑，字青石赤形模奇。',40,'全唐诗/poet.song.107000.json','["岣嶁峯頭神禹碑，字青石赤形模奇。", "無目仙人纔一見，便應撫掌笑嘻嘻。", "雲暗蒼龍化葛陂。"]'),
('bc2664cb-9e27-4d0b-84a1-09f539c56da9','頌古五首  其四','釋彥岑','宋','宋诗','song-poetry','','[]','一橈打著這瞎漢，堪笑令猶行一半。',32,'全唐诗/poet.song.107000.json','["一橈打著這瞎漢，堪笑令猶行一半。", "竿頭絲線釣鯨波，趯浪拏雲猶是鈍。"]'),
('dbc3e5f2-b47c-4ca3-904c-2358b29676bb','頌古五首  其五','釋彥岑','宋','宋诗','song-poetry','','[]','沒蹤迹處莫藏身，看來端是眼中塵。',32,'全唐诗/poet.song.107000.json','["沒蹤迹處莫藏身，看來端是眼中塵。", "全機打破繫馿橛，棒頭敲出玉麒麟。"]'),
('be223be5-6a6d-4fc0-88b6-0cb408cc7538','頌','釋清','宋','宋诗','song-poetry','','[]','諸佛出身處，東山水上行。',48,'全唐诗/poet.song.107000.json','["諸佛出身處，東山水上行。", "石壓笋斜出，岸懸花倒生。", "舉僧問雲門：如何是諸佛出身處？門曰：東山水上行。"]'),
('e3800579-06c5-46a9-ad29-eb3c0a8e4239','頌','釋了贇','宋','宋诗','song-poetry','','[]','趙州狗子無佛性，萬疊青州藏古鏡。',32,'全唐诗/poet.song.107000.json','["趙州狗子無佛性，萬疊青州藏古鏡。", "赤脚波斯入大唐，八臂那吒行正令。"]'),
('388a8066-9559-4534-8e95-0b3945974a41','偈二首  其一','釋慧溫','宋','宋诗','song-poetry','','[]','拶出通身是口，何妨駡雨訶風。',28,'全唐诗/poet.song.107000.json','["拶出通身是口，何妨駡雨訶風。", "昨夜前村猛虎，咬殺南山大蟲。"]'),
('47de8c87-247a-4c2b-858b-50a6a5feccc1','偈二首  其二','釋慧溫','宋','宋诗','song-poetry','','[]','釋迦老子，四十九年坐籌帷幄。',74,'全唐诗/poet.song.107000.json','["釋迦老子，四十九年坐籌帷幄。", "彌勒大士，九十一劫带水拖泥。", "凡情聖量，不能剗除。", "理照覺知，猶存露布。", "佛意祖意，如將魚目作明珠。", "大乘小乘，似認橘皮爲猛火。"]'),
('ec26f25c-8913-489e-b838-7e65e95ee5ec','五位  其一','釋慧溫','宋','宋诗','song-poetry','','[]','正中偏，玉兔金烏落二邊。',28,'全唐诗/poet.song.107000.json','["正中偏，玉兔金烏落二邊。", "丫角童兒騎黑象，三更穿過御樓前。"]'),
('83485d67-841c-4a76-b780-b8f588f42db0','五位  其二','釋慧溫','宋','宋诗','song-poetry','','[]','偏中正，過房之子初受命。',28,'全唐诗/poet.song.107000.json','["偏中正，過房之子初受命。", "金剛脚下崑崙奴，腰間也佩毗盧印。"]'),
('280d8d78-ebbe-45f5-856c-74c29dddc59c','五位  其三','釋慧溫','宋','宋诗','song-poetry','','[]','正中來，無著當年訪善財。',28,'全唐诗/poet.song.107000.json','["正中來，無著當年訪善財。", "瑠璃盤裏藏明月，異草山華處處開。"]'),
('0ba9b493-941e-4613-9867-e28acd234bf3','五位  其四','釋慧溫','宋','宋诗','song-poetry','','[]','兼中至，不歷僧祇超十地。',28,'全唐诗/poet.song.107000.json','["兼中至，不歷僧祇超十地。", "雖然踏著舊家鄉，更須知有深深意。"]'),
('f6dfd79d-e3c6-48a7-b380-8f7fd2c4559f','五位  其五','釋慧溫','宋','宋诗','song-poetry','','[]','兼中到，天寒大雪長安道。',28,'全唐诗/poet.song.107000.json','["兼中到，天寒大雪長安道。", "五陵才子錦袍新，馬蹄亂踏瓊瑶草。"]'),
('a1af332c-66fd-424d-b8b5-848325301ab8','呈高庵偈','釋自圓','宋','宋诗','song-poetry','','[]','外國言音不可窮，起雲亭下一時通。',32,'全唐诗/poet.song.107000.json','["外國言音不可窮，起雲亭下一時通。", "口門廣大無邊際，吞盡楊歧栗棘蓬。"]'),
('1ed59479-859b-4997-bfe8-e20135b1c334','頌','釋自圓','宋','宋诗','song-poetry','','[]','南北東西萬萬千，乾坤上下兩無邊。',32,'全唐诗/poet.song.107000.json','["南北東西萬萬千，乾坤上下兩無邊。", "相逢相見呵呵笑，屈指抬頭月半天。"]'),
('5d679813-c83a-4f50-9498-115c0b0ad65a','偈二首  其一','釋清旦','宋','宋诗','song-poetry','','[]','三世諸佛不知有，一一面南看北斗。',64,'全唐诗/poet.song.107000.json','["三世諸佛不知有，一一面南看北斗。", "狸奴白牯却知有，雲外金毛正哮吼。", "箇中隠顯現全身，頭頭透脫無前後。", "撥轉機輪向上關，八角磨盤空裏走。"]'),
('27fe00ed-1783-4d6b-b18c-656a413127a2','偈二首  其二','釋清旦','宋','宋诗','song-poetry','','[]','三脚馿子弄蹄行，步步相隨不相到。',96,'全唐诗/poet.song.107000.json','["三脚馿子弄蹄行，步步相隨不相到。", "樹頭驚起雙雙魚，拈來一老一不老。", "爲憐松竹引清風，其柰出門便是草。", "因喚檀郎識得渠，大機大用都推倒。", "燒香勘證見根源，糞埽堆頭拾得寶。", "叢林浩浩謾商量，勸君莫謗先師好。"]'),
('4b352e93-9722-4d97-b0ac-9b5d6d01eaba','頌古四首  其一','釋清旦','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',36,'全唐诗/poet.song.107000.json','["世尊拈花，迦葉微笑。", "天際二輪，更相互照。", "若能截斷老瞿曇，閉目黄河只一跳。"]'),
('c6d2a08c-18be-4496-b2b3-319375d5e3ba','頌古四首  其二','釋清旦','宋','宋诗','song-poetry','','[]','荆棘林中宣妙義，蒺藜園裏放毫光。',32,'全唐诗/poet.song.107000.json','["荆棘林中宣妙義，蒺藜園裏放毫光。", "千言萬語無人會，又逐流鶑過短牆。"]'),
('6c7dd26e-a92e-40d1-b806-13b893cb1af6','頌古四首  其三','釋清旦','宋','宋诗','song-poetry','','[]','誰道先師無此語，焦尾大蟲元是虎。',56,'全唐诗/poet.song.107000.json','["誰道先師無此語，焦尾大蟲元是虎。", "胡蜂不戀舊時窠，猛將豈在家中死。", "急著眼，却回顧。", "若會截流那下去，匝地清風隨步舉。"]'),
('bd3734e6-3350-4ab1-8be6-59115dd91d78','頌古四首  其四','釋清旦','宋','宋诗','song-poetry','','[]','嶮崖之處，無處插嘴。',50,'全唐诗/poet.song.107000.json','["嶮崖之處，無處插嘴。", "去却藥忌，露當門齒。", "杈下放身捨命，箇裏如龍得水。", "三千里外賺吾來，捋虎鬚兮捉虎尾。"]'),
('cc6d9cb8-245a-40e7-a21d-b8d40ac5e231','偈','釋慧觀','宋','宋诗','song-poetry','','[]','前村落葉盡，深院桂花殘。',24,'全唐诗/poet.song.107000.json','["前村落葉盡，深院桂花殘。", "此夜初冬節，從茲特地寒。"]'),
('fa53aca9-9275-4f29-bf57-16420de4f6d3','頌','釋戒修','宋','宋诗','song-poetry','','[]','兩輪舉處烟塵起，電急星馳擬何止。',48,'全唐诗/poet.song.107000.json','["兩輪舉處烟塵起，電急星馳擬何止。", "目前不礙往來機，正令全施無表裏。", "丈夫意氣自衝天，我是我兮你是你。"]'),
('3220ab6a-09b1-47d5-8059-440b39543c4e','偈','釋淵','宋','宋诗','song-poetry','','[]','節近端午，乍晴乍雨。',124,'全唐诗/poet.song.107000.json','["節近端午，乍晴乍雨。", "带累達磨眼睛，特地和泥合土。", "二祖不會承當，雪庭枉受辛苦。", "引得後代兒孫，各自開張門戶。", "或放南山毒蛇，或作玄沙猛虎。", "雪峰連輥三毬，禾山一味打鼓。", "山僧檢點將來，盡是葛藤露布。", "爭如喫飯著衣，此外更無佛祖。", "阿嫂便是大哥妻，師姑元是女人做。"]'),
('2830a1f0-8ab8-4083-bf48-b70491cad679','臨終偈','釋淵','宋','宋诗','song-poetry','','[]','動靜聲色外，時人不肯對。',24,'全唐诗/poet.song.107000.json','["動靜聲色外，時人不肯對。", "世間出世間，畢竟使誰會。"]'),
('7ac93cdf-b052-419e-9ada-84920a00c329','留題澹巖  其一','張滉','宋','宋诗','song-poetry','','[]','偷閑切欲訪巖扃，恍若桃源洞裏春。',32,'全唐诗/poet.song.107000.json','["偷閑切欲訪巖扃，恍若桃源洞裏春。", "平世自無憂國事，徘徊愁見避秦人。"]'),
('21158e3a-4f95-426b-a8a8-3a366f37bcd2','留題澹巖  其二','張滉','宋','宋诗','song-poetry','','[]','天然一穴透融光，廣闊能容萬頃篁。',32,'全唐诗/poet.song.107000.json','["天然一穴透融光，廣闊能容萬頃篁。", "翻念塵寰苦炎熱，人人付與一襟凉。"]'),
('9094890b-7178-492c-aac5-f952a1b33c39','李伯紀丞相挽詩二首  其一','張浚','宋','宋诗','song-poetry','','[]','蒼蒼安可料，舊德奄重泉。',48,'全唐诗/poet.song.107000.json','["蒼蒼安可料，舊德奄重泉。", "痛爲黎民惜，誰扶大厦顛。", "英風摩日月，正氣返山川。", "丙午功勳在，豐碑萬口傳。"]'),
('59415970-0ca8-45d9-8ead-8f2c6b908fcf','李伯紀丞相挽詩二首  其二','張浚','宋','宋诗','song-poetry','','[]','十相從明主，唯公望最隆。',48,'全唐诗/poet.song.107000.json','["十相從明主，唯公望最隆。", "召周雖異迹，李郭本心同。", "未遇升天藥，空餘濟世功。", "薰風歌吹咽，泪盡古城東。"]'),
('277e10c4-9596-4464-859e-9ac938eb1892','贈羅赤脚','張浚','宋','宋诗','song-poetry','','[]','學道由來不記年，嘯歌風月在前緣。',32,'全唐诗/poet.song.107000.json','["學道由來不記年，嘯歌風月在前緣。", "身心已到無塵處，疑是人間自在仙。"]'),
('dd9c6377-248a-4016-abff-bd981da4efcc','詩一首','張浚','宋','宋诗','song-poetry','','[]','羣凶用事人心去，大義重新天意回。',32,'全唐诗/poet.song.107000.json','["羣凶用事人心去，大義重新天意回。", "解使中原無左衽，斯文千古未塵埃。"]'),
('8e875948-00a5-4cc4-a306-f108781db782','朝陽岩','張浚','宋','宋诗','song-poetry','','[]','已覺雲天闊，風聲四面凉。',48,'全唐诗/poet.song.107000.json','["已覺雲天闊，風聲四面凉。", "路幽遲晚日，岩古浥流香。", "客舍長年靜，漁舟底事忙。", "相逢賢太守，不用管弦將。"]'),
('eaa41575-4e3b-47ea-b643-ebd0e7f5f53a','登道觀','張浚','宋','宋诗','song-poetry','','[]','蒼髯野褐予甚古，蘿月桂風誰爲貧。',64,'全唐诗/poet.song.107000.json','["蒼髯野褐予甚古，蘿月桂風誰爲貧。", "當戶蛟龍森漢柏，隔江雞犬隠秦人。", "好山如畫能留客，寶鼎藏丹不計春。", "更上高亭問玄鶴，莫教詩眼有纖塵。"]'),
('98d4b3f2-b228-4b0f-a4fa-cd48ff8cccd1','詩一首','張浚','宋','宋诗','song-poetry','','[]','三相當年鎮廟堂，江山草木亦增光。',32,'全唐诗/poet.song.107000.json','["三相當年鎮廟堂，江山草木亦增光。", "一時主宰權衡重，千古人間姓字香。"]'),
('8c7e62d9-9d30-43b7-ba7d-8a389c2a3299','贊喻彌陀掩遺骸','張浚','宋','宋诗','song-poetry','','[]','刀兵劫海苦漫漫，原野遺骸葬若干。',32,'全唐诗/poet.song.107000.json','["刀兵劫海苦漫漫，原野遺骸葬若干。", "盡大地人須薦取，眼睛突出髑髏寒。"]'),
('492402ae-9ae5-4895-8d07-14a8376631fc','偈','張浚','宋','宋诗','song-poetry','','[]','教外單傳佛祖機，本來無悟亦無迷。',32,'全唐诗/poet.song.107000.json','["教外單傳佛祖機，本來無悟亦無迷。", "浮雲散盡青天在，日出東方夜落西。"]'),
('78d6c757-d10a-4bb3-89ec-1d85e7b5dc2a','過嚴子陵釣臺二首  其一','張浚','宋','宋诗','song-poetry','','[]','古木籠烟半鎖空，高臺隠隠翠微中。',32,'全唐诗/poet.song.107000.json','["古木籠烟半鎖空，高臺隠隠翠微中。", "身安不羨三公貴，寧與漁樵卒歲同。"]'),
('c455921f-2b47-47a1-8a05-bca675e3e1d1','過嚴子陵釣臺二首  其二','張浚','宋','宋诗','song-poetry','','[]','中興自是還明主，訪舊胡爲屬老臣。',32,'全唐诗/poet.song.107000.json','["中興自是還明主，訪舊胡爲屬老臣。", "從古風雲由際會，歸歟聊復養吾真。"]'),
('6a575839-9c27-4bd5-8792-55b14a958f04','還張德遠書幣題詩蔬圃壁間','蘇雲卿','宋','宋诗','song-poetry','','[]','多年別作一番風，誰料聲名達帝聰。',32,'全唐诗/poet.song.107000.json','["多年別作一番風，誰料聲名達帝聰。", "自有時人求富貴，莫將富貴污蘇公。"]'),
('7fe07a1a-b0ed-42ad-a954-9ca4f6ad4e45','嘲宰相賞花','張隠','宋','宋诗','song-poetry','','[]','位乖燮理致傷殘，四面牆匡不忍看。',32,'全唐诗/poet.song.107000.json','["位乖燮理致傷殘，四面牆匡不忍看。", "正是花時堪下淚，相公何必更追歡。"]'),
('fd0a2a41-2af6-4fff-9e92-cbbfd5f95f02','書弋陽館','陳康伯','宋','宋诗','song-poetry','','[]','憶昨東京拜相時，武夫前導爭驅馳。',176,'全唐诗/poet.song.107000.json','["憶昨東京拜相時，武夫前導爭驅馳。", "上奉天子一人命，下率百寮羅綱維。", "泰階賜膳侑金幣，上食供進黄門賫。", "夜來胡塵犯邊土，手握億萬兵擒虜。", "揮揚殺氣橫九秋，指揮猛將皆貔虎。", "八荒掃蕩沙漠空，旋師奏凱明皇宮。", "英雄富貴皆長事，辭榮解綬歸興濃。", "白石如玉泉如酥，河清海晏樂耕鋤。", "雉鳴麥秀花卉敷，親朋會合情歡娛。", "有子可教孫可訓，有書可讀田可租。", "常願年豐五穀登，斯民安堵心則愉。"]'),
('c17d281d-d811-4114-b017-7d8ef9b72230','題龜峯','陳康伯','宋','宋诗','song-poetry','','[]','形勢如龜稟賦奇，昂頭曳尾向溪湄。',64,'全唐诗/poet.song.107000.json','["形勢如龜稟賦奇，昂頭曳尾向溪湄。", "石色烝霞紅甲潤，苔痕濕雨綠毛垂。", "恍如獻瑞在官日，猶似呈書出洛時。", "千秋矻立層霄表，壽比喬松可等期。"]'),
('66ea10eb-4d0b-4445-a541-8b3f06a06ce5','題閩縣西湖','陳康伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鑿開百頃碧融融，潁上錢塘約略同。',64,'全唐诗/poet.song.107000.json','["鑿開百頃碧融融，潁上錢塘約略同。", "楊柳兩堤連綠蔭，芰荷十里馥香風。", "波涵翠巘層層出，潮接新河處處通。", "輿誦載塗農事起，從今歲歲作年豐。"]'),
('20fdc316-9c4c-46bf-976d-6ed02f6db9d9','送葉守','陳康伯','宋','宋诗','song-poetry','','[]','海國民皆興禮義，潢池盜已息干戈。',32,'全唐诗/poet.song.108000.json','["海國民皆興禮義，潢池盜已息干戈。", "農桑四境豐年屢，簫鼓千村叶氣多。"]'),
('9d6d81b9-d16c-4baa-8bdc-57b90092d15f','句','揚無咎','宋','宋诗','song-poetry','','[]','陳迹千年在，斯人百代無。',12,'全唐诗/poet.song.108000.json','["陳迹千年在，斯人百代無。"]'),
('0ff2b66f-1666-4bff-9737-867e5285c7a5','雙魚花','朱翌','宋','宋诗','song-poetry','','[]','物生本不同，所貴以形似。',72,'全唐诗/poet.song.108000.json','["物生本不同，所貴以形似。", "如何小草間，或作潜淵類。", "宛然花葉分，有此尾鬣備。", "如以柳貫腮，十百共一蒂。", "可肩比目鱗，與世爲上瑞。", "稽首蓬萊宮，願附花鳥使。"]'),
('d70c03d8-3fe4-457c-97de-f3f819976d8e','送山芥與徐稚山','朱翌','宋','宋诗','song-poetry','','[]','北風撼坤軸，飛雪封高崖。',180,'全唐诗/poet.song.108000.json','["北風撼坤軸，飛雪封高崖。", "萬草坐凍死，不復存根荄。", "蔚然蒼山底，有此紫玉釵。", "本無塵土侵，寧畏霜霰埋。", "偶爲樵牧知，遂與薇蕨偕。", "堅瘦故耐久，苦森終怒俳。", "未免一時出，肯事衆口諧。", "可以寄樂天，時供八關齋。", "可以送庾郎，三九代食鮭。", "朱門厭燖煼，嘉蔬日誰差。", "飛觴失行次，可口相推排。", "爾來走缾甖，遂費登山鞋。", "文昌列宿光，騎省後人佳。", "居官乃退步，養氣能實骸。", "一箸須子同，苦硬求吾儕。"]'),
('b564997a-e6f5-43a4-a7f1-e6ebc93ba3cf','淮人多食蛙者作詩示意','朱翌','宋','宋诗','song-poetry','','[]','淮人爲水族，庖膾亦已巧。',228,'全唐诗/poet.song.108000.json','["淮人爲水族，庖膾亦已巧。", "田間有鳴雞，性命得自保。", "吳人口垂涎，捕取窮浩渺。", "於吳産或多，於淮求則少。", "要之業境會，食債良自繞。", "予也家淮南，遊吳嘗草草。", "平生下箸處，但覺皆羊棗。", "不論赤鯶公，亦及長鬚老。", "何况鼓吹部，可作鐘鼎寶。", "世間多空中，所見徒有表。", "至美不外示，魚鼈豈皆好。", "君看十月鶉，羽翼甚輕矯。", "變化須臾間，不念舊池沼。", "食鶉乃無言，食蛙或顰愀。", "鶉蛙等無二，妄想自顛倒。", "舌根無盡期，所得在一飽。", "哀哉南路徐，食方說燖煼。", "但俱供芋羹，不必著錦襖。", "較之食瘡痂，豈但能稍稍。"]'),
('4ea554ba-f285-43d0-a55e-ee5264c7326c','游月巖詩','朱翌','宋','宋诗','song-poetry','','[]','赫日方正中，忽見第二月。',72,'全唐诗/poet.song.108000.json','["赫日方正中，忽見第二月。", "老木盤硬枝，扶疏真桂葉。", "烟雲成顯晦，弦望靡盈闕。", "初無大小餘，可以歷沒滅。", "但能照行人，千古此山側。", "却笑天上輪，晝夜不停轍。"]'),
('d29b51f9-316a-4cd4-a976-0d2ffaabddbb','張翰惠書告窘','朱翌','宋','宋诗','song-poetry','','[]','伯龍營什一，撫掌鬼在側。',120,'全唐诗/poet.song.108000.json','["伯龍營什一，撫掌鬼在側。", "燕公鑄橫財，地下萬爐執。", "貧富有物司，得失難智索。", "我今竟日餐，或待門生設。", "朝園斸菜根，暮火團松節。", "黄嬭坐上座，方兄行禁謁。", "安能决餘波，可以潤子篋。", "俯視腰一圍，何時解三篾。", "薦福縱有碑，震雷即驚裂。", "讀我送窮文，還君乞米帖。"]'),
('807fe77a-cf5d-4a8d-80f5-3bbd5a1504ff','與劉令食枸杞','朱翌','宋','宋诗','song-poetry','','[]','周黨過仲叔，菽水無菜茹。',96,'全唐诗/poet.song.108000.json','["周黨過仲叔，菽水無菜茹。", "我槃有枸杞，與子同一箸。", "若比閔縣令，已作方丈富。", "但令齒頰香，差免腥羶汙。", "我壽我自知，不待草木輔。", "政以不種勤，日夕供草具。", "更約傅延年，一飯美無度。", "解衣高聲讀，蘇陸前後賦。"]'),
('5c8273dc-1982-4596-9f15-5276fba0a5e5','王令收桂花蜜漬埳地瘞三月啟之如新','朱翌','宋','宋诗','song-poetry','','[]','桂花老月窟，墮地散金蕊。',120,'全唐诗/poet.song.108000.json','["桂花老月窟，墮地散金蕊。", "長憂風雨餘，失此香旖旎。", "撫樹三歎息，留花姑少俟。", "枕中有仙方，解使香不死。", "蜜蜂喜輸糧，餘潤獲漸靡。", "瘞深閲三月，發覆驗封璽。", "虛堂習新觀，博山爲頻啟。", "初從鼻端參，忽置秋色裏。", "氤氳縹緲間，可以降月姊。", "自茲聞四時，何止名七里。"]'),
('627cd3d0-49b2-4bd8-8e64-8c2f4a760f60','與郭令步至城下見田間稻秧已可插慨然有感示郭令','朱翌','宋','宋诗','song-poetry','','[]','端居倦來往，春去誰與娛。',108,'全唐诗/poet.song.108000.json','["端居倦來往，春去誰與娛。", "眷眷斗升米，翛翛東南都。", "薄暮喜穿屐，同遊又吾徒。", "念昔始經此，汙邪祝滿車。", "及今幾何日，立苗還欲疏。", "懷新舞翠剡，生意蔚以舒。", "吾生將安之，土偶之與俱。", "清夜夢鄉曲，未覺田園蕪。", "他時招子歸，把鋤春雨餘。"]'),
('7e29323d-080d-45c3-9462-9818e4313345','重午菊有花遂與菖蒲同採','朱翌','宋','宋诗','song-poetry','','[]','菖蒲秀端午，黄花作重陽。',96,'全唐诗/poet.song.108000.json','["菖蒲秀端午，黄花作重陽。", "萬物各時行，半歲遥相望。", "云何忽並開，相與同一觴。", "仙人九節杖，東坡一枝香。", "洗去仲夏熱，如逢晚秋霜。", "均是酒中物，俱使吾年長。", "莫誇雨露私，勿笑草木狂。", "登高閲競渡，樂哉未渠央。"]'),
('a1256b4f-7adf-42e9-96ba-bb2d2cefa472','競渡示周宰','朱翌','宋','宋诗','song-poetry','','[]','英英屈大夫，遺骨淪湘湄。',252,'全唐诗/poet.song.108000.json','["英英屈大夫，遺骨淪湘湄。", "楚人念何深，叫空冤水妃。", "雖無些詞招，顧有鐃鼓悲。", "憶昨上巳日，縱觀金明池。", "突殿隠負鼇，長橋低卧蜺。", "諸公貴人來，珠幢紺幰隨。", "兩軍各氣焰，萬楫生光輝。", "龜魚戢影避，虎龍挾翼飛。", "想當大軍後，益覺遊子稀。", "况我中興君，高拱絕宴嬉。", "羈人老淮楚，古寺臨長溪。", "節物亦撩人，風俗自隨時。", "往來兩舴艋，規模具體微。", "邑人樂豐年，聚觀眼不移。", "捐金賞先至，頓足助絕馳。", "在昔攻戰具，今但娛羣兒。", "因而語兵法，可以威四夷。", "八寶水中央，大海壓左圻。", "其中椎剽姦，連艦揚鼓旗。", "先事能預防，在易則見幾。", "作詩示周郎，赤壁有成師。"]'),
('5cefd728-8c5e-494e-8ff9-cad8ffb2a0ba','竹枕','朱翌','宋','宋诗','song-poetry','','[]','方牀洗湘斑，夏簟織蘄笛。',84,'全唐诗/poet.song.108000.json','["方牀洗湘斑，夏簟織蘄笛。", "誰與同卧起，青奴甚相得。", "嘉哉直節君，契分近愈密。", "深林捕貓頭，乃復枕上膝。", "直從無熱天，徑下清凉國。", "早晚報平安，一覺我自適。", "夢中從我遊，子猷推第一。"]'),
('10c25a21-a61e-4a0c-ac68-e17afd12ac8e','西園月夜竹影滿堂','朱翌','宋','宋诗','song-poetry','','[]','良夜天徹幕，林間月如篩。',84,'全唐诗/poet.song.108000.json','["良夜天徹幕，林間月如篩。", "解與竹傳神，月娥真畫師。", "東坡元不死，鶴駕相追隨。", "習氣未掃除，戲筆聊一麾。", "調和水墨勻，幻出虯龍枝。", "圖成不挂壁，擲地容俯窺。", "欲進復小却，尚慮鞋底泥。"]'),
('803e6a4b-bc88-41db-b4b9-2f2d16cc46b8','初直省宿','朱翌','宋','宋诗','song-poetry','','[]','薄暮欣暑退，吏散列閑屋。',84,'全唐诗/poet.song.108000.json','["薄暮欣暑退，吏散列閑屋。", "冰廳冷如水，孤坐一巾幅。", "久絕青綾賜，僅免牀下伏。", "何嘗語丁寧，但愧頭蓄縮。", "頻年耗太倉，初夜費官燭。", "枕書倦已拋，夢蝶來更速。", "咍臺到天明，從人笑列宿。"]'),
('a2c416e1-2bc1-4146-b59e-57651b4d40a5','次韻胡明仲見寄','朱翌','宋','宋诗','song-poetry','','["\u8861\u5c71"]','去年玉笋班，仰視見櫑具。',120,'全唐诗/poet.song.108000.json','["去年玉笋班，仰視見櫑具。", "論事似陸贄，任事似裴度。", "今年起衡山，出守非不遇。", "床頭看周易，象在益長裕。", "解琴須更張，謀國乃疾固。", "要開天地爐，更使萬物鑄。", "可憐冰氏子，大似鐵鑪步。", "自謂樂於貧，公乃知其素。", "來刪城旦書，聊免吏部注。", "祝公早來朝，爲上寬北顧。"]'),
('3aebf94e-c0ea-4eb1-9f71-58a70054be25','送張巨山','朱翌','宋','宋诗','song-poetry','','[]','天方六月暑，君有千里行。',108,'全唐诗/poet.song.108000.json','["天方六月暑，君有千里行。", "相從苦不款，惜別難爲情。", "發軫子胥山，落帆石頭城。", "火雲午尤奇，水風晚更清。", "輝輝螢自燭，嘒嘒蟬爭鳴。", "今代太史氏，昔者蘭臺英。", "人如晉宋間，詩與顔謝并。", "吾君志恢復，求士出至誠。", "玉堂紫微省，待子來經營。"]'),
('5bd4e8b9-48f0-4ee2-af84-975b3c48e835','七月十四夜月分韻得明字','朱翌','宋','宋诗','song-poetry','','[]','澹澹烟覆渚，嗚嗚角收聲。',120,'全唐诗/poet.song.108000.json','["澹澹烟覆渚，嗚嗚角收聲。", "白毫萬丈光，下注千山傾。", "良夜三五時，玉樓十二城。", "皇天老眼開，碧湛雙瞳睛。", "窺我讀書窗，徘徊到天明。", "風從樹頭來，挾我入太清。", "飛螢轉蒿叢，熠燿徒營營。", "露氣下庭宇，秀爽凌冠纓。", "以茲無盡景，對此不平鳴。", "不如使雲遮，寂歷忘吾情。"]'),
('1ad67950-a8eb-4c4f-aa52-520c23d9f026','有感','朱翌','宋','宋诗','song-poetry','','[]','退之傳毛穎，步驟過遷固。',72,'全唐诗/poet.song.108000.json','["退之傳毛穎，步驟過遷固。", "當時不入眼，怪笑且驚怖。", "柳州極不平，裁書細說喻。", "浮雲蔽兩曜，憑虛亦暫駐。", "何傷黄道行，終古元氣聚。", "嗚呼古今一，吾其祕緗素。"]'),
('d0a35531-fbc2-4f66-a3df-4590b4e36fc7','曉上烏石灘','朱翌','宋','宋诗','song-poetry','','[]','急灘上水船，進寸輒退尺。',120,'全唐诗/poet.song.108000.json','["急灘上水船，進寸輒退尺。", "老夫敢穩坐，解衣起佐刺。", "凡我同舟人，有力俱不惜。", "已濟各相賀，可以正枕席。", "反觀順流人，如電亦如射。", "艱難與快意，等是時行役。", "月落東方明，雲收遠山碧。", "翩然兩白鷺，過眼已無迹。", "天地正爾寬，何苦自跼蹐。", "脫带且腰舟，歇我履一隻。"]'),
('23950a5b-5709-4aa9-989f-c65be336891c','章質夫帥廣時以酒六壺寄東坡於惠州書到而酒不至東坡有詩傳在人口思召作廣東漕翌適居曲江亦惠六尊且云吾家故事也爲作此詩','朱翌','宋','宋诗','song-poetry','','[]','西樞鎮番禺，紹聖之初年。',120,'全唐诗/poet.song.108000.json','["西樞鎮番禺，紹聖之初年。", "覆露落南人，雅意極周旋。", "六尊南海春，萬里羅浮仙。", "先生洗破觥，使者張空拳。", "五十有六字，至今星斗懸。", "君持澤國節，我賦囚山篇。", "欣然故事脩，要使家法傳。", "禮等百牢我，情均一觴天。", "夜來燈有花，不憂爨無烟。", "但恨語無味，何以追昔賢。"]'),
('4c89d235-8be8-45a6-9c2d-ff2047a0cdf0','三月旦行園','朱翌','宋','宋诗','song-poetry','','[]','我柳已飄絮，我筍亦上竹。',132,'全唐诗/poet.song.108000.json','["我柳已飄絮，我筍亦上竹。", "雪氈密蓋地，犢角橫入屋。", "茲辰略行園，喜色動眉綠。", "炎荒異中原，氣候少清淑。", "一日具四時，旦暮變寒燠。", "而我於此間，兀若蠶上簇。", "但愛草木長，遂使杖屨熟。", "喜甚得小詩，意斷語不續。", "尚可羊何和，不用唐衢哭。", "諸公幸無事，來不待休沐。", "牀敷三百棋，勝負任反覆。"]'),
('1833d49a-edf7-4542-96bf-cbbc534211d3','飯大涌泉入紫微洞洞乃余尋出','朱翌','宋','宋诗','song-poetry','','[]','山川有佳處，神物嚴守衛。',144,'全唐诗/poet.song.108000.json','["山川有佳處，神物嚴守衛。", "自非夙有因，孰敢發其秘。", "衆壑擁流泉，青間見白沸。", "洗我杖與屨，時作深入計。", "要須鄉道先，行與老人值。", "指我洞壑已，忽不知所詣。", "斸荒剗巨石，稍去眼中翳。", "豁然大厦開，位可百人置。", "嵌嚴一日出，自此沓遊騎。", "開山屬老夫，愛山必同類。", "甚畏長風寒，當暑皆斂袂。", "歡伯遂行登，相引入勝地。"]'),
('20d061b4-dc84-465c-b0d0-333621d97537','歲乙丑余年四十有九矣因誦太白四十九年非一往不可復之句次其韻','朱翌','宋','宋诗','song-poetry','','[]','南來不贏糧，隨身一竿竹。',96,'全唐诗/poet.song.108000.json','["南來不贏糧，隨身一竿竹。", "四年釣曹溪，溪水香可掬。", "求方駐隙駒，辟穀起黄獨。", "五十止欠一，何地可歸宿。", "今晨祖師前，一擲杯珓卜。", "去以六月息，來期七日復。", "往事一局棋，信手不必覆。", "吾生行休矣，自此生處熟。"]'),
('b9893aba-74af-41a6-8773-4416dd9a4ae9','題劉憲十君子軒','朱翌','宋','宋诗','song-poetry','','[]','北極元軒氣，受命惟爾獨。',144,'全唐诗/poet.song.108000.json','["北極元軒氣，受命惟爾獨。", "四方散子孫，萬里異閩蜀。", "戴譜六十一，岩谷無遺錄。", "段記三十九，冥搜出隠伏。", "世若不盡見，誰爲合其族。", "儒林老丈人，與世談無欲。", "開軒延十君，跪坐進三沐。", "高低列雲來，新舊間伯叔。", "團欒十家春，門戶各清肅。", "客至爲卷簾，贊名問寒燠。", "一見伯玉輩，遂使季子服。", "我欲作竹史，就君求品目。"]'),
('9e4346b8-4b95-4f25-8002-b71f7f7f3091','予居曲江五年今歲又暮慨然有感','朱翌','宋','宋诗','song-poetry','','[]','坐對研旁峰，卧閲屏上山。',84,'全唐诗/poet.song.108000.json','["坐對研旁峰，卧閲屏上山。", "一事不掛心，萬病方窮源。", "吾君禮南郊，吾母望北還。", "一歲幾得書，五年闕問安。", "是自取之爾，尚復何所言。", "手種庭下梅，花開聊喜歡。", "繫日既無術，縮地良獨難。"]'),
('a736e6a5-f57c-4806-bf71-f9bfc06f0a85','寄江東王端明','朱翌','宋','宋诗','song-poetry','','[]','德人大江南，壺歌溫玉帳。',144,'全唐诗/poet.song.108000.json','["德人大江南，壺歌溫玉帳。", "三歲豐年玉，民倚嵩華壯。", "政碑滿七尺，賜蓋高一丈。", "平生詩有聲，行與李杜抗。", "餘力到行草，妙合晉人樣。", "如此未賜環，頗復辜衆望。", "前時幕下生，今作倚門骯。", "故國動遠思，一夜清江漲。", "身如龜甲卷，書自魚乙放。", "南風造新凉，爽氣來疊嶂。", "壺觴得自引，茵鼎保無恙。", "願公介厚禨，中卣調秬鬯。"]'),
('cc04503a-132c-4f03-b946-005f732277e7','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其一','朱翌','宋','宋诗','song-poetry','','[]','戰休左觸氏，夢破大槐國。',84,'全唐诗/poet.song.108000.json','["戰休左觸氏，夢破大槐國。", "肝膽方一家，燕越非異域。", "是中路坦平，本自無降陟。", "乾坤有乾坤，無極復無極。", "海角盡東南，天門洞西北。", "萬里無寸草，何人不相識。", "亦有鼓刀兒，大烹舉銅鬲。"]'),
('c60fda23-85fe-4c4e-8dc8-ec9f49f52bef','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其二','朱翌','宋','宋诗','song-poetry','','[]','問學要根柢，文章忌雷同。',96,'全唐诗/poet.song.108000.json','["問學要根柢，文章忌雷同。", "字求反切當，義用訓詁通。", "縱之逼論劍，收之入檀弓。", "平生苦我心，不如作一農。", "林間瀟灑侯，川上赤鯶公。", "姑從賢者樂，勿笑鄙夫空。", "秋宵引佳月，暑晝追凉風。", "如此了一生，我其塞上翁。"]'),
('63d20dff-499d-4f96-b361-b5b6c1c76d5d','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其三','朱翌','宋','宋诗','song-poetry','','[]','戲語隴頭子，與若本等夷。',96,'全唐诗/poet.song.108000.json','["戲語隴頭子，與若本等夷。", "朱紫强包裹，本非我所宜。", "失脚落番山，杳杳隨風吹。", "將買二頃田，樹以枳棘籬。", "還我本來面，度今正其時。", "此策我自决，欲問其從誰。", "譬彼沈疴人，忽然飲上池。", "窮命可抵虎，寧畏山林魑。"]'),
('d2cce229-c165-4d06-8a0e-2ca15830a5e5','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其四','朱翌','宋','宋诗','song-poetry','','[]','老火已退師，寓客不憂瘴。',60,'全唐诗/poet.song.108000.json','["老火已退師，寓客不憂瘴。", "靜坐窺物理，一一見情狀。", "用起舉拂子，功成卓拄杖。", "五行更主事，衰絕變生王。", "此身屬造物，窮健勝美恙。"]'),
('04e7a5b3-aa08-4d46-99b6-3dffe6eb5f67','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其五','朱翌','宋','宋诗','song-poetry','','[]','厭晴思滴瀝，閔雨思開霽。',72,'全唐诗/poet.song.108000.json','["厭晴思滴瀝，閔雨思開霽。", "姑欲快吾私，豈暇計豐歲。", "身如姑射山，物物無疵癘。", "可笑建除家，卜日論開閉。", "堂堂百年中，顧已閲半世。", "徭蜑且友朋，百粵即魯衛。"]'),
('fb454d7d-2e41-44d6-8de8-62c021ae5825','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其六','朱翌','宋','宋诗','song-poetry','','[]','子房憫濁世，意欲一洗爲。',84,'全唐诗/poet.song.108000.json','["子房憫濁世，意欲一洗爲。", "五日老人約，何乃數後期。", "功成去學仙，辟穀從清羸。", "豈不知自苦，反覆加深維。", "志士極鑽仰，堅高今益彌。", "是爲萬世法，何止帝者師。", "寧知取履時，幾欲真毆之。"]'),
('fdb2edaa-9311-4307-9e13-9cabfe954789','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其七','朱翌','宋','宋诗','song-poetry','','[]','茲辰馭北風，所至有東道。',84,'全唐诗/poet.song.108000.json','["茲辰馭北風，所至有東道。", "把袂問浮邱，餽芝走商皓。", "著裙拜木公，獻寶出富媼。", "氣平四大和，以此可却老。", "長生等終古，彭祖是亦夭。", "有客詣理窟，相過或談妙。", "再拜有所乞，乞我如瓜棗。"]'),
('7454a072-4400-4f3a-b58b-d94c70703350','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其八','朱翌','宋','宋诗','song-poetry','','[]','南來走炎荒，北歸定尋思。',96,'全唐诗/poet.song.108000.json','["南來走炎荒，北歸定尋思。", "一生困坎壈，憂患真吾師。", "堂中木上座，萬里唯爾隨。", "方幸得良喜，那肯懷秋悲。", "但令今可行，勿愧論少卑。", "少時不解事，日日荒于嬉。", "投老又懶惰，得一或十遺。", "戲我過此生，造物真小兒。"]'),
('015bb24f-3016-45b7-b7e8-1504f778b0ab','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其九','朱翌','宋','宋诗','song-poetry','','[]','中夜念凉天，搔首坐待旦。',96,'全唐诗/poet.song.108000.json','["中夜念凉天，搔首坐待旦。", "北風鳴屋角，此懷忽凄斷。", "兒曹計伏臘，極力供井爨。", "憶昔冬來南，骨肉遣星散。", "念茲豈人爲，稍定理絲亂。", "呻吟裘氏地，皆是儒與緩。", "往語執金剛，勉力守門閈。", "倒囊留一錢，且免用鞭算。"]'),
('2c113e6d-9ce7-4bb7-bb77-d6a0a4c86735','十月旦讀子美北風吹瘴癘羸老思散策之句初寮嘗作十詩因次其韻  其一○','朱翌','宋','宋诗','song-poetry','','[]','囚山無他謀，治生出下策。',72,'全唐诗/poet.song.108000.json','["囚山無他謀，治生出下策。", "載之百漏船，吹以無孔笛。", "一飽久定矣，誓不爲欣戚。", "家山天一方，何地休行役。", "天其調伏予，中歲遭遠謫。", "養成一牯牛，露地見純白。"]'),
('ce8b2f96-73f1-4461-af28-57b20be88a66','寄無錫諸蔣','朱翌','宋','宋诗','song-poetry','','[]','夜帆起奔牛，烏竿鳴五兩。',108,'全唐诗/poet.song.108000.json','["夜帆起奔牛，烏竿鳴五兩。", "百年幾寒暑，兩歲五來往。", "竟不到惠山，閑日真難享。", "聞道山中泉，煮茗蒙珍賞。", "當年京浙遞，不洗牛李黨。", "故人在邑中，乃漢三徑蔣。", "欲擊月下門，正想鼻雷響。", "茲山君常到，此約吾又爽。", "且復卜後來，歸程一陽長。"]'),
('fce8a3db-abfc-4b28-846f-506e11a596e6','王承可有招隠黄龍之意','朱翌','宋','宋诗','song-poetry','','[]','通途無寧軌，世網闊遮邏。',168,'全唐诗/poet.song.108000.json','["通途無寧軌，世網闊遮邏。", "九遷食肉榮，一餉在堂賀。", "泥深迹逾深，時過事亦過。", "要之鐘鼎飽，不及薇蕨餓。", "吾知此理明，甘作蟻旋磨。", "丈夫當勇决，勿使良便蹉。", "黄龍百丈間，山圍天幾大。", "往丐一椽茅，撫枕得高卧。", "不能賡梁噫，且復繙屈些。", "賣藥足生理，故是伯休那。", "當年白鳥盟，肯爲青衫破。", "微官亦漫爾，棄去不啻唾。", "王子里中人，到處成穩坐。", "儻不食前言，扁舟在公左。"]'),
('a732abb7-22ea-4223-8513-06ec0d92e660','羅巨濟闢學之西序爲軒以奉板輿之樂余名之曰難老軒','朱翌','宋','宋诗','song-poetry','','[]','龜息六用藏，禽戲兩翼張。',156,'全唐诗/poet.song.108000.json','["龜息六用藏，禽戲兩翼張。", "俯仰何自苦，要與宇宙長。", "深山具竈火，煮沙烹硫黄。", "此又出下策，中乾外徒强。", "我有不朽計，事具泮水章。", "佳哉羅江東，意師張曲江。", "重席坐日永，脫屨來雁行。", "舉盞醉六經，抵掌談三王。", "青雲去一蹴，壽域開八荒。", "始知吾道中，大有却老方。", "以此施其母，何疑壽而康。", "煌煌忘憂花，秀色迎朝陽。", "願子多釀酒，容我時登堂。"]'),
('f0735875-288d-4bcf-b348-22967e747f86','徑山白虎寺詩','朱翌','宋','宋诗','song-poetry','','[]','繞郭尋好山，直北得覩徑。',120,'全唐诗/poet.song.108000.json','["繞郭尋好山，直北得覩徑。", "一重復一掩，間度略彴峻。", "溪聲出左方，環玦步相應。", "萬木儼扶持，四山擁清潤。", "高疑星可摘，况乃斗之分。", "諸公恨到晚，六月宜問信。", "頗聞開山老，說法起衆病。", "坐受於菟降，了不懷寸刃。", "山僧詫神通，辯口紛若磬。", "我豈必勝哉，渠自有佛性。"]'),
('4e5edfb9-eccd-43d4-b8bc-c01687b0af7d','告春亭詩','朱翌','宋','宋诗','song-poetry','','[]','東皋有佳致，中夜雨一犁。',72,'全唐诗/poet.song.108000.json','["東皋有佳致，中夜雨一犁。", "喜笑作春聲，麥塊青欲齊。", "淺瀨發清響，陳根出新夷。", "紅情顔未破，翠顰眉上低。", "練巾已堪岸，藜杖始一携。", "殷勤遺好音，胡盧來勸提。"]'),
('a798ac05-81e9-41e7-9fab-6f01489b521a','送鄭公績赴試金陵  其一','朱翌','宋','宋诗','song-poetry','','[]','庭槐著老花，佳興渺澄江。',72,'全唐诗/poet.song.108000.json','["庭槐著老花，佳興渺澄江。", "束書望故國，飛帆響篷窗。", "白袍看先登，唾手築受降。", "從風靡彊燕，舉火燭老龐。", "秋天鴻鵠高，驚到中疊雙。", "閨人侈宵占，玉蟲綴燈缸。"]'),
('8026209f-9c21-462a-8ba2-cfc1f8ef1c7d','送鄭公績赴試金陵  其二','朱翌','宋','宋诗','song-poetry','','[]','君到洗沐已，蠟屐款北山。',72,'全唐诗/poet.song.108000.json','["君到洗沐已，蠟屐款北山。", "吾祖山中人，凜然千載顔。", "其旁馬鬣封，近去龍衮間。", "通鑑恰施行，新經宜少刪。", "世上有公議，渠自明忠姦。", "物情有報復，天道則好還。"]'),
('338a1050-351e-4a05-a51d-6d8ff77af8bf','送鄭公績赴試金陵  其三','朱翌','宋','宋诗','song-poetry','','[]','昨日天子詔，痛念并州兒。',72,'全唐诗/poet.song.108000.json','["昨日天子詔，痛念并州兒。", "儻有長轂動，何憂折箠笞。", "似聞當宁歎，頗牧今何之。", "豈惟一方痛，其勢又類腓。", "策士仍三年，側席收六奇。", "誰當挽天河，洗出中興碑。"]'),
('cd1ce06c-eaef-45f7-86b6-d2b31a3115b3','送鄭公績赴試金陵  其四','朱翌','宋','宋诗','song-poetry','','[]','筆端忘杻械，舌本貴溫潤。',72,'全唐诗/poet.song.108000.json','["筆端忘杻械，舌本貴溫潤。", "明明獲麟書，作世大龜鏡。", "哀哉束高閣，斯文久不勝。", "皇天開老眼，牽復首拜命。", "秋來舉子場，誰領斯文印。", "向來鍼膏肓，必古司農鄭。"]'),
('2641eed7-6c3b-4f87-985a-ad595842d050','送鄭公績赴試金陵  其五','朱翌','宋','宋诗','song-poetry','','[]','念我答颯久，區區勞此生。',72,'全唐诗/poet.song.108000.json','["念我答颯久，區區勞此生。", "借屋就瞿曇，長湖繞廂瀠。", "未了文字債，截蒲坐縱橫。", "天公喜相我，貺以秋風清。", "他年載兼兩，策勳首短檠。", "饑吟愧峨冠，誰知此心傾。"]'),
('62fe2764-2bd4-4827-a8d8-4c8fd4e6cf45','送鄭公績赴試金陵  其六','朱翌','宋','宋诗','song-poetry','','[]','孤城挾龍虎，盤礴納萬象。',72,'全唐诗/poet.song.108000.json','["孤城挾龍虎，盤礴納萬象。", "馮夷遵節制，旦暮過稽顙。", "君今搦寸毫，意與孤鴻往。", "雄豪攬千古，光彩發萬丈。", "憶昨吏三年，到今餘夢想。", "古寺壁間名，勞君拂蛛網。"]'),
('a9b79d86-4202-4c99-8c74-5cb962b7648e','送鄭公績赴試金陵  其七','朱翌','宋','宋诗','song-poetry','','[]','我缾無儲粟，世累如綴纓。',72,'全唐诗/poet.song.108000.json','["我缾無儲粟，世累如綴纓。", "讀書寡見功，一飽不可營。", "鱗差四百指，習慣啼饑聲。", "天豈私貧我，客氣略已平。", "安能事計然，且復師淵明。", "儻有故人問，但如詩所稱。"]'),
('82de5f56-3350-44f5-8a8c-a03abd3eeca5','送鄭公績赴試金陵  其八','朱翌','宋','宋诗','song-poetry','','[]','高軒過我數，相對心跡清。',72,'全唐诗/poet.song.108000.json','["高軒過我數，相對心跡清。", "共乘殿角凉，劇談新月生。", "稍作蓮芡費，久絕壺觴傾。", "告我買夜航，襆被催宵征。", "秋晚破敵歸，連營稍休兵。", "青雲付一蹴，齊晉多世卿。"]'),
('fbc9455b-8a67-430f-bd75-b1697825477c','豹隠軒詩','朱翌','宋','宋诗','song-poetry','','[]','金錢暈花山中奇，七日霧雨人不知。',96,'全唐诗/poet.song.108000.json','["金錢暈花山中奇，七日霧雨人不知。", "一朝躍出從於菟，毛羣驚駭光陸離。", "釣竿在手身在野，未用聲名動天下。", "久幽則見理則然，世間豈有終藏者。", "道人見笑皮爲災，羔裘要袖孰剪裁。", "男兒獨患無文爾，聖世何憂不遇哉。"]'),
('c7a1ac8f-05f2-467e-bf09-d696742f3ca1','羣玉亭','朱翌','宋','宋诗','song-poetry','','[]','泗濱石窟如蟻族，巧匠琢山如琢木。',208,'全唐诗/poet.song.108000.json','["泗濱石窟如蟻族，巧匠琢山如琢木。", "不問人家與官舍，軒窗隨分作巖谷。", "符離城東石更多，天劃神刓相倚綠。", "當年來過玉局翁，拄杖敲門步幽麓。", "翼然危屋誰所興，賜以嘉名號羣玉。", "翁家自有小仇池，壺中九華伴孤獨。", "經行趣尚絕世姿，醜好例皆蒙紀錄。", "銀鈎爛爛照無窮，走馬來看僵立僕。", "是時官梅香正闌，亦有海棠紅映肉。", "老翁蓋棺二十年，世上遺編數遭獄。", "只今見字如見人，滿眼清風亂庭竹。", "想當入海期汗漫，雲車屢下仙山曲。", "仙山縹緲虛無間，我欲憑之兩黄鵠。"]'),
('3163f26e-fb18-4e75-9626-7b3559ddaa7b','大雪','朱翌','宋','宋诗','song-poetry','','[]','漢時長安雪一丈，少陵有詩不吾誑。',240,'全唐诗/poet.song.108000.json','["漢時長安雪一丈，少陵有詩不吾誑。", "今年廣陵雪一尺，忍寒長作縮龜狀。", "從來窮巷說多泥，自是泥深勞拄杖。", "閉門不出動經旬，出門無路將何向。", "故人乃遺咫尺書，遠祝長鬚問無恙。", "濕薪如桂米如珠，有突不黔旦逾望。", "但携古鼎燒黄連，香穗流珠凝碧帳。", "𡷾崒窗間石數峰，氣凌太華嵩衡上。", "黄楊冬青壓餘滋，碧幢羽蓋排仙仗。", "蒿廬頼有此清絕，興來何用山陰訪。", "飛鴻似带燕山書，重冰怕結黄河浪。", "玄冥得意愈自嬌，歲律回春未全壯。", "吾君曲軫天下寒，語到三軍真挾纊。", "自憐難備絕域使，規模但可山中相。", "起來舉手祝羲車，何日金篦開眼障。"]'),
('195b4d27-c3d6-4328-af5c-05a19c819750','溪南大雪示常子正','朱翌','宋','宋诗','song-poetry','','[]','王者有德琪樹生，兵馬欲洗銀甕出。',96,'全唐诗/poet.song.108000.json','["王者有德琪樹生，兵馬欲洗銀甕出。", "天將以寶奠中原，何用真如傳恍惚。", "沙寒汀冷鷺啄冰，藻暖餌香魚近罾。", "梅花抱蕊不肯吐，斂衽且讓天花升。", "朱門歌呼正圍妓，江上獵圍飛鐵騎。", "惟有書生無所爲，下帷煮茗候湯沸。"]'),
('e8f46563-ae0e-471f-8dc1-1de62b505206','用禁物體書雪','朱翌','宋','宋诗','song-poetry','','[]','宵分獵獵風翻幃，平明漫漫雪擁扉。',176,'全唐诗/poet.song.108000.json','["宵分獵獵風翻幃，平明漫漫雪擁扉。", "高妝老樹枝不舉，深壓野麰根漸肥。", "削平履迹頃刻盡，吹落楊花從來稀。", "饑烏大有在陳厄，循階入戶冷不飛。", "我曾倚頼東風暖，驅兒出市典衲衣。", "不料玄冥賈餘勇，小窗無地逃寒威。", "起來磚爐薦軟火，敢營肉陣張妓圍。", "認香尋梅亦不惡，敲冰煮茗寧皆非。", "掃除習氣幾時了，忍寒琢句聲益微。", "東坡先生六一老，當年格法誰遵依。", "不量吾力效跛蹩，從今望炙晴簷暉。"]'),
('bf3ce345-d19f-4642-b046-3853b3a58382','韓幹二馬圖','朱翌','宋','宋诗','song-poetry','','[]','飛龍翔麟夜不關，房星之精下人間。',176,'全唐诗/poet.song.108000.json','["飛龍翔麟夜不關，房星之精下人間。", "一鳴墮地勢千里，四十萬匹中如山。", "皇天生此意何在，天意有在平百蠻。", "百蠻款塞皆稽首，干戈包盡於菟斑。", "剪成三鬃代官字，濯之太液登王閑。", "紫壇謁天五使出，玉輅扶日雙輪還。", "寶鞭不用繡韉穩，扇筤前開曲蓋彎。", "方知徐行備天仗，絕勝疾走周人寰。", "開元距今四百載，人物風流無一在。", "如何兩驥今尚存，好手傳神能不壞。", "請從此畫究規模，便見當時似三代。"]'),
('48ea0d44-f65e-430f-b4c9-1560e78af85c','人日雪','朱翌','宋','宋诗','song-poetry','','[]','天公號令今年早，阿香動地連催曉。',147,'全唐诗/poet.song.108000.json','["天公號令今年早，阿香動地連催曉。", "今朝纔及七日人，却見長空六花擾。", "我獨磚爐坐畫灰，扶杖出門愁屐倒。", "細挑生菜羹鼎香，落盡梅花妝額巧。", "詩成思發在花前，更願晴多怕晴少。", "君不見貞觀有道幾成康，誰其致此唐文皇。", "一時獻納盡豪傑，鄭公臣徵尤激昂。", "當年入見適此時，見謂人日宜相當。", "有如此人當此日，整頓乾坤纔頃刻。"]'),
('657c4870-eaee-49c1-8083-b99c91fab91f','夜夢與羅子和論藥名詩','朱翌','宋','宋诗','song-poetry','','[]','鑽破故紙我拙計，該貫衆史子得意。',144,'全唐诗/poet.song.108000.json','["鑽破故紙我拙計，該貫衆史子得意。", "籤排百部象齒懸，陟釐萬張蠅頭字。", "分甘遂如百兩金，作苦躭成五車記。", "地錦天花出妙機，瓊田水英生爽氣。", "詩成欲度甫白前，冠彈請繼王陽起。", "天門冬夏鳶尾翔，香芸臺閣龍骨蛻。", "任真朱子老無用，得時羅君政如此。", "今宵月白及風清，想君不作呼盧會。", "泉石膏肓肯過予，飲量定能加五倍。"]'),
('14e92829-646d-4234-8771-d2f2bf2b159e','吳道子華清宮圖','朱翌','宋','宋诗','song-poetry','','[]','霜清十月天無風，行宮縹緲祥雲中。',176,'全唐诗/poet.song.108000.json','["霜清十月天無風，行宮縹緲祥雲中。", "重重繡嶺光相通，莊嚴具足無遺功。", "泉鳴三湯春濛濛，合歡皂莢雙垂紅。", "人間塵垢一洗空，玉聲璆然出房櫳。", "鸞吟鳳舞紛層空，豈不大勝遊月宮。", "向非道子妙絕筆，那見開元全盛日。", "槎牙老木青銅柯，坡陀巨石蒼玉質。", "石言木應若何聞，阿房興廢纔頃刻。", "乃知吳生有深意，一時心事能貌出。", "臣非丹青好畫師，臣以畫諫乃其職。", "此山此事姑置之，此畫當今須第一。"]'),
('b5c6d704-72ad-4fe7-8dfe-be12752398e2','觀獵會圖','朱翌','宋','宋诗','song-poetry','','[]','一日射雉六十三，命中要是人所難。',112,'全唐诗/poet.song.108000.json','["一日射雉六十三，命中要是人所難。", "一日射虎三十六，驍勇無前誰不伏。", "沙平草軟雪泥乾，手拓弓弦腰兩鏃。", "祥麟選馬捷若龍，翻身已墮雙飛鵠。", "拜賀將軍箭有神，摩旗拍鼓轟相逐。", "錦褾大袖掛虛堂，勇夫視之心發狂。", "不如緩带氈車上，舉酒割鮮殊不忙。"]'),
('b09cd5ce-b2d8-40e5-a367-2bf9ee021ecc','送硯與周宰','朱翌','宋','宋诗','song-poetry','','[]','巧匠斵山取山骨，媼神拱手不敢惜。',240,'全唐诗/poet.song.108000.json','["巧匠斵山取山骨，媼神拱手不敢惜。", "因隆作防漥作池，以金爲聲玉爲質。", "藉以綈衣便挈携，置之烏皮長拂拭。", "憶昨隨計西入關，太學三年同寢食。", "晨昏綴緝困蠅頭，歲月磨研取雞肋。", "時來偶題千佛經，吾自無功子何得。", "祇今懶慢大可笑，身外了然無一物。", "經時不脫管城帽，子宜不賜湯沐邑。", "我今容子乞身去，却到安宜宰君室。", "宰君真是瀟洒人，文章機杼乃自出。", "陳玄毛穎費追呼，子堅而厚宜比德。", "從茲去給上方札，便當入珥螭坳筆。", "切勿勸草封禪書，亦莫上獻開邊策。", "願君發明錯與誼，昨奏條畫今所急。", "忠言讜論聞四方，硯乎汝爲不失職。"]'),
('95b6b82e-49b3-4ead-a4ae-b6b11ed8dbfd','簡宗人利賓','朱翌','宋','宋诗','song-poetry','','[]','昔時桐鄉漢九卿，家在淮南天一柱。',208,'全唐诗/poet.song.108000.json','["昔時桐鄉漢九卿，家在淮南天一柱。", "石麒麟冷一千年，子孫不敢去墳墓。", "我之曾高主宗盟，昭穆亦與公家敘。", "不容妄繼酇侯蕭，何嘗敢掘城南杜。", "深山大澤塹劫灰，甲第名園走狐兔。", "飄零直見似人喜，何况乃與吾宗遇。", "爲善本求鄉里稱，浩歎正坐儒冠誤。", "出參留守入坐曹，抑亦爲此微祿故。", "灊山山高灊水深，眼前誰作藩籬護。", "心隨大信小信潮，夢遶長亭短亭路。", "生涯舊欠錢一囊，歸裝或有經五庫。", "今子新從彭澤來，歸去來兮幾時去。", "一杯且遣客枕安，百尺竿頭同進步。"]'),
('85d863a3-c98e-4fe3-b8d5-0c42393132a7','觀諸公打馬詩','朱翌','宋','宋诗','song-poetry','','[]','酒酣侑坐展博局，分曹並進角馬足。',176,'全唐诗/poet.song.108000.json','["酒酣侑坐展博局，分曹並進角馬足。", "過關驗齒出天衢，入關未掩繞日軸。", "十驥并驅縱來往，一將折箠制起伏。", "擊前疊後看騰驤，避塹守狹良局促。", "緩時必若出門殿，妙處正須蟻封逐。", "孫臏能令田忌勝，諸人徐賀塞翁福。", "障泥在前解則行，杜蘅可采带宜速。", "莫疑檀溪墜三丈，終使青雲成一蹴。", "吾家款段乃如狗，敢上夷塗陪驥騄。", "但能書與尾而五，未免以策數曰六。", "歸歟秋滿華山陽，苘麥倍收連苜蓿。"]'),
('8fa50cbe-c43b-4b78-9efc-f4b765df42a7','聞鄰舟琵琶','朱翌','宋','宋诗','song-poetry','','[]','檣烏逐風不停飛，尾燕掠水東復西。',128,'全唐诗/poet.song.108000.json','["檣烏逐風不停飛，尾燕掠水東復西。", "蠻弦金撥竊私語，行客轉頭聲更悲。", "擾擾雲吹寶鬟綠，新妝半隠朱簾曲。", "無限柔情指下生，誰道彈絲不如竹。", "谷兒指法來帝城，曹供奉傳新曲名。", "香山居士家有此，何况更聞江上聲。", "路轉溪回雙櫓咽，彈盡胡笳十八拍。", "山頭日落暮潮平，一带荷花自秋色。"]'),
('73ecbce0-6119-4bd5-b9fb-e5aaf1d315f6','石斛栽蓮','朱翌','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','數夕一夢吳淞江，兩槳飛度荷花鄉。',112,'全唐诗/poet.song.108000.json','["數夕一夢吳淞江，兩槳飛度荷花鄉。", "刳中山骨泥數斗，趁雨屈盤三節藕。", "鏡面光寒溢井花，四顧無人下渴鴉。", "老翁真箇兒童似，我非韓公亦兒戲。", "綠莖亭亭忽獨立，簾疏不隔香直入。", "宛若船舫坐促膝，遂使江湖在方尺。", "雖無太華藕如船，定有廬山房似笠。"]'),
('ec97ff16-1c67-49e0-8808-c0932d181fd5','端午觀競渡曲江','朱翌','宋','宋诗','song-poetry','','[]','楝花角黍五色縷，一弔湘纍作端午。',144,'全唐诗/poet.song.108000.json','["楝花角黍五色縷，一弔湘纍作端午。", "越人哀君檝迎汝，呼聲動地汗流雨。", "魚蝦走避無處所，小試勒兵吾有取。", "樓船將軍下潢浦，佽飛射士彍强弩。", "大堤士女立如堵，樂事年年動荆楚。", "却憶金明三月天，春風引出大龍船。", "二十餘年成一夢，夢中猶記水鞦韆。", "三軍罷休各就舍，一江烟雨朱簾夜。", "隠隠灘聲細卷沙，沙淺灘平雙鷺下。"]'),
('c45c34f6-c8d8-4a9c-9520-8e619b0397ab','南園用端中韻','朱翌','宋','宋诗','song-poetry','','[]','有韓太尉淮陰家，十年種木今開花。',160,'全唐诗/poet.song.108000.json','["有韓太尉淮陰家，十年種木今開花。", "松陰漸可張翠葆，桃蹊久已蒸紅霞。", "早來雨過著芒屩，曲沼鏡平清見沙。", "道人從我似支遁，公子立名非務華。", "劇談坐致千歲日，默誦初無一字差。", "主人負重守且將，一手撚箭腰黄蛇。", "因來小集休沐地，何時共聽歸來笳。", "饑腸欲餌桄榔粉，香身要采毗陵茄。", "凉風翛翛引佳月，歸興忽起從棲鴉。", "誰憐老我夜不寐，兒曹見祝無多茶。"]'),
('4c386899-77fd-4105-9a98-5c820cbedc02','八月十四夜對月效李長吉','朱翌','宋','宋诗','song-poetry','','[]','雨江洗出揉藍天，結璘下鋪白玉筵。',80,'全唐诗/poet.song.108000.json','["雨江洗出揉藍天，結璘下鋪白玉筵。", "尾箕斗牛珠一穿，連暉接影墮我前。", "整襟危坐天地默，不知夜漏下幾刻。", "飛螢一點從外入，白露下濕桂子香。", "藍橋雲英正賣漿，金盤荔枝龍眼雙。"]'),
('4000476e-7c6c-49ec-982c-eb19145bb6ee','題校書圖','朱翌','宋','宋诗','song-poetry','','[]','我聞校書如掃塵，塵隨帚去輒隨有。',128,'全唐诗/poet.song.108000.json','["我聞校書如掃塵，塵隨帚去輒隨有。", "螢窗孤坐志不分，帝虎魯魚相可否。", "榻上諸公富貴人，安能辦此鉛黄手。", "綠柳啼鶑耳畔春，翠袖彈絲眼前酒。", "如何復窺蠹簡塵，又借管城公作帚。", "畫史畫名不畫實，潤色丹青傳不朽。", "我是瀛洲舊校書，揮汗磨鉛胝兩肘。", "當時萬一見此圖，諸郎不免涎垂口。"]'),
('0e5900aa-bb50-4f53-819f-c970106b35eb','寄張子公','朱翌','宋','宋诗','song-poetry','','[]','政和聖人拜賢書，陛臚春曉傳天衢。',208,'全唐诗/poet.song.108000.json','["政和聖人拜賢書，陛臚春曉傳天衢。", "集英殿下八百衆，一時如公此策無。", "萬口一詞期第一，擢之第三衆不懌。", "諸公貴人願相識，戒閽走馬要君入。", "君言不媚有藥石，國子先生乃例得。", "我亦跪起就穿執，妄意得蒙子公力。", "六年一別安宜北，憂患壓人氣不出。", "聞之減米符離日，首陽激貪用一律。", "嗚呼四海鳴鋒鏑，白晝豺狼恣吞吸。", "帝在奉天頗倉卒，絲綸政渴宣公筆。", "緘情遠附雪原鶺，願公來扈巡南蹕。", "平泉松菊凌霜碧，伐叛亭成燕賓戚。", "起居因書問晨夕，宜爲蒼生調鼎食。"]'),
('b9ccd35f-9c95-47e5-b72c-3fd882d36f6c','方提幹有端石硯池狹不能容水予携以歸令匠者廣之疑其不返也書來見督以詩解嘲','朱翌','宋','宋诗','song-poetry','','[]','端溪有石紫玉潤，未遇良工失追琢。',192,'全唐诗/poet.song.108000.json','["端溪有石紫玉潤，未遇良工失追琢。", "眇哉池面劣容指，水至不能容一勺。", "灊山道人請歸治，要使墨池少開拓。", "每煩健步遠來徵，事必不然空臆度。", "子如不忘一塊頑，予亦敢負千金諾。", "會令合浦看還珠，豈忍荆山長抱璞。", "一毫不敢我非有，萬頃難量子宜學。", "聞道年來好說禪，初機最忌多貪著。", "認爲己有已大謬，久假不歸非爽約。", "均之在此猶在彼，弟兄四海何曾各。", "笑傾萬斛付江流，所有盡空心境廓。", "請對使者一斧碎，與公少解貪癡縛。"]'),
('9a8e5e99-b043-4b17-bfe2-098fdc7f347e','謝人寄硯','朱翌','宋','宋诗','song-poetry','','[]','老矣捐書卧看屋，尚記姓名供簡牘。',144,'全唐诗/poet.song.108000.json','["老矣捐書卧看屋，尚記姓名供簡牘。", "倉皇去越著南冠，頭已如蓬口生醭。", "無因可結孔方交，有藥唯醫管城禿。", "新凉稍與燈火親，學字頗慚蛇蚓曲。", "羅紋重厚使守舍，銅雀不真非所蓄。", "敢遣良工開下巖，要使珍材過天目。", "君家舊物多錦藉，聲若鏘金眼鸜鵒。", "前者一見首重稽，回視他山真碌碌。", "公今遣一從我遊，謹當配以蟾蜍玉。"]'),
('6f6e7080-26a0-4f10-bc72-7f1404f597d8','諸公勸楚真叟應進士舉以詩勉之','朱翌','宋','宋诗','song-poetry','','[]','太祖皇帝龍飛初，君家樞密推日車。',160,'全唐诗/poet.song.108000.json','["太祖皇帝龍飛初，君家樞密推日車。", "一時事載太史筆，九廟畫展功臣圖。", "昭陵取士極妙選，乃孫應詔從諸儒。", "威如草木部刺史，屢進藥石諫大夫。", "誰知冷落百蠻裏，忽見其後清而腴。", "讀書過眼似皎月，裁詩出手爭秋蕖。", "諸公力請舉進士，駢四儷六子有餘。", "三經新義未改科，一代元老出此塗。", "要令我才必有用，不憂此口無以餬。", "他年上國與計偕，看日五色傳天衢。"]'),
('4a92d07c-f1ce-4961-a99a-61ad800e0d3b','謝人惠淺灘一字水圖','朱翌','宋','宋诗','song-poetry','','[]','風行水上初如織，任使蕩雲高沃日。',160,'全唐诗/poet.song.108000.json','["風行水上初如織，任使蕩雲高沃日。", "屏翳歇去馮夷歸，本體湛然無損益。", "風本無形不可畫，遇水方能顯其質。", "畫工畫水不畫風，水外見風稱妙筆。", "清泉道人乃了此，筆下淵源心自得。", "斜斜一字淺可揭，渺渺橫灘晚尤急。", "規模上繼蜀兩孫，妙處直度吳諸戚。", "老夫老矣不觀瀾，但愛漪漣才咫尺。", "面牆注目風蕭蕭，漁浦西興待晚潮。", "縱貧那肯拆波濤，還渠并州快剪刀。"]'),
('06de2c24-af71-4eec-bae0-cc0370151b9e','過秀野亭觀趙昌花','朱翌','宋','宋诗','song-poetry','','[]','牡丹酴醾送春歸，南風亦復吹戎葵。',152,'全唐诗/poet.song.108000.json','["牡丹酴醾送春歸，南風亦復吹戎葵。", "青女不瘦芙蓉肌，雪中山茶火爭輝。", "此開彼落相背馳，安得坐隅皆見之。", "劍南老人來解衣，好手不免如徐熙。", "蕭然四幅十二枝，規模一出衆史卑。", "妙處天授非人爲，右軍字畫少陵詩。", "後來縱好難並馳，傳觀左右識者誰。", "愛畫入骨吾一癡，惜哉不獲坡谷題。", "何妨擾擾俗眼疑，秀野前後花成帷，按圖求之君自知。"]'),
('65a01a39-df61-45fd-94af-6815b5367bb0','簡韓仲朋','朱翌','宋','宋诗','song-poetry','','[]','老范好客老更豪，長恨無人陪痛飲。',112,'全唐诗/poet.song.108000.json','["老范好客老更豪，長恨無人陪痛飲。", "我嘗解带坐南軒，閉門投轄則大窘。", "小韓云是故人子，酒量直須吞萬頃。", "昨宵風雨送秋來，雨罷月林散清影。", "想當一口吸西江，看撫朱絲移玉軫。", "誰將五斗爲解酲，蜾蠃螟蛉供一哂。", "野人無酒可留公，一酌山泉薦佳茗。"]'),
('6a69196b-879c-434f-bbb8-6274da80cbe5','謝方務德惠粟麥','朱翌','宋','宋诗','song-poetry','','[]','投閑閉門且穩坐，動輒有礙天難測。',160,'全唐诗/poet.song.108000.json','["投閑閉門且穩坐，動輒有礙天難測。", "錢神不肯赴招要，瘧鬼乘時作寒熱。", "要之貧困真我道，一一爲向兒童說。", "山中宿麥舊爲農，缾無儲粟今何拙。", "甑塵不掃爨未烟，米盡自從仁祖索。", "元英之孫陳義高，急遣樵青分粟麥。", "細舂落落簸珠圓，退磨紛紛飛玉屑。", "粥香恍若在僧坊，麵熟又將思水厄。", "從來藿食不謀國，饑即須餐困仍歇。", "笑殺多牛足穀翁，何用詩腸生錦襭。"]'),
('00038ece-407c-46e6-84f5-acf868f2ba18','耘村麥熟','朱翌','宋','宋诗','song-poetry','','[]','君不見五經紛綸井大春，不得已見陰將軍。',134,'全唐诗/poet.song.108000.json','["君不見五經紛綸井大春，不得已見陰將軍。", "將軍故爲設麥飯，推去不食言非誠。", "又不見劉懷慰作齊太守，廉吏籍中自稱首。", "邦人饋米不肯取，示以麥飯吾所有。", "我有郭內一畝田，带經荷耡願有年。", "今年麥熟始一飽，久饑客子俱來前。", "姓名久與市朝絕，將軍薄飯不吾設。", "亦不彊學劉公清，但使兒曹知稼穡。"]'),
('a240cc25-c32d-478d-bb81-aac89ab7809d','題孫倅面山軒詩','朱翌','宋','宋诗','song-poetry','','[]','舉頭直北看青山，低頭直下覷黄卷。',144,'全唐诗/poet.song.108000.json','["舉頭直北看青山，低頭直下覷黄卷。", "黄卷辛勤有時厭，青山於人保不變。", "山作主人我爲客，主人看客長不倦。", "今代風流潄石公，吏事直以儒雅緣。", "一丘一壑在胸中，塵土污人聊舉扇。", "開門抆拭舊題傍，坐與烏龍通一綫。", "近因秋雨聘此君，更倚歲寒爲外援。", "賤子與世多背馳，只有青山存半面。", "莫嫌剝啄時扣門，要是綈袍故人戀。"]'),
('c036502d-7774-426d-882d-597f6248b8f9','高風堂','朱翌','宋','宋诗','song-poetry','','[]','一溪之雲各爲雨，聊與蕭王分出處。',96,'全唐诗/poet.song.108000.json','["一溪之雲各爲雨，聊與蕭王分出處。", "亂山深處有生涯，三尺漁竿一枝艣。", "細讀懷仁輔義書，先生於世未嘗疏。", "我已飄然遺物去，斯言却以告司徒。", "參政樹碑頌遺德，舍人作堂詔無極。", "高風之高高幾何，下視烏龍六千尺。"]'),
('9e4e0c24-6580-4a4d-9763-c78c8657b80d','洞霄宮','朱翌','宋','宋诗','song-poetry','','[]','委委曲曲山九鎖，巍巍堂堂天一柱。',80,'全唐诗/poet.song.108000.json','["委委曲曲山九鎖，巍巍堂堂天一柱。", "靈官跨龍出洞來，仙人驅虎載箬去。", "泉流兩山鳴珮玦，夜壇星辰可手摘。", "世間何限真人祠，身未嘗到銜空結。", "一日來遊豈偶然，草中更識天荷葉。"]'),
('ac6d9a84-afc1-4adb-8b5b-096a5c1d237c','羅教授不赴真叟觀李花之約已而有詩次其韻','朱翌','宋','宋诗','song-poetry','','[]','廣文著書不窺園，刻杯以玉露以繁。',96,'全唐诗/poet.song.108000.json','["廣文著書不窺園，刻杯以玉露以繁。", "澹乎不躡俗士駕，雅意要令吾道尊。", "那知韓賦李有花，常以博士居四門。", "老夫却欲來不速，但恨人靜鐘鳴昏。", "明朝未必遽零落，往看花上春風喧。", "更語宗文與宗武，詩成入耳宜不煩。"]'),
('e17e45b7-0f04-42c0-82ed-e2e9d353b94d','賀陳內翰去非三首  其一','朱翌','宋','宋诗','song-poetry','','[]','聞道催宣召，傳呼入翰林。',48,'全唐诗/poet.song.108000.json','["聞道催宣召，傳呼入翰林。", "堂高初上玉，带重更垂金。", "煩悉周公誥，丁寧葛亮心。", "調元知有日，天意向君深。"]'),
('620e1577-1041-41f9-8cb7-c58f690546ac','賀陳內翰去非三首  其二','朱翌','宋','宋诗','song-poetry','','[]','夢獲生花筆，祥開視草儒。',48,'全唐诗/poet.song.108000.json','["夢獲生花筆，祥開視草儒。", "奉天專仰陸，元祐只傳蘇。", "蓮影光分燭，絲紋細結絇。", "禁中頗牧在，夙夜贊神謨。"]'),
('83c3e55e-dedb-41ff-b65d-e671de40350e','賀陳內翰去非三首  其三','朱翌','宋','宋诗','song-poetry','','[]','夜到甘泉捷，光摇建曉魁。',48,'全唐诗/poet.song.108000.json','["夜到甘泉捷，光摇建曉魁。", "唐家方再造，漢德已重開。", "太史書雲後，羣公賀雪回。", "十行寬大詔，早晚出銀臺。"]'),
('f5da9910-fae9-4fe8-8076-61c7d6eaffd4','出城','朱翌','宋','宋诗','song-poetry','','[]','少策經營飽，多方處置閑。',48,'全唐诗/poet.song.108000.json','["少策經營飽，多方處置閑。", "樵談消一日，野坐看千山。", "白鷺遠飛去，微雲時復還。", "展開新樂地，攻破舊愁關。"]'),
('34da7424-0567-4ac7-8273-4a156ffe63c5','城上觀月','朱翌','宋','宋诗','song-poetry','','[]','月上孤城早，山迎雉堞低。',48,'全唐诗/poet.song.108000.json','["月上孤城早，山迎雉堞低。", "四天浮沆瀣，萬瓦貯玻璃。", "松獵風聲北，江摇斗柄西。", "諸公宜款曲，吾且倚枯藜。"]'),
('99c5d5d1-a765-4d9d-bdcf-0ab8b80ac488','示葉令','朱翌','宋','宋诗','song-poetry','','[]','舟楫三吳客，江湖二月寒。',48,'全唐诗/poet.song.108000.json','["舟楫三吳客，江湖二月寒。", "交情元自淡，酒味莫嫌酸。", "日者坐何事，君乎能自寬。", "不來同一醉，何以解憂端。"]'),
('bc2dd780-0e59-4b3a-b842-511a587e7a53','示李令','朱翌','宋','宋诗','song-poetry','','[]','春色遽如許，春愁無柰何。',48,'全唐诗/poet.song.108000.json','["春色遽如許，春愁無柰何。", "看山連楚越，端坐惜羲娥。", "吾子頻相見，新詩苦未多。", "試穿一兩屐，從我上烟蘿。"]'),
('7db9880b-42a1-4305-948d-821b5bee046e','轎中坐睡','朱翌','宋','宋诗','song-poetry','','[]','飽食登長道，箯輿枕臂眠。',48,'全唐诗/poet.song.108000.json','["飽食登長道，箯輿枕臂眠。", "鼻間真栩栩，腹外亦便便。", "徙倚兩竿竹，咍臺四僕肩。", "忽然成小憩，放手即醒然。"]'),
('24b553f9-e15d-4e56-94a1-271a217c75d6','寄王承可','朱翌','宋','宋诗','song-poetry','','[]','籍甚王郎子，揚州一再逢。',48,'全唐诗/poet.song.108000.json','["籍甚王郎子，揚州一再逢。", "至今清夜夢，猶在笑談中。", "想見芙蓉句，空懷楊柳風。", "著鞭來不晚，聲價動諸公。"]'),
('c3f30c15-993b-42cf-865c-516928dbf2c6','寄葉應之','朱翌','宋','宋诗','song-poetry','','[]','人老江湖外，官拘簿領緣。',48,'全唐诗/poet.song.108000.json','["人老江湖外，官拘簿領緣。", "劇談嘗共夜，好句得先傳。", "行李無他阻，朝廷有闕員。", "相逢一笑喜，已種玉爲田。"]'),
('282e6b5b-34d0-4878-bbf0-601960ec8b70','寄符正民','朱翌','宋','宋诗','song-poetry','','[]','體力今何似，函書闕到門。',48,'全唐诗/poet.song.108000.json','["體力今何似，函書闕到門。", "匆匆緣不暇，負負復何言。", "此日忘疏遠，明公實見存。", "捫參懷蜀道，叱馭憶王尊。"]'),
('663d9a97-c3d5-46e1-8cf2-a5b2869c9bfd','五更不睡','朱翌','宋','宋诗','song-poetry','','[]','擂罷城頭鼓，膏凝燭下槃。',48,'全唐诗/poet.song.108000.json','["擂罷城頭鼓，膏凝燭下槃。", "窗留三尺月，纊挾五更寒。", "事事華巾結，年年紙帳寬。", "梅花正好在，青女莫摧殘。"]'),
('80ab516c-ab09-40f5-b8d6-54bc635b3751','曉出','朱翌','宋','宋诗','song-poetry','','[]','浩蕩乾坤曉，凄凉客路窮。',48,'全唐诗/poet.song.108000.json','["浩蕩乾坤曉，凄凉客路窮。", "小舟輕劈浪，宿霧密糊空。", "累重苦無飯，時危甘轉蓬。", "但聞淮上賊，不敢視江東。"]'),
('71859779-2956-431b-bee8-106e6ba722e4','初到曲江六首  其一','朱翌','宋','宋诗','song-poetry','','[]','度嶺三百里，携家五六人。',48,'全唐诗/poet.song.108000.json','["度嶺三百里，携家五六人。", "卜居依古寺，愛日向初春。", "時有逃虛喜，端無去客嗔。", "團欒何所作，不寐守庚申。"]'),
('ccfb514b-5119-483e-b09d-200c028f9f0c','初到曲江六首  其二','朱翌','宋','宋诗','song-poetry','','[]','昭代人無棄，遐方住亦堪。',48,'全唐诗/poet.song.108000.json','["昭代人無棄，遐方住亦堪。", "司分大火舍，官作世南男。", "守拙休心匠，忘憂縱手談。", "平生不喜閙，所欠一茅庵。"]'),
('a0359b01-4fa3-43c6-9919-a27a0be6b4a5','初到曲江六首  其三','朱翌','宋','宋诗','song-poetry','','[]','燈火光元夕，歌呼亦盡歡。',48,'全唐诗/poet.song.108000.json','["燈火光元夕，歌呼亦盡歡。", "欣聞雪霏白，愁失荔垂丹。", "老酒蓮花麴，甜魚藿葉槃。", "萬金書若到，便可解憂端。"]'),
('0a927513-51c6-42b5-8607-680cd771462c','初到曲江六首  其四','朱翌','宋','宋诗','song-poetry','','[]','嶺外山川最，天涯草木芬。',48,'全唐诗/poet.song.108000.json','["嶺外山川最，天涯草木芬。", "曾經五月狩，俱被一琴薰。", "韶石靜張樂，舜峰高出雲。", "真同適魯見，何異在齊聞。"]'),
('b3f4316d-09e9-4497-a05f-ea5fe6e660ae','初到曲江六首  其五','朱翌','宋','宋诗','song-poetry','','[]','草斷城頭路，春未履屢穿。',48,'全唐诗/poet.song.108000.json','["草斷城頭路，春未履屢穿。", "雨餘峰染黛，雲出嶺垂蓮。", "眼傍青林轉，愁來白鳥邊。", "中原好消息，問取此江船。"]'),
('b057e1c6-90e3-4d37-91fc-b78718d35cd1','初到曲江六首  其六','朱翌','宋','宋诗','song-poetry','','[]','嘉卉懷炎德，孤根幸斗臨。',48,'全唐诗/poet.song.108000.json','["嘉卉懷炎德，孤根幸斗臨。", "象蹄交綠潤，佛眼瞬紅深。", "含笑香飄坐，素馨嬌滿簪。", "老榕雖擁腫，六月十分陰。"]'),
('2b17005c-7db1-46ec-b674-5dbabe7a6a24','丙辰人日雨雪','朱翌','宋','宋诗','song-poetry','','[]','此地從來僻，今朝自古陰。',48,'全唐诗/poet.song.108000.json','["此地從來僻，今朝自古陰。", "五年猶作客，一飯敢虛襟。", "春色豈終閟，晨光宜早臨。", "國香無恙否，抱雪秀深林。"]'),
('531bd441-68da-4aa8-b347-48fab08ad7bc','有惠曾公逍遥樓字者','朱翌','宋','宋诗','song-poetry','','[]','蒲阪今灰燼，茲樓亦草萊。',48,'全唐诗/poet.song.108000.json','["蒲阪今灰燼，茲樓亦草萊。", "如何三字大，却到百蠻開。", "屋漏真能爾，霜嚴可畏哉。", "置之當座右，親手拂塵埃。"]'),
('a2813f02-b25a-421f-bdd3-14babaa05874','次韻胡明仲見寄二首  其一','朱翌','宋','宋诗','song-poetry','','[]','雙鳥鳴方盛，公今遂著書。',48,'全唐诗/poet.song.108000.json','["雙鳥鳴方盛，公今遂著書。", "浮雲供一掃，直筆用三餘。", "孔孟揚韓道，乾坤日月如。", "平生擊姦手，發蹤自桐廬。"]'),
('e62b921f-b472-48ea-bede-1dca3bfa2d2b','次韻胡明仲見寄二首  其二','朱翌','宋','宋诗','song-poetry','','[]','柳州非國語，意恐亂詩書。',48,'全唐诗/poet.song.108000.json','["柳州非國語，意恐亂詩書。", "去草絕根本，立言推緒餘。", "斷疑先近似，反己問何如。", "歲晚飄零甚，歸歟指敝廬。"]'),
('7662e29c-249b-4eb2-af84-1d20edbd24d0','歸自南華詩','朱翌','宋','宋诗','song-poetry','','[]','衆綠揚新楚，初晴中薄寒。',48,'全唐诗/poet.song.108000.json','["衆綠揚新楚，初晴中薄寒。", "行山無闊步，陟巘有遐觀。", "蕨紫拳猶小，松黄粉漸乾。", "無嫌一馬瘦，徑度兩重灘。"]'),
('c2621b26-3313-449e-8fcf-db566b087b27','南華具素飯烹茶詩','朱翌','宋','宋诗','song-poetry','','[]','頗有客倉卒，初無具咄嗟。',48,'全唐诗/poet.song.108000.json','["頗有客倉卒，初無具咄嗟。", "家貧難辦素，人衆不烹茶。", "此老來修供，茲辰並拜嘉。", "小船橫一笛，風引入荷花。"]'),
('09af6d6d-01f3-4bda-bf8a-65d07f4ab129','南華道中詩','朱翌','宋','宋诗','song-poetry','','[]','小市荒堤轉，湧泉春水慳。',48,'全唐诗/poet.song.108000.json','["小市荒堤轉，湧泉春水慳。", "頻經石角鋪，不上馬鞍山。", "橋斷衝泥過，松摧塞道艱。", "草鞋牢踏雨，更著一蓑還。"]'),
('35953339-ac2c-4ff2-a15a-ff69ed51a996','晨起','朱翌','宋','宋诗','song-poetry','','[]','曉日光穿戶，衡門起及晨。',48,'全唐诗/poet.song.108000.json','["曉日光穿戶，衡門起及晨。", "簷垂冰折柱，澗湧雪鎔銀。", "臘取一時樂，春期數日新。", "曝書仍曝背，自笑巧於貧。"]'),
('48d315d3-c6a8-40ed-b311-8ca65f5cb766','遣興','朱翌','宋','宋诗','song-poetry','','[]','客去抽書讀，愁來閉戶推。',48,'全唐诗/poet.song.108000.json','["客去抽書讀，愁來閉戶推。", "眼花因酒劇，書草更人催。", "怪石巧依竹，凈瓶香引梅。", "悠然鑑湖念，又向雁邊回。"]'),
('58f1f9fe-dab2-46c4-9c03-e1951095add6','次韻張巨山正月十日遊天竺','朱翌','宋','宋诗','song-poetry','','[]','欲飯雲邊寺，先尋湖上春。',48,'全唐诗/poet.song.108000.json','["欲飯雲邊寺，先尋湖上春。", "山川良是舊，歲月又更新。", "草長烟如積，梅晴粉自勻。", "久留知不可，暫過却須頻。"]'),
('9357ad7a-7e29-44d1-8ba2-39cad559846a','猗覺寮晚飯','朱翌','宋','宋诗','song-poetry','','[]','卒律葛答美，鉤輈格磔肥。',48,'全唐诗/poet.song.108000.json','["卒律葛答美，鉤輈格磔肥。", "翁川茶不媚，何氏酒今非。", "硯水添池淺，棋盤下子稀。", "姮娥憐我獨，未暮款窗扉。"]'),
('5dfc337f-0542-4744-91a0-8637a985b3c3','歸去來圍南鄰劉家菜圃近許闢路相通','朱翌','宋','宋诗','song-poetry','','[]','假道趨南浦，排牆度小溝。',48,'全唐诗/poet.song.108000.json','["假道趨南浦，排牆度小溝。", "仙人中謫李，鄰里外依劉。", "良友經時集，清貧覺我優。", "檳榔初不設，佳茗或相投。"]'),
('c4ac782c-cd48-46fe-ab4d-048a3732c0a8','雨晴吳李過園中','朱翌','宋','宋诗','song-poetry','','[]','聯璧來吾隠，交歡只賀晴。',48,'全唐诗/poet.song.108000.json','["聯璧來吾隠，交歡只賀晴。", "酌泉心不易，指李話平生。", "萬木翠光合，一池春水平。", "更詢消遣法，元自不容聲。"]'),
('b43b2834-effe-4d60-a86f-ca517aa8b8fa','告春亭  其一','朱翌','宋','宋诗','song-poetry','','[]','一丈寬鋤地，三重密蓋茅。',48,'全唐诗/poet.song.108000.json','["一丈寬鋤地，三重密蓋茅。", "分封鷗鷺境，拾翠芰荷㘭。", "正爾賓中主，居然國外郊。", "老來俱倒置，營圃不營巢。"]'),
('6afa952d-8488-4670-81b8-5e855d456aaf','告春亭  其二','朱翌','宋','宋诗','song-poetry','','[]','竟日成清坐，因行或撫松。',48,'全唐诗/poet.song.108000.json','["竟日成清坐，因行或撫松。", "牆陰連曲浪，木杪涌奇峰。", "要路看公等，閑鄉屬我儂。", "未春花已盡，春到若爲容。"]'),
('d799838d-9ef4-42d2-8b01-6c16258282c1','告春亭  其三','朱翌','宋','宋诗','song-poetry','','[]','自斷身將隠，無嫌論少卑。',48,'全唐诗/poet.song.108000.json','["自斷身將隠，無嫌論少卑。", "江湖雙桂楫，天地一茅茨。", "溪篆行蝌蚪，林妝囀畫眉。", "悠悠昏復晝，聊爾給其私。"]'),
('3d30aedc-330f-42a3-92f9-efae2cbeb050','地僻','朱翌','宋','宋诗','song-poetry','','[]','地僻門常閉，家貧客自疏。',48,'全唐诗/poet.song.108000.json','["地僻門常閉，家貧客自疏。", "溪山行老我，風月不欺予。", "謾有書成誦，端無貨可居。", "清江千里道，持此問舂鋤。"]'),
('dccff701-26f9-4f07-b86b-bca4c7008b9f','種黄菊','朱翌','宋','宋诗','song-poetry','','[]','白日殆欲寢，黄花能起予。',48,'全唐诗/poet.song.108000.json','["白日殆欲寢，黄花能起予。", "妙香來枕上，正色立霜餘。", "護外勞編竹，培深更荷鋤。", "收功歸我枕，洗眼讀殘書。"]'),
('f77943ff-1485-4bf1-973a-51d234fa2e67','重陽不見菊次諸公韻  其一','朱翌','宋','宋诗','song-poetry','','[]','我圃黄花晚，君行不下輿。',48,'全唐诗/poet.song.108000.json','["我圃黄花晚，君行不下輿。", "屏居甘寂寞，佳節愧空疏。", "小待西風急，頻游夏屋渠。", "開時即重九，那恨子來徐。"]'),
('6a6a3775-b5a1-4477-b0fa-6616012833b4','重陽不見菊次諸公韻  其二','朱翌','宋','宋诗','song-poetry','','[]','遲笑秦昭舅，吝譏和長輿。',48,'全唐诗/poet.song.108000.json','["遲笑秦昭舅，吝譏和長輿。", "當時雖說貴，退步不爲疏。", "萸實采重嶺，拒霜臨碧渠。", "梁王門下客，先後有嚴徐。"]'),
('00d0be85-d2e8-4140-a77e-ba6a808aed59','重陽不見菊次諸公韻  其三','朱翌','宋','宋诗','song-poetry','','[]','歸去思陶令，安時似子輿。',48,'全唐诗/poet.song.108000.json','["歸去思陶令，安時似子輿。", "近知園可灌，唯恐菊相疏。", "酒幸濃如珀，詩令價重渠。", "看花隨早晚，何必更因徐。"]'),
('4199bdc9-3f2a-496e-ad81-86218fa73e44','重陽不見菊次諸公韻  其四','朱翌','宋','宋诗','song-poetry','','[]','菊以黄爲正，紛紛祇皂輿。',48,'全唐诗/poet.song.108000.json','["菊以黄爲正，紛紛祇皂輿。", "待寒緣耿介，縱老不凋疏。", "秋凈花如染，時遷水走渠。", "惟留五字句，能不愧應徐。"]'),
('52054b9c-5763-40dc-9cb7-9c617dcfc798','重陽不見菊次諸公韻  其五','朱翌','宋','宋诗','song-poetry','','[]','風流人稍間，涉筆爲題輿。',48,'全唐诗/poet.song.108000.json','["風流人稍間，涉筆爲題輿。", "今我思黄菊，携君近綺疏。", "先秋飄桂子，出水老芙渠。", "俯仰俱陳迹，聊書歲執徐。"]'),
('ed2c5fe2-0d3e-4c9e-8e33-219f049f56f4','重陽不見菊次諸公韻  其六','朱翌','宋','宋诗','song-poetry','','[]','西風吹露斝，晴日駕香輿。',48,'全唐诗/poet.song.108000.json','["西風吹露斝，晴日駕香輿。", "羨彼根莖茂，憐予齒髮疏。", "功成身老健，重味笑軒渠。", "甘谷誰能汲，瓶甖走莫徐。"]'),
('49678631-7ec1-4f7d-a3eb-13ce08b1ce09','十月十四日立冬菊花方盛','朱翌','宋','宋诗','song-poetry','','[]','黄菊一何好，持觴惟爾從。',48,'全唐诗/poet.song.108000.json','["黄菊一何好，持觴惟爾從。", "名應稱晚秀，色豈爲人容。", "正似花重九，休論月孟冬。", "霜威占清曉，直欲犯其鋒。"]'),
('51ee6bf0-ef91-4a44-aced-ff721cfaf365','夜雪','朱翌','宋','宋诗','song-poetry','','[]','夜集羣山雪，寒欺一把茅。',48,'全唐诗/poet.song.108000.json','["夜集羣山雪，寒欺一把茅。", "紅爐無宿火，黄絹有新抄。", "坐久燈排粟，杯行橘解包。", "頹然投敗絮，老懶信兒嘲。"]'),
('3ccb33b7-4551-4bda-abe5-8f822bdc7941','謝邕倅寄佛面杖','朱翌','宋','宋诗','song-poetry','','[]','自得閑居樂，欣聞隠具來。',48,'全唐诗/poet.song.108000.json','["自得閑居樂，欣聞隠具來。", "杖頭觀佛面，掌內化龍才。", "行變黄金色，依然滿月開。", "從今不妄出，留上妙高臺。"]'),
('722238cb-e5d6-45a2-8171-e39610799b9b','遣僧澄收刈潼陽','朱翌','宋','宋诗','song-poetry','','[]','下潠田將穫，東屯稼亦收。',48,'全唐诗/poet.song.108000.json','["下潠田將穫，東屯稼亦收。", "厭煩吾老矣，爲衆子行不。", "一粒生何處，千箱慶有秋。", "灌溪明日飯，今日已無愁。"]'),
('d7198518-ba7c-4b16-b263-eb100a8ab0f7','送楊亨仲還建康','朱翌','宋','宋诗','song-poetry','','[]','湖海重相面，干戈早脫身。',48,'全唐诗/poet.song.108000.json','["湖海重相面，干戈早脫身。", "亦知懷琰琬，寧肯就風塵。", "船泛東吳夜，梅尋故國春。", "毛錐有持護，如子豈長貧。"]'),
('c03f27a1-67d9-443b-80e8-72f367609e15','金秀軒詩','朱翌','宋','宋诗','song-poetry','','[]','金秀皆垂穎，山園特有光。',48,'全唐诗/poet.song.108000.json','["金秀皆垂穎，山園特有光。", "牽牛高暈碧，滴露小勻黄。", "老讀離騷傳，兒尋急就章。", "杜門觀化物，吾得傲羲皇。"]'),
('48208849-c50c-43c2-a59b-69cfbd994508','過王監園','朱翌','宋','宋诗','song-poetry','','[]','爲問西園客，秋花餘幾何。',48,'全唐诗/poet.song.108000.json','["爲問西園客，秋花餘幾何。", "敲門容剝啄，此老正婆娑。", "十月爲春酒，今年得子鵝。", "舉杯邀月罷，擊缶仰天歌。"]'),
('f976e9f5-54db-49ef-84d8-c2dada324d6f','戲事','朱翌','宋','宋诗','song-poetry','','[]','相逢多戲事，聊以度長年。',48,'全唐诗/poet.song.108000.json','["相逢多戲事，聊以度長年。", "間出詩聯句，時因酒合錢。", "歌狂無所擇，棋勝亦欣然。", "齷齪好苛禮，逡巡不敢前。"]'),
('1fc3490f-8bae-418d-90be-f535bb5ec73a','牡丹次韻  其一','朱翌','宋','宋诗','song-poetry','','[]','一日春工過潁陽，名園次第款侯王。',64,'全唐诗/poet.song.108000.json','["一日春工過潁陽，名園次第款侯王。", "風流得見昇平瑞，氣味初無世俗香。", "早託筠籠馳驛騎，旋張羅蓋護晨光。", "最憐一尺槃盂玉，穩上高鬟映額黄。"]'),
('5c718b4d-de73-45cc-9507-d2765f58b70c','牡丹次韻  其二','朱翌','宋','宋诗','song-poetry','','[]','畫舫何須載西子，青裙今幸拜東王。',64,'全唐诗/poet.song.108000.json','["畫舫何須載西子，青裙今幸拜東王。", "佛談非想色界色，天造玉皇香案香。", "興慶池邊凝曉露，善和坊裏借餘光。", "行聞綺席開東省，飛鞚爭馳御道黄。"]'),
('2c1afd87-ee90-4e15-a1ac-a1c4e373fc2f','跋司馬才仲六論','朱翌','宋','宋诗','song-poetry','','[]','溫公言語藥石譜，猶子文章星斗羅。',64,'全唐诗/poet.song.108000.json','["溫公言語藥石譜，猶子文章星斗羅。", "家世有方能治國，宦遊無地可降魔。", "諦觀深切著明論，平視賢良方正科。", "四海共知勳室後，享年孰似賈生多。"]'),
('619e189e-fa6b-4eed-9871-5176aabf5bf4','題蔣山草堂','朱翌','宋','宋诗','song-poetry','','[]','俯仰之間跡已塵，重來屐齒蘚痕勻。',64,'全唐诗/poet.song.108000.json','["俯仰之間跡已塵，重來屐齒蘚痕勻。", "晚菘早韭有真味，夜鶴曉猿無故人。", "萬一可償他日願，再三須卜此山鄰。", "北山大士乃吾祖，烝蕙肴蘭長薦新。"]'),
('b363a32e-d5be-47cb-971c-396ecb34c36d','約徐令登妙高峰徐不至','朱翌','宋','宋诗','song-poetry','','[]','衙鼓聲中百事休，獨攀危磴看江流。',64,'全唐诗/poet.song.108000.json','["衙鼓聲中百事休，獨攀危磴看江流。", "君脩吏課中中考，我且山行上上頭。", "下視三千佛世界，高尋十二仙人樓。", "聞思大士誰呼應，願賜飛霖洗旱眸。"]'),
('d9c7fb5d-e5da-4b04-a398-51fa6a38c9af','後兩日葉幹携酒','朱翌','宋','宋诗','song-poetry','','[]','喜君釃酒吸鯨空，置我飛雲卷霧中。',64,'全唐诗/poet.song.108000.json','["喜君釃酒吸鯨空，置我飛雲卷霧中。", "蒲鴿青浮初落蔕，冰蠶繭就旋開篷。", "小凉已覺生衣怯，短策能尋熟路通。", "直上高臺延望眼，萬山橫浸一溪東。"]'),
('fb18593f-a196-44f2-9b26-354541b30f9c','題水雲亭劉升道福唐所居','朱翌','宋','宋诗','song-poetry','','[]','沙合南臺會有期，沙邊築屋俯清漪。',64,'全唐诗/poet.song.108000.json','["沙合南臺會有期，沙邊築屋俯清漪。", "宋香陳紫丹成後，渭綠湘斑族盛時。", "長者時懷流水念，老兄元愛白雲知。", "一塵不到忘言處，雲在青天水在池。"]'),
('9e02c945-e586-4a88-bae9-cd0a33ad8a0e','雨後登城上亭','朱翌','宋','宋诗','song-poetry','','[]','何堪濕熱坐支離，且就虛凉看劇棋。',64,'全唐诗/poet.song.108000.json','["何堪濕熱坐支離，且就虛凉看劇棋。", "避雨唯應急走耳，登城願丐少休之。", "江山政此成三絕，耳目醒然亦一奇。", "突兀小亭吾畫篋，真形妙境恣君窺。"]'),
('3fe279dd-bee8-48b7-95b9-c0230e8dfda6','觀李思訓幸蜀圖','朱翌','宋','宋诗','song-poetry','','[]','上青天路最崎嶇，藏日擎天却有餘。',64,'全唐诗/poet.song.108000.json','["上青天路最崎嶇，藏日擎天却有餘。", "既驗六龍行萬里，始知一卒當千夫。", "望雲騅穩無前馬，带雨鈴鳴動屬車。", "縱有將軍天下筆，不如無逸舊時圖。"]'),
('f5f42bb9-225a-40c1-a16d-c6c5007c58d8','顔魯公畫像','朱翌','宋','宋诗','song-poetry','','[]','結芻續體祭中丞，鬼質何爲苦見嗔。',64,'全唐诗/poet.song.108000.json','["結芻續體祭中丞，鬼質何爲苦見嗔。", "千五百年如烈日，二十四州惟一人。", "朝衣視坎趨前死，羽服行山即此身。", "頼有區區張孝舉，直言驚倒漢廷臣。"]'),
('a2e068f7-4502-45cf-ba12-51d076159c45','讀劉太真碑','朱翌','宋','宋诗','song-poetry','','[]','衮衣華藻刻堅珉，下馬來尋剝蘚痕。',64,'全唐诗/poet.song.108000.json','["衮衣華藻刻堅珉，下馬來尋剝蘚痕。", "斷畫豈如弦可續，闕文猶冀石能言。", "鬣村故址今仍在，螭首遺蹤碎莫存。", "欲較智愚三十里，又飛絲鞚過前村。"]'),
('366be26e-0536-4820-b910-da4e39330d35','黄守不飲茶','朱翌','宋','宋诗','song-poetry','','[]','賓客相傳無水厄，欣然脫屐上公堂。',64,'全唐诗/poet.song.108000.json','["賓客相傳無水厄，欣然脫屐上公堂。", "滌煩療渴名雖著，瘠氣侵精暗有妨。", "夢寐無憂眠可熟，清虛自積體尤强。", "樵青竹裏管何事，側聽杯行供暖湯。"]'),
('e450f4e3-a0cc-4a16-a626-ac251ad917ab','寄范伯達','朱翌','宋','宋诗','song-poetry','','[]','薰風永日一簾垂，剝芡從容待晚炊。',64,'全唐诗/poet.song.108000.json','["薰風永日一簾垂，剝芡從容待晚炊。", "舉白且看連引滿，汗青不用歎無期。", "晝思夜夢人非遠，客附書來喜可知。", "千里與公供一笑，何時相遇戰低棋。"]'),
('0cfea5d2-f907-4cfb-b2eb-a405d6b650ba','次韻劉美中早朝','朱翌','宋','宋诗','song-poetry','','[]','鳳凰山下鳳凰城，輦路凌霄遡紫清。',64,'全唐诗/poet.song.108000.json','["鳳凰山下鳳凰城，輦路凌霄遡紫清。", "秋入九天風露冷，雲藏五玉佩環聲。", "虞淵出日升黄道，織女斜河轉啟明。", "鬰鬰安能久居此，君王有意待還京。"]'),
('725f1540-8ebb-4d68-b25d-41213f67f712','題日涉園詩','朱翌','宋','宋诗','song-poetry','','[]','一葉黄時秋氣清，三山轉處大江橫。',64,'全唐诗/poet.song.108000.json','["一葉黄時秋氣清，三山轉處大江橫。", "禽魚自有親人意，草木皆能識履聲。", "晴望高崖尋李愿，酒行半道致淵明。", "將詩與結江山好，他日來遊分不生。"]'),
('681d100d-251c-40df-bd94-84353f52a73b','寄胡明仲','朱翌','宋','宋诗','song-poetry','','[]','尺一催公想疾驅，盛傳今已過羌廬。',64,'全唐诗/poet.song.108000.json','["尺一催公想疾驅，盛傳今已過羌廬。", "紛紛眼底何時定，鬰鬰江南更久居。", "陛下不妨高枕卧，先生來草射聊書。", "銅駝可惜埋荆棘，會有人能爲掃除。"]'),
('3a480f5b-5250-4d81-b6a2-f6868fdfc0d7','送王端材以宣諭屬官入川','朱翌','宋','宋诗','song-poetry','','[]','使星入蜀動佳占，幕府謨謀要子參。',64,'全唐诗/poet.song.108000.json','["使星入蜀動佳占，幕府謨謀要子參。", "天下兵戈連歲月，朝廷根本在西南。", "路經九折休回首，事考三分小駐驂。", "想見梅黄飛雨裏，前旌已在百花潭。"]'),
('3d95417a-2b65-4509-b597-7282cf0e69a7','方竹杖','朱翌','宋','宋诗','song-poetry','','[]','此君骨相一成矩，氣稟坤爻六二全。',64,'全唐诗/poet.song.108000.json','["此君骨相一成矩，氣稟坤爻六二全。", "運用四方隨手轉，操持一節比松堅。", "玉雕界尺疑同樣，金作觚稜笑削圓。", "見寄分司真得力，時將緩步與周旋。"]'),
('3e42a799-8638-47be-b6b0-00e7ea59fe9d','萬竹亭','朱翌','宋','宋诗','song-poetry','','[]','氣稟元軒玉立身，露幛烟纛曉初勻。',64,'全唐诗/poet.song.108000.json','["氣稟元軒玉立身，露幛烟纛曉初勻。", "一時頓有七賢集，千畝今餘萬箇春。", "能以風流誇後日，政緣名篆得斯人。", "寂寥不見平安報，只有東風爲掃塵。"]'),
('a35627ba-502a-43b7-9c8d-fc8395e4ec19','頃入南華僧仲有詩爲次其韻仲欲見予詩集  其一','朱翌','宋','宋诗','song-poetry','','[]','促駕難求馬一尋，行纏快走任山深。',64,'全唐诗/poet.song.108000.json','["促駕難求馬一尋，行纏快走任山深。", "上方首入文公褐，小語能披逸少襟。", "三尺盆池清照影，五更窗月默傳心。", "更煩細看門前水，昔日西流何似今。"]'),
('879c96ee-36e6-4592-a337-9cd513021b13','頃入南華僧仲有詩爲次其韻仲欲見予詩集  其二','朱翌','宋','宋诗','song-poetry','','[]','寺分三集易披尋，藏在名山意亦深。',64,'全唐诗/poet.song.108000.json','["寺分三集易披尋，藏在名山意亦深。", "但與止茲鸞鳳友，共逃不學馬牛襟。", "年來惟以睡過夏，老去莫令詩嘔心。", "欲見文章須近北，太平風雅盛於今。"]'),
('ad1f44d2-8df1-4422-8108-31a10d4608c4','約鄭公績出城','朱翌','宋','宋诗','song-poetry','','[]','頗厭低頭看文字，似曾有約到南山。',64,'全唐诗/poet.song.108000.json','["頗厭低頭看文字，似曾有約到南山。", "稍回妍暖日自喜，掃盡積陰天解顔。", "便合與君聯騎出，更誰如我兩人閑。", "相逢莫作傷時狀，且趁春光競往還。"]'),
('c9838f1b-8430-49a1-b790-811329f27539','寄江東故人','朱翌','宋','宋诗','song-poetry','','[]','北風號木造秋悲，書到江南九月遲。',64,'全唐诗/poet.song.108000.json','["北風號木造秋悲，書到江南九月遲。", "雁過宜頻問消息，詩成猶得慰相思。", "想當雨澹烟昏處，又見橙黄橘綠時。", "若到北山煩寄語，道林真覺乃吾師。"]'),
('6dc8efcc-6ec0-4692-90f5-addc02621f91','冬前雪珠夜下早聞遠山皆白','朱翌','宋','宋诗','song-poetry','','[]','夜深真可覆三氈，地僻何因致八綿。',64,'全唐诗/poet.song.108000.json','["夜深真可覆三氈，地僻何因致八綿。", "五嶺盛傳非昔日，一寒如此怪今年。", "固知淵客難藏寶，倒卷珠池立散天。", "日下有丹能變白，青山休恨早華顛。"]'),
('8993f288-d212-4450-9bc7-8c2b32a323dd','雪作兒童以衣袖盛之如柳花狀','朱翌','宋','宋诗','song-poetry','','[]','六花幾歲不來南，大似優曇欲遇難。',64,'全唐诗/poet.song.108000.json','["六花幾歲不來南，大似優曇欲遇難。", "瓦響急傾鮫鮹顆，袖寬先得柳花團。", "莫憂荔子明年少，已是梅英向臘殘。", "骨冷魂清北風裏，更臨江檻俯驚湍。"]'),
('5b1371a2-d853-4784-b3f5-543b4ad142a6','龍山送客','朱翌','宋','宋诗','song-poetry','','[]','茸茸風草弄春柔，密密桑陰向綠稠。',64,'全唐诗/poet.song.108000.json','["茸茸風草弄春柔，密密桑陰向綠稠。", "江上星居多草閣，波間斗轉一漁舟。", "吾行適此心無事，客去何妨刺漫留。", "尚戒奚奴休叱馭，不辭小住看潮頭。"]'),
('b99eafd7-8eac-4616-9789-0175843ea02a','煩人置葛','朱翌','宋','宋诗','song-poetry','','[]','飽誦韶州白葛輕，十年曾不慰前聞。',64,'全唐诗/poet.song.108000.json','["飽誦韶州白葛輕，十年曾不慰前聞。", "芰荷欲使風裳製，溪谷難褰霧縠紋。", "坐甑遭炊無可避，踏冰赤脚謾多云。", "試將一事煩吾子，粗綌精絺可細分。"]'),
('883b3f78-7618-4109-a4fc-290a4d7df866','七月一日夜坐觀星','朱翌','宋','宋诗','song-poetry','','[]','半夜凉生過雨初，起迎秋色掃庭除。',64,'全唐诗/poet.song.108000.json','["半夜凉生過雨初，起迎秋色掃庭除。", "西牛東女經年會，北客南風一笑疏。", "乾鵲悲鳴橋渡漢，龍泉騰躍氣凌虛。", "盆池水面螢飛過，上下天星總一如。"]'),
('5e80bb1b-8a6e-4ee1-b429-36b41f28bc88','七夕後一日諸公携酒見過','朱翌','宋','宋诗','song-poetry','','[]','昨夜天孫擁翠軿，餘光猶此照河津。',64,'全唐诗/poet.song.108000.json','["昨夜天孫擁翠軿，餘光猶此照河津。", "且欣大暑去酷吏，更辱諸君爲主人。", "庭桂釀花香有信，盆荷迎露綠長新。", "浮雲掃盡天無滓，仰面爭看月半輪。"]'),
('cbe5cdaf-379b-4178-8993-d8f881a16b18','送范漕子儀','朱翌','宋','宋诗','song-poetry','','[]','乃公乃祖帝王師，勳在周家日月旗。',64,'全唐诗/poet.song.108000.json','["乃公乃祖帝王師，勳在周家日月旗。", "德盛固宜長有後，材高如此用何遲。", "五更雨脚方收絕，六月雲峰正出奇。", "好去加鞭度梅嶺，及時功業繼前規。"]'),
('ff703712-f61b-4c4d-b990-9d2d0131d859','丙寅十月遊南華','朱翌','宋','宋诗','song-poetry','','[]','五年四轉入曹溪，飛蓋干霄日爲低。',64,'全唐诗/poet.song.108000.json','["五年四轉入曹溪，飛蓋干霄日爲低。", "人定忽聞鐘不嗄，飲香休問水流西。", "桄榔子熟旒珠重，荳蔻叢深扇羽齊。", "鬰鬰蒼蒼千嶂裏，犯寒猶著一蟬嘶。"]'),
('91c567de-a12f-4de6-b2b1-0ac4329052b1','大歷寺遇風','朱翌','宋','宋诗','song-poetry','','[]','舟絕清江繫老榕，杖藜小住翠陰中。',64,'全唐诗/poet.song.108000.json','["舟絕清江繫老榕，杖藜小住翠陰中。", "縈青繚白千山日，駭綠紛紅萬竅風。", "足倦要休憐地僻，心閑無事見春工。", "回塘大有田田葉，索酒來傾碧玉筩。"]'),
('ff176bab-55d1-4913-9480-6dcac22173c2','夜宿方允迪家雨雪大作','朱翌','宋','宋诗','song-poetry','','[]','肺腑羣山襟带江，近人鷗鳥日成行。',64,'全唐诗/poet.song.108000.json','["肺腑羣山襟带江，近人鷗鳥日成行。", "每來問道維摩室，何幸濃薰班氏香。", "雨脚雪花方間作，燈紅酒綠正爭光。", "更煩采選消長夜，坐看回旋穴骼忙。"]'),
('dc9387b1-469c-4916-a3af-fefc08f71e5d','觀潮','朱翌','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','海山不見兩螺青，但見橫江展玉城。',64,'全唐诗/poet.song.108000.json','["海山不見兩螺青，但見橫江展玉城。", "動地鼓鼙飛屋瓦，刺天鬐鬛鬭溟鯨。", "拍浮未見羣兒弄，借勢須令萬楫迎。", "俄頃日斜風欲定，向來元是一漚生。"]'),
('6bd89ee5-7147-4a5a-9654-8a09a2841941','寄諸洪','朱翌','宋','宋诗','song-poetry','','[]','彭蠡春生萬頃湖，光明相映棣華跗。',64,'全唐诗/poet.song.108000.json','["彭蠡春生萬頃湖，光明相映棣華跗。", "鵷雛鸑鷟俱爲鳳，乳酪醍醐總是酥。", "歸壽其親來繼踵，無求於世獨知吾。", "青天一紙雁數字，南北雖殊意不殊。"]'),
('7ec4d378-d975-4c1a-a569-afd1f7559786','次韻俞路分見寄  其一','朱翌','宋','宋诗','song-poetry','','[]','有田二頃復何求，長恐斯言久不酬。',64,'全唐诗/poet.song.108000.json','["有田二頃復何求，長恐斯言久不酬。", "青篛正堪烟雨笠，白文終返水雲裘。", "相親多謝風標子，可款豈無瀟灑侯。", "更下疏簾對君弈，要觀都大出棋州。"]'),
('fd7e6404-ee6d-4a8d-950c-54d7255d0ee5','次韻俞路分見寄  其二','朱翌','宋','宋诗','song-poetry','','[]','龍尾道南初見子，烱如玉筍出瑶林。',64,'全唐诗/poet.song.108000.json','["龍尾道南初見子，烱如玉筍出瑶林。", "別來東海記三淺，歌罷武溪同一深。", "後五日看真得力，前三語且更留心。", "平生著手枯桐上，會有人能識此音。"]'),
('8898d291-98a2-44f9-9a2b-c682807842d6','戊辰元日到南華詩','朱翌','宋','宋诗','song-poetry','','[]','清曉匆匆賀歲歸，又隨微雨渡曹溪。',64,'全唐诗/poet.song.108000.json','["清曉匆匆賀歲歸，又隨微雨渡曹溪。", "禱晴願見五色羽，揭戶方占一日雞。", "沙水半摇新略彴，雲烟深護古伽黎。", "曹源激水仍過顙，桃李無言下有蹊。"]'),
('e0308b75-e993-4369-8a1e-3bc8f720d4ad','書事','朱翌','宋','宋诗','song-poetry','','[]','春來何事可相關，撥置書叢得少閑。',64,'全唐诗/poet.song.108000.json','["春來何事可相關，撥置書叢得少閑。", "洗硯諦觀鸜鵒眼，焚香仍揀鷓鴣斑。", "花開北陌東阡外，人在朝三暮四間。", "俯仰乾坤了無愧，心如枯枿更誰刪。"]'),
('976c6b3c-1b9e-47e8-939d-5d537de15825','遊錦石巖','朱翌','宋','宋诗','song-poetry','','[]','梯空何事上秋旻，要定三巖著隠君。',64,'全唐诗/poet.song.108000.json','["梯空何事上秋旻，要定三巖著隠君。", "斗柄下垂星可摘，天門將近語先聞。", "猿窺虎隠人驚去，牛污龍池雨解紛。", "償我七年東向念，却張風腋跨歸雲。"]'),
('e2d0cc36-f805-40e2-a1c7-637bf7d99b69','遊紫微洞','朱翌','宋','宋诗','song-poetry','','[]','堂堂勝境久潜幽，經始耡荒用我謀。',64,'全唐诗/poet.song.108000.json','["堂堂勝境久潜幽，經始耡荒用我謀。", "日照洞門開戶牖，霜飛暑路索衣裘。", "鞭笞鸞鳳天將近，彈壓山川酒不休。", "大費騷人題品力，薜蘿俱挽入雕鎪。"]'),
('2390cec0-0a3c-4689-8c4b-a045b08dcb08','揖翠軒','朱翌','宋','宋诗','song-poetry','','[]','篛笠蓑衣一葉舟，西風吹我與同遊。',64,'全唐诗/poet.song.108000.json','["篛笠蓑衣一葉舟，西風吹我與同遊。", "洋洋盈耳松聲亂，亹亹逼人山翠浮。", "講罷已聞花雨落，心清暗與妙香投。", "道人居士忘機久，一飽關門相對休。"]'),
('23c2ed5b-fc91-4fd8-bb7d-1469f75afe70','戲同諸子書所見','朱翌','宋','宋诗','song-poetry','','[]','已老猶癡作蠹魚，出門延望立須臾。',64,'全唐诗/poet.song.108000.json','["已老猶癡作蠹魚，出門延望立須臾。", "或深或淺花先後，半霽半陰雲有無。", "山月向人俱引領，海風無日不噓枯。", "論詩各盡諸郎意，籬落之中自可娛。"]'),
('a108ff1f-ff9e-45a8-bde0-c4ce61d26f04','八月十三夜與張檢法泛武溪','朱翌','宋','宋诗','song-poetry','','[]','川凈波平五板舟，天開地闢一輪秋。',64,'全唐诗/poet.song.108000.json','["川凈波平五板舟，天開地闢一輪秋。", "白銀國放黄金色，宮錦袍添紫綺裘。", "坐久星河掛瓔珞，夜深風露走珠旒。", "人間意適須乘興，我是閑人更自由。"]'),
('d684e08b-c5f4-4d9d-b979-fb7ab0770894','次韻李令','朱翌','宋','宋诗','song-poetry','','[]','青雲獨上肯隨羣，遇我真成數面親。',64,'全唐诗/poet.song.108000.json','["青雲獨上肯隨羣，遇我真成數面親。", "未許兒童騎竹馬，且看土偶笑桃人。", "弟兄酬唱詩無敵，賓客過從德有鄰。", "世味儻教如嚼蠟，便能調鼎識甘辛。"]'),
('81818896-5d65-4924-9797-d58271186b39','過小市李秀才居','朱翌','宋','宋诗','song-poetry','','[]','大涌泉東小市頭，川平土沃似中州。',64,'全唐诗/poet.song.108000.json','["大涌泉東小市頭，川平土沃似中州。", "誰歟築屋溪山裏，李也讀書窗戶幽。", "懶覺郊行差自適，老於春事不相謀。", "他時來問曹溪路，繫馬橋邊更少留。"]'),
('e35fe4fb-c657-4d65-8a85-867b8ae7bfb4','同郭侯僧仲晚至武溪亭議真率會','朱翌','宋','宋诗','song-poetry','','[]','平遠寒林暮靄橫，右丞不死畢韋生。',64,'全唐诗/poet.song.108000.json','["平遠寒林暮靄橫，右丞不死畢韋生。", "八人過處草齊綠，一日去來花笑迎。", "衲子自知空是色，將軍要使酒猶兵。", "尺書相與盟真率，嶺海風流似洛京。"]'),
('78bc0ede-8c46-4291-9a0d-bd2782d6ca26','鄧提舉留詩南華予後五日入山次韻','朱翌','宋','宋诗','song-poetry','','[]','有句誰知李似陰，好奇仍許杜猶岑。',64,'全唐诗/poet.song.108000.json','["有句誰知李似陰，好奇仍許杜猶岑。", "後期五日來圯下，面壁九年參少林。", "瘴鬼安能驚鶴衆，地靈何敢著狐任。", "雷車電熾中宵起，看取龍工濟物心。"]'),
('bf0eac9e-479a-4281-99da-9eb0ac7879f1','南華卓錫泉復出','朱翌','宋','宋诗','song-poetry','','[]','竹龍銜尾轉山房，飲足寒清滴夜長。',64,'全唐诗/poet.song.108000.json','["竹龍銜尾轉山房，飲足寒清滴夜長。", "曾問鞠窮目眢井，爲焚安息坐胡床。", "千山從此俱蒙潤，一綫纔通未可量。", "六月炎方了無暑，誰知世上有清凉。"]'),
('453e6cee-94de-4c34-8ca1-37e7313f5aee','次韻常子正','朱翌','宋','宋诗','song-poetry','','[]','骨鯁當朝迹未塵，但知謀國不謀身。',64,'全唐诗/poet.song.108000.json','["骨鯁當朝迹未塵，但知謀國不謀身。", "試看犀角龜文表，真是鸞臺鳳閣人。", "短別可堪馳夢驛，小詩聊爲寫情親。", "雪山滿眼寒潮急，憑仗歸鴻一問津。"]'),
('b9075ea9-8cd6-4556-baf1-7623e4ef966c','寄洪倅景伯','朱翌','宋','宋诗','song-poetry','','[]','潦倒麤疏老更癡，手摩枵腹逐兒嬉。',64,'全唐诗/poet.song.108000.json','["潦倒麤疏老更癡，手摩枵腹逐兒嬉。", "處陰息跡真休矣，遇坎乘流一聽之。", "臘後春生須雁到，花前思發幸梅知。", "瀛洲學士滄洲興，妙唱一年漁父詞。"]'),
('d68c1bf1-5d8e-41ef-b8c9-bde026e31867','題足軒詩','朱翌','宋','宋诗','song-poetry','','[]','域中寧有一毫真，靜極方知衆妙存。',64,'全唐诗/poet.song.108000.json','["域中寧有一毫真，靜極方知衆妙存。", "疏受果能從父議，王章終不用妻言。", "脫身兵火蒙天幸，沃日風濤到海吞。", "兩頓藜羹如大饗，一番布被有春溫。"]'),
('57c1ff2c-5f29-445a-ba53-f0dc3e51dff5','元日登城','朱翌','宋','宋诗','song-poetry','','[]','第一逢春管物華，率先桃李被褒嘉。',64,'全唐诗/poet.song.108000.json','["第一逢春管物華，率先桃李被褒嘉。", "明朝又數日爲狗，回首猶驚歲在蛇。", "香聚椒槃縈綵字，春生茶碗結瓊花。", "層城獨秀東風裏，下瞰川流脈脈斜。"]'),
('000fd584-7c9d-414a-961e-ea154efe2e35','睡起','朱翌','宋','宋诗','song-poetry','','[]','客不敲門飽睡魔，靜聽簷雨瀉天河。',64,'全唐诗/poet.song.108000.json','["客不敲門飽睡魔，靜聽簷雨瀉天河。", "從人指畫竹如意，假手爬搔松養和。", "屏上水翻波浩渺，硯旁山卧石陂陀。", "十年游戲三間屋，一笑留連兩曜梭。"]'),
('6de1e93c-df25-4fb9-93ab-8bed4451bd80','送福帥','朱翌','宋','宋诗','song-poetry','','[]','春到春城和雅歌，又携春去度雲蘿。',64,'全唐诗/poet.song.108000.json','["春到春城和雅歌，又携春去度雲蘿。", "過余竹裏煎茶久，看子花邊簇馬多。", "千里福星臨福地，一時天使挽天河。", "江紅陳紫留連得，奈此催歸尺一何。"]'),
('9a7a7c34-3280-4ec5-a669-657aeb0a427a','謝劉憲惠龍眼詩','朱翌','宋','宋诗','song-poetry','','[]','龍目秋成亦一奇，略無瘴霧損瑶肌。',64,'全唐诗/poet.song.108000.json','["龍目秋成亦一奇，略無瘴霧損瑶肌。", "荔枝韻勝材誰亞，益智名同性即非。", "俠士從禽携彈去，鮫人探海得珠歸。", "不須直待枯成臘，便遣尊前解褐衣。"]'),
('42fb43c3-992b-41a4-964a-63d134e86558','江上待客不至','朱翌','宋','宋诗','song-poetry','','[]','煙霧濛濛遠岫埋，沙邊特爲小徘徊。',64,'全唐诗/poet.song.108000.json','["煙霧濛濛遠岫埋，沙邊特爲小徘徊。", "行人又向去處去，客子未知來不來。", "詩似芙蓉臨水出，人如楊柳待風開。", "何時見此消愁眼，更責後期傾玉杯。"]'),
('965d18bb-d123-48a5-bb51-4474362083d8','寄劉明道','朱翌','宋','宋诗','song-poetry','','[]','平山飛騎竹西州，到處逢君得縱遊。',64,'全唐诗/poet.song.108000.json','["平山飛騎竹西州，到處逢君得縱遊。", "滿地落花春病酒，一簾明月夜登樓。", "江帆带雨人歸後，烽火連天客罷休。", "一紙短書勞遠祝，貂蟬到底出兜鍪。"]'),
('1328405e-bc5d-4484-a2b1-f532667a956b','次韻傅丈見寄  其一','朱翌','宋','宋诗','song-poetry','','[]','到處能行到處藏，飯餘掛鉢解茶囊。',64,'全唐诗/poet.song.108000.json','["到處能行到處藏，飯餘掛鉢解茶囊。", "不緣頭上五分白，始與人間萬事忘。", "一介遠勞詢近日，十年如此住南荒。", "只今已是交遊絕，不問比鄰不擇鄉。"]'),
('a962158e-4d57-4705-9c70-ca6c9174e70c','次韻傅丈見寄  其二','朱翌','宋','宋诗','song-poetry','','[]','土瓜甘蔗窖深藏，青李來禽子在囊。',64,'全唐诗/poet.song.108000.json','["土瓜甘蔗窖深藏，青李來禽子在囊。", "勝日園林吾有分，暮年歌酒爾無忘。", "掃除金屑不到眼，盡力石田難救荒。", "每遇北風長引領，皖公山下是桐鄉。"]'),
('7f89d97d-6b5d-4191-9382-c2f914db6d95','湘江亭別程幹','朱翌','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','十年頻望秀而巉，琴筑齊音和阮咸。',64,'全唐诗/poet.song.108000.json','["十年頻望秀而巉，琴筑齊音和阮咸。", "硯浴珍材躬試墨，畫收名筆旋開緘。", "長江流自胸襟出，大艑來如首尾銜。", "分手一言君勿忘，他時容我見千巖。"]'),
('cad64daf-3ba7-4ebe-93a5-f3989c7e477a','鄭元亞新居面梅開軒諸子讀書其間名曰擢英','朱翌','宋','宋诗','song-poetry','','[]','紛紛百卉不須栽，一見論交正有梅。',64,'全唐诗/poet.song.108000.json','["紛紛百卉不須栽，一見論交正有梅。", "詩興已從東閣動，山寒併許北枝開。", "影橫窗紙月爲友，香著硯屏春共來。", "庭下芝蘭爭秀發，對花君但莫停杯。"]'),
('9989d902-dc57-4275-966f-73bddfa2c320','江上送客夜歸','朱翌','宋','宋诗','song-poetry','','[]','江干燕客酒如淮，歸路飛輈破綠苔。',64,'全唐诗/poet.song.108000.json','["江干燕客酒如淮，歸路飛輈破綠苔。", "燈影入簾窺酩酊，雨聲宜夢引咍臺。", "豈無文送窮行別，似有人呼隠去來。", "一念不生無可道，此懷今欲向誰開。"]'),
('fe0b59f9-6725-4523-a470-e0a733019f5e','送楊倅致政還鄉','朱翌','宋','宋诗','song-poetry','','[]','交說紛紛不憚煩，要公小駐北歸轅。',64,'全唐诗/poet.song.108000.json','["交說紛紛不憚煩，要公小駐北歸轅。", "三休恐負名亭意，二去吾寧顧子言。", "快指柴桑還我里，遥瞻神虎到君門。", "畫圖史筆俱張大，又得楊家一巨源。"]'),
('0949379f-be50-4025-9fab-078a606576e3','與錢端修諸公飲興福','朱翌','宋','宋诗','song-poetry','','[]','積陰解盡可信眉，梵宇仍容款扣扉。',64,'全唐诗/poet.song.108000.json','["積陰解盡可信眉，梵宇仍容款扣扉。", "山凈且無塵一點，湖平惟有鷺雙飛。", "杯行客惡思傳令，劫急棋爭看解圍。", "招隠不知誰好事，爲尋幽處著漁磯。"]');
